# ─── Enemy Attack Windup Telegraph ──────────────────────────────────────────
# In the final moments before an enemy's attack cooldown expires (while it's
# in melee range), the enemy briefly squashes down and brightens — a clear
# "winding up to hit you!" telegraph. This makes melee attacks readable
# instead of instantaneous, giving the player a fair chance to dash or sidestep.
# The windup only triggers when the enemy is in attack range and its cooldown
# is nearly done, so it doesn't fire during the long post-attack cooldown gap.
ENEMY_ATTACK_WINDUP_TIME = 0.25      # Seconds before attack lands that the windup begins
ENEMY_ATTACK_WINDUP_SQUASH = 0.15    # Max Y compression during windup (0.15 = squished to 85%)
ENEMY_ATTACK_WINDUP_BRIGHTNESS = 0.5 # How far to lerp enemy color toward white during windup

# ─── Spore Spitter Spit Charge-Up Telegraph ──────────────────────────────────
# In the final moments before a Spore Spitter fires its ranged projectile, the
# enemy briefly swells (scale up) and brightens toward a glowing orange — a
# clear "winding up to spit!" telegraph that mirrors the melee windup system.
# This makes the ranged attack readable and dodgeable instead of
# instantaneous, giving the player a fair window to strafe or dash before the
# spore launches. Only triggers when the spit timer is nearly done AND the
# player is within spit range, so it doesn't fire during the long cooldown.
SPORE_SPIT_CHARGE_TIME = 0.45       # Seconds before spit that the charge-up begins
SPORE_SPIT_CHARGE_SCALE = 0.25      # Max scale increase during charge (0.25 = swells to 125%)
SPORE_SPIT_CHARGE_BRIGHTNESS = 0.55 # How far to lerp enemy color toward bright orange during charge

# ─── Enemy Attack Forward Lunge ──────────────────────────────────────────────
# When an enemy lands a melee attack, it physically lunges forward a short
# distance toward the player instead of staying in place. This makes melee
# combat feel more dynamic — enemies commit to a direction when they strike,
# making attacks readable and dodgeable. The lunge distance scales inversely
# with enemy size so small enemies lunge further (fast attackers) while large
# enemies barely move (heavy hitters). A lunge speed is applied over a brief
# duration so the enemy slides forward smoothly rather than teleporting.
ENEMY_ATTACK_LUNGE_DISTANCE = 1.5    # Base forward lunge distance (world units)
ENEMY_ATTACK_LUNGE_DURATION = 0.15   # How long the lunge movement lasts (seconds)
ENEMY_ATTACK_LUNGE_SIZE_BASE = 1.0   # Enemy scale at which lunge = base distance
ENEMY_ATTACK_LUNGE_SIZE_MULT_MIN = 0.3  # Min lunge multiplier (for very large enemies)
# ── Smooth Lunge Slide ── The attack lunge now uses a velocity-based smooth
# slide over ENEMY_ATTACK_LUNGE_DURATION instead of teleporting instantly.
# The enemy gets a lunge_vel that's applied each frame and decays, so it
# visibly slides forward toward the player during the strike — a much more
# dynamic and readable attack motion than a snap-to-position teleport.
# Combined with the directional stretch below, this makes enemy melee
# attacks feel like committed physical strikes.
ENEMY_ATTACK_LUNGE_DECAY = 8.0      # How fast lunge velocity decays (higher = snappier)
# ── Enemy Attack Lunge Directional Stretch ── During the lunge slide, the
# enemy briefly stretches along the lunge direction (elongated in the strike
# direction, compressed perpendicular) — a directional squash & stretch that
# makes the attack feel like a committed forward thrust rather than a slide.
# The stretch decays with the lunge velocity so it's strongest at the start
# of the strike and eases back to normal as the lunge settles.
ENEMY_ATTACK_LUNGE_STRETCH = 0.20   # Max elongation along lunge direction (0.20 = 120%)
ENEMY_ATTACK_LUNGE_SQUISH = 0.10    # Max compression perpendicular to lunge (0.10 = 90%)

# ── Enemy Spawn Grace Shield Visual ── During the spawn grace period
# (ENEMY_SPAWN_GRACE_PERIOD), enemies are non-hostile but previously showed
# no visual indication of this. A translucent cyan dome now appears around
# newly spawned enemies and fades out as the grace period ends, making it
# visually clear that the enemy is temporarily not a threat — so the player
# can distinguish a "still materializing" enemy from an active threat.
ENEMY_SPAWN_GRACE_SHIELD_ALPHA = 80    # Max alpha of the grace dome
ENEMY_SPAWN_GRACE_SHIELD_SCALE = 1.8  # Dome scale multiplier on enemy scale

# ─── Enemy Behavior ───────────────────────────────────────────────────────────
ENEMY_WANDER_SPEED_FACTOR = 0.20
ENEMY_WANDER_INTERVAL_MIN = 2.0
ENEMY_WANDER_INTERVAL_MAX = 5.0
ENEMY_WANDER_DIR_JITTER = 1.0

# ─── Enemy Chase Acceleration Ramp ────────────────────────────────────────────
# When an enemy first detects the player, it currently snaps from wander speed
# (20% of base) to full chase speed instantly — a jarring teleport-like lurch.
# This ramp smoothly interpolates the chase speed multiplier from a gentle start
# to full speed over ENEMY_CHASE_RAMP_DURATION seconds, so enemies "wind up" into
# the chase instead of exploding into sprint. The ramp starts at ENEMY_CHASE_RAMP_START
# (a fraction of full speed) so the transition from wander (0.2x) to chase feels
# continuous rather than a step down then up.
ENEMY_CHASE_RAMP_DURATION = 0.5    # Seconds to reach full chase speed after detecting
ENEMY_CHASE_RAMP_START = 0.35      # Starting chase speed fraction (between wander 0.2 and full 1.0)

# ─── Enemy Separation ──────────────────────────────────────────────────────────
# Enemies gently push apart when too close, preventing the "ball of enemies"
# clumping problem. This makes combat more readable — enemies form a natural
# ring around the player instead of stacking into a single point.
ENEMY_SEPARATION_RADIUS = 2.5  # How close enemies get before pushing apart
ENEMY_SEPARATION_FORCE = 5.0   # Push strength when enemies are too close
# ── Size-Scaled Separation Radius ── The separation radius now scales with
# enemy size so large enemies (Plasma Drake, scale 2.2) spread out more than
# tiny enemies (Swarm Mite, scale 0.5). Previously the flat 2.5-unit radius
# meant a massive boss and a tiny mite occupied the same personal-space
# bubble, causing large enemies to overlap their neighbors while small
# enemies spread too far apart. The scaled radius keeps the effective personal
# space proportional to the enemy's physical size, making combat formations
# look natural across all 18 enemy types — big enemies form a loose ring
# while small enemies cluster tighter.
ENEMY_SEPARATION_SIZE_BASE = 1.0   # Enemy scale at which radius = base value
ENEMY_SEPARATION_SIZE_MULT = 1.2   # Radius scales by this factor per unit of scale

