# ─── Leveling ─────────────────────────────────────────────────────────────────
LEVEL_UP_HEAL_AMOUNT = 40              # Base heal — rewards survival and leveling up
LEVEL_UP_HEAL_PERCENT = 0.15           # Heals 15% of max HP on level-up (scales with level)
LEVEL_UP_HP_BONUS = 12                 # More HP per level — 120→132→144→... feels meaningful
LEVEL_UP_SPEED_BONUS = 0.4             # Slightly more speed per level for better kite feel
XP_SCALE_FACTOR = 1.35                 # Flatter XP curve — levels keep flowing at a satisfying pace in mid-late game
BASE_KILL_XP = 30                       # Higher base kill XP — kills feel rewarding earlier
KILL_XP_HP_DIVISOR = 8                 # Tougher enemies give proportionally more XP
# ── Minimum Kill Score ── Even the weakest enemies (Swarm Mite: 12 HP) grant a
# minimum score reward so early-game kills feel worthwhile. Without this, a
# Swarm Mite kill gives only 12 points — barely noticeable. The floor ensures
# every kill feels rewarding regardless of enemy toughness.
KILL_SCORE_MIN = 30                    # Minimum score awarded per kill (before combo mult)

# ─── Visual Effects ───────────────────────────────────────────────────────────
DEATH_ANIM_DURATION = 0.5             # Slightly longer death for better readability
SCREEN_SHAKE_DAMAGE = 0.4             # Stronger shake on player damage — clearer feedback
SCREEN_SHAKE_KILL = 0.75              # More impactful kill shake
# ── Combo-Scaled Kill Screen Shake ── Each kill's screen shake intensifies
# with the current combo count, so high kill streaks feel progressively more
# impactful — each successive kill in a big combo shakes the screen harder,
# building visceral momentum. At combo x1 the shake is the base value; at
# x10 it gets +50% (1.125); at x20+ it's capped at +75% (1.3). The scaling
# uses the same COMBO_MAX_TIER cap as the XP/score multipliers so it doesn't
# grow unbounded. This makes sustained kill chains feel like an escalating
# physical event through the camera, complementing the combo edge glow and
# milestone fireworks with a tactile sense of growing power.
COMBO_SHAKE_TIER = 5          # Combo count per +25% shake increment
COMBO_SHAKE_PER_TIER = 0.25   # +25% shake per tier (every 5 combo)
COMBO_SHAKE_MAX_BONUS = 0.75  # Max +75% shake at high combos
SCREEN_SHAKE_DECAY = 8.0              # Slower decay so shake lingers a touch longer
LEVEL_UP_FLASH_DURATION = 2.5          # Longer level-up visibility so players notice it
CAMERA_LERP_SPEED = 6.0
CAMERA_HEIGHT = 18
CAMERA_DISTANCE = 22
CAMERA_ANGLE = 30
CAMERA_YAW_SPEED = 200      # Degrees per second of mouse movement for orbit
CAMERA_PITCH_SPEED = 150    # Degrees per second of mouse movement for pitch
CAMERA_PITCH_MIN = 10       # Lowest pitch (looking far ahead)
CAMERA_PITCH_MAX = 80       # Highest pitch (looking nearly straight down)
CAMERA_YAW_SMOOTH = 10.0    # Lerp speed for yaw smoothing
CAMERA_PITCH_SMOOTH = 10.0  # Lerp speed for pitch smoothing
# ── Camera Shoot Recoil Kick ── Each shot nudges the camera backward (away
# from the firing direction) and slightly upward, then springs back — a subtle
# "kick" that makes shooting feel impactful through the camera without being
# disorienting. The kick decays exponentially so rapid fire produces a steady
# gentle push instead of accumulating into a violent shake. The vertical
# component adds a tiny "recoil lift" (like a real weapon kicking up).
CAMERA_SHOOT_RECOIL_DISTANCE = 0.35  # How far the camera kicks back (world units)
CAMERA_SHOOT_RECOIL_LIFT = 0.15       # Small upward kick on the camera Y
CAMERA_SHOOT_RECOIL_DECAY = 14.0      # How fast the recoil recovers (higher = snappier)

# ─── Enemy Hit Feedback ───────────────────────────────────────────────────────
ENEMY_HIT_FLASH_DURATION = 0.12        # Slightly longer flash for clearer read (was 0.1)
ENEMY_HIT_SCALE_PUNCH = 1.25          # Brief scale multiplier on hit for impactful feedback
ENEMY_HIT_SCALE_RECOVERY = 12.0        # How fast scale returns to normal after hit punch
# ── Enemy Hit Vertical Flinch ── When an enemy is hit by a projectile, it
# briefly pops upward (a tiny vertical "flinch") in addition to the existing
# flash and scale punch. This makes hits feel more physically impactful — the
# enemy physically reacts to being struck, not just visually flashes. The
# flinch is a small upward offset that decays quickly, composited on top of
# the normal bob animation. Larger enemies flinch less (they're heavier) while
# small enemies pop more noticeably, matching the size-scaled hit punch logic.
ENEMY_HIT_FLINCH_HEIGHT = 0.4       # Max upward flinch on hit (world units, at base size)
ENEMY_HIT_FLINCH_DECAY = 10.0       # How fast the flinch recovers to 0 (higher = snappier)
# ── Size-Scaled Hit Punch ── The scale punch is more dramatic on small enemies
# and subtler on large ones. A Swarm Mite (scale 0.5) punching to 1.25x is barely
# visible, while a Plasma Drake (scale 2.2) at 1.25x is a huge screen-filling
# distortion. This multiplier scales the punch intensity inversely with enemy
# size so combat feedback is equally readable across all enemy types.
ENEMY_HIT_PUNCH_SIZE_BASE = 1.0        # Enemy scale at which punch = ENEMY_HIT_SCALE_PUNCH (no adjustment)
ENEMY_HIT_PUNCH_SIZE_MULT_MIN = 0.7    # Minimum punch multiplier (for very large enemies)
ENEMY_HIT_PUNCH_SIZE_MULT_MAX = 1.6    # Maximum punch multiplier (for very small enemies)
ENEMY_HIT_RIPPLE_DURATION = 0.5       # How long the expanding impact ring lasts on hit
ENEMY_HIT_RIPPLE_EXPAND_SPEED = 8.0   # How fast the impact ring expands
ENEMY_HIT_RIPPLE_MAX_SCALE = 3.0      # Maximum scale the impact ring reaches
ENEMY_HIT_RIPPLE_START_SCALE = 0.3    # Starting scale of the impact ring
# ── Damage-Scaled Hit Particles ── The number of hit particles spawned on a
# projectile hit now scales logarithmically with the damage dealt — a 20-damage
# shot produces the base count while an 80-damage crit spawns up to 50% more
# particles. This makes heavy hits (high-level crits, combo buffed shots, etc.)
# visually more impactful than light hits, adding a satisfying weight scaling
# to combat feedback. The scaling is logarithmic so it doesn't explode into
# screen-filling particle storms on high-damage hits.
ENEMY_HIT_PARTICLE_DAMAGE_SCALE = 0.5  # Max fractional bonus particles at very high damage
ENEMY_HIT_PARTICLE_DAMAGE_REF = 20    # Reference damage for baseline particle count
# ─── Enemy Hit Flash Tint ────────────────────────────────────────────────────
# On hit, enemies flash a brightened version of their OWN color instead of pure
# white. This produces cohesive, target-tinted feedback — hitting a Lava Crawler
# yields a bright orange flash, hitting a Crystal Guardian yields bright cyan —
# making each impact feel tailored to the enemy instead of a generic white wash.
# The brightened tint is computed by lerping the enemy's original color toward
# white by ENEMY_HIT_FLASH_BRIGHTNESS (0.85 = 85% toward white, retaining a hint
# of the enemy's hue for a more polished, less harsh flash).
ENEMY_HIT_FLASH_BRIGHTNESS = 0.85  # How far to lerp enemy color toward white on hit (0=own color, 1=white)

# ─── Enemy Enrage at Low HP ───────────────────────────────────────────────────
# When an enemy's HP drops below ENRAGE_HP_THRESHOLD (25%), it enters a brief
# "enrage" state: its movement speed increases, its color shifts toward red, and
# it emits small red rage particles. This makes the final moments of a tough
# fight more dynamic and rewarding — enemies fight back harder when cornered,
# making kills feel earned rather than inevitable.
ENRAGE_HP_THRESHOLD = 0.25         # Fraction of max HP below which enrage triggers

# ── Enemy Enrage Proximity Warning ── When a nearby enemy (within
# ENRAGE_PROXIMITY_RADIUS units) enters its enraged state for the first time,
# a brief orange-tinted message appears in the kill feed so the player is
# immediately alerted that a desperate, more dangerous enemy is close. This
# complements the existing red aura visual with a HUD-level alert that
# doesn't require looking at the enemy — you know something nearby just
# went berserk even if you're focused elsewhere. Only triggers once per enemy
# (on the enrage transition, not every frame while enraged).
ENRAGE_PROXIMITY_RADIUS = 25.0      # How close the enemy must be to trigger the warning
ENRAGE_PROXIMITY_NOTIFY_COOLDOWN = 4.0  # Min seconds between proximity warnings (prevents spam)
ENRAGE_SPEED_MULT = 1.35           # Speed multiplier while enraged
ENRAGE_COLOR_MIX = 0.6              # How far to lerp toward red (0=own color, 1=full red)
ENRAGE_PARTICLE_INTERVAL = 0.4     # Seconds between rage particle emissions
ENRAGE_PARTICLE_COUNT = 3          # Particles per emission
# ── Desperation-Scaled Rage Particles ── As an enraged enemy's HP drops from
# 25% toward 0%, its rage particle emission rate accelerates and the count per
# emission increases — making the enemy look increasingly desperate and
# dangerous as it nears death. At 25% HP the interval is the base value and
# count is the base; at near-0% HP the interval shrinks to half and the count
# doubles. This creates a visible escalation of fury that makes finishing off
# an enraged enemy feel urgent and rewarding — the enemy is visibly losing
# control as it dies.
ENRAGE_DESPERATION_INTERVAL_MULT = 0.5   # Particle interval at near-0 HP (half the base)
ENRAGE_DESPERATION_COUNT_MULT = 2.0     # Particle count multiplier at near-0 HP
ENRAGE_AURA_ALPHA = 50            # Alpha of the persistent red aura while enraged
ENRAGE_AURA_SCALE = 1.4           # Scale multiplier for the enrage aura sphere

# ─── Execution Bonus ──────────────────────────────────────────────────────────
# Killing an enemy that is in its enraged state (below 25% HP) grants bonus XP
# — turning the enrage mechanic into a risk/reward system. The enemy fights
# harder when cornered, but finishing it off while enraged rewards the player
# for aggressive, decisive play. The bonus scales with the enemy's max HP so
# tougher enemies (which are enraged longer and more dangerous) give a bigger
# payoff. A golden "EXECUTION!" damage number and extra particles celebrate
# the kill, making it feel like a skillful finish rather than just another kill.
EXECUTION_XP_BONUS_BASE = 15       # Base bonus XP for executing an enraged enemy
EXECUTION_XP_BONUS_PER_HP = 0.1   # Additional XP per point of enemy max HP
EXECUTION_PARTICLE_COUNT = 12     # Gold particle burst on execution
EXECUTION_SCREEN_SHAKE = 0.2      # Screen shake on execution

# ── Enemy Hit Directional Stretch ── When a projectile hits an enemy, the
# enemy briefly stretches along the shot's travel direction (and compresses
# perpendicular to it) in addition to the existing uniform scale punch. This
# makes hits feel like the projectile physically pushes THROUGH the enemy — a
# classic "juice" technique that adds directional impact feedback. The stretch
# decays quickly (sharing the hit_scale_punch timer) and composes on top of the
# uniform punch via a non-uniform Vec3 scale. The stretch is subtle (max ~15%
# elongation) so it enhances rather than distorts the enemy model.
ENEMY_HIT_STRETCH_AMOUNT = 0.15   # Max elongation along shot direction (0.15 = 115%)
ENEMY_HIT_STRETCH_SQUISH = 0.08   # Max compression perpendicular to shot direction (0.08 = 92%)

# ─── Flawless Kill Streak ──────────────────────────────────────────────────────
# Tracks consecutive kills made WITHOUT taking any damage. At milestones (every
# FLAWLESS_MILESTONE kills), bonus XP is awarded with a unique "FLAWLESS!"
# announcement and golden particle burst. Taking any damage resets the streak to 0.
# This rewards skillful dodging and damage avoidance — the player who never gets
# hit builds up an impressive streak and earns significantly more XP. The streak
# runs parallel to the combo system but is specifically about NOT taking damage,
# complementing the combo (which is about rapid kills) and multi-kill (which is
# about simultaneous kills).
FLAWLESS_MILESTONE = 5             # Kills per milestone (every 5 flawless kills = bonus)
FLAWLESS_XP_PER_MILESTONE = 50    # Bonus XP per milestone tier
FLAWLESS_DISPLAY_LIFETIME = 3.0   # How long the flawless streak HUD text stays visible
FLAWLESS_COLOR = color.rgb(255, 215, 0)  # Gold — visually distinct from combo/multikill
FLAWLESS_MAX_TIER = 20            # Cap on streak for display/XP scaling

# ─── Emergency Health Potion Magnet ───────────────────────────────────────────
# When the player's HP drops below EMERGENCY_HP_THRESHOLD, all Health Potions
# within EMERGENCY_POTION_PULL_RADIUS are magnetically pulled toward the player
# — a much larger radius than the normal pull. This is a "survival instinct"
# mechanic: when near death, Zorp can sense health potions from far away and
# they rush toward him. The emergency pull uses a stronger pull speed so the
# potion arrives quickly in a clutch moment. This prevents frustrating deaths
# where a health potion was just out of reach.
EMERGENCY_HP_THRESHOLD = 0.25      # HP fraction below which emergency magnet activates
EMERGENCY_POTION_PULL_RADIUS = 18.0  # How far the emergency pull reaches (much larger than normal)
EMERGENCY_POTION_PULL_SPEED = 22.0  # Faster pull speed for emergency potions

# ─── Critical HP Potion Homing ──────────────────────────────────────────────────
# When the player's HP drops below CRITICAL_HP_THRESHOLD (15%), ALL Health
# Potions within CRITICAL_POTION_HOMING_RADIUS are magnetically pulled toward
# the player at an accelerated speed — an even more desperate version of the
# existing Emergency Health Potion Magnet (which activates at 25% HP with an
# 18-unit radius). At 15% HP the radius extends to 30 units and the pull speed
# increases further, essentially making every Health Potion in a wide area
# rush to Zorp. This prevents the most frustrating deaths where a potion was
# *just* out of reach during a clutch moment. Additionally, each potion within
# the radius gets a pulsing green beacon ring so the player can see that help
# is on the way. The critical homing stacks with the emergency magnet.
CRITICAL_HP_THRESHOLD = 0.15         # HP fraction below which critical homing activates
CRITICAL_POTION_HOMING_RADIUS = 30.0 # How far the critical homing reaches
CRITICAL_POTION_HOMING_SPEED = 28.0  # Pull speed for critical homing (faster than emergency)
CRITICAL_POTION_BEACON_ALPHA = 100    # Alpha of the green beacon ring on each potion
CRITICAL_POTION_BEACON_PULSE_SPEED = 10.0  # How fast the beacon pulses (urgent)

# ─── Pickup Streak Score Multiplier ────────────────────────────────────────────
# When the player is on a pickup streak of PICKUP_STREAK_SCORE_TIER1 (10+), each
# collectible is worth 1.5x score. At PICKUP_STREAK_SCORE_TIER2 (20+), 2x score.
# This rewards the item-gathering playstyle and makes long collection runs feel
# increasingly lucrative — synergizing with the existing pickup streak bonus XP.
PICKUP_STREAK_SCORE_TIER1 = 10    # Streak needed for 1.5x score multiplier
PICKUP_STREAK_SCORE_TIER2 = 20    # Streak needed for 2x score multiplier
PICKUP_STREAK_SCORE_MULT_TIER1 = 1.5
PICKUP_STREAK_SCORE_MULT_TIER2 = 2.0

# ─── Vengeful Surge ─────────────────────────────────────────────────────────────
# When the player takes damage while at a high combo (x5+), a "VENGEFUL SURGE!"
# triggers: a brief speed + fire rate buff that rewards aggressive counterplay.
# Instead of getting hit and losing everything, the player gets a short window of
# enhanced power to fight back — turning a setback into an opportunity. The buff
# only triggers if the combo was high enough to feel like a real loss (x5+), and
# has a cooldown so it doesn't fire repeatedly during sustained damage. The surge
# is distinct from Adrenaline Rush (which triggers on low HP) — this is about the
# combo, not the HP level.
VENGEFUL_SURGE_COMBO_MIN = 5         # Minimum combo count to trigger the surge
VENGEFUL_SURGE_DURATION = 3.0        # How long the buff lasts (seconds)
VENGEFUL_SURGE_SPEED_MULT = 1.25     # +25% movement speed during surge
VENGEFUL_SURGE_FIRE_RATE_MULT = 1.4  # +40% fire rate during surge (lower cooldown)
VENGEFUL_SURGE_COOLDOWN = 12.0       # Cooldown before the surge can trigger again
VENGEFUL_SURGE_ANNOUNCE_DURATION = 2.0  # How long the HUD announcement stays visible
VENGEFUL_SURGE_COLOR = color.rgb(255, 80, 160)  # Pink-magenta — distinct from adrenaline (orange) and berserk (red)

# ─── Rapid Pickup Chain ─────────────────────────────────────────────────────────
# When the player collects items in very rapid succession (within
# RAPID_CHAIN_WINDOW seconds of each other — tighter than the existing pickup
# streak window), a "RAPID CHAIN" counter increments. Each chain step awards a
# small bonus score that grows with the chain length. This rewards tight, fast
# collection patterns (e.g., vacuuming a cluster of items) and is distinct from
# the broader pickup streak (which has a longer window and awards XP at
# milestones). The chain has its own HUD display and decays if the player doesn't
# collect another item within the window.
RAPID_CHAIN_WINDOW = 1.0             # Seconds between pickups to maintain the chain
RAPID_CHAIN_SCORE_BONUS_BASE = 5     # Base bonus score per chain step
RAPID_CHAIN_SCORE_BONUS_PER_STEP = 2  # Additional score per chain length
RAPID_CHAIN_DISPLAY_LIFETIME = 2.5   # How long the HUD text stays visible
RAPID_CHAIN_COLOR = color.rgb(100, 255, 180)  # Mint green — distinct from pickup streak (gold)
# ── Rapid Chain Break Feedback ── When a rapid chain of 3+ ends (the timer
# expires without another pickup), a brief "CHAIN ENDED xN" message and a
# small mint-green particle puff appear so the player gets closure on their
# chain instead of it silently vanishing. This mirrors the combo break
# shatter feedback, but gentler — a chain ending isn't a failure, just the
# end of a nice run. Only triggers for chains of 3+ so short incidental
# pairs don't clutter the feed. The threshold is high enough that the
# message only fires when the player had a meaningful chain going.
RAPID_CHAIN_BREAK_MIN = 3           # Minimum chain count to trigger break feedback
RAPID_CHAIN_BREAK_PARTICLES = 6    # Small particle puff on chain break

