PARTICLE_COLLECT_COUNT = 16            # More collect sparkles
PARTICLE_LEVELUP_COUNT = 30          # Bigger level-up burst
PARTICLE_COLOR_VARIATION = 0.20      # ±20% random hue shift on each particle for natural, non-uniform bursts

# ─── Muzzle Flash ──────────────────────────────────────────────────────────────
