MOVEMENT_DUST_COUNT = 2              # Number of dust particles per puff

# ─── Enemy Smooth Rotation ──────────────────────────────────────────────────
ENEMY_TURN_SPEED = 8.0               # How fast enemies rotate to face the player (higher = snappier)

# ─── Enemy Chase Predictive Lead ──────────────────────────────────────────────
# When chasing the player, enemies aim at a predicted future position instead
# of the player's current position — a simple pursuit curve that makes enemies
# feel smarter and more predatory. Without this, enemies always head toward
# where the player IS, which produces a naive "tail chase" when the player
# moves sideways: enemies trail behind in a straight line, making kiting too
# easy and enemies look dim-witted. With predictive lead, enemies cut the
# corner and intercept, so the player must actively change direction to shake
# them — making kiting more engaging and enemies feel like they're anticipating
# your movement rather than blindly following. The lead is proportional to the
# player's velocity, capped so fast-moving players aren't impossible to escape.
# The prediction factor scales down for fast enemies (they already reach the
# player quickly) and up for slow enemies (they need the lead to stay relevant).
ENEMY_CHASE_PREDICT_LEAD = 0.35     # Seconds ahead to predict player position
ENEMY_CHASE_PREDICT_MAX = 6.0      # Max lead distance (world units) to prevent absurd interception
ENEMY_CHASE_PREDICT_SPEED_THRESHOLD = 3.0  # Player speed below which no lead is applied (standing still = no prediction)

# ─── Enemy Wander Direction Smoothing ────────────────────────────────────────
# When wandering, enemies lerp toward their new wander direction instead of
# snapping instantly. This makes idle movement feel more natural and organic —
# enemies curve gracefully into new directions like creatures meandering
# rather than teleporting their facing vector on a timer tick.
ENEMY_WANDER_TURN_SPEED = 3.0  # How fast the actual wander dir lerps toward target

# ─── Player-Level Difficulty Scaling ──────────────────────────────────────────
PLAYER_LEVEL_DIFFICULTY_INTERVAL = 5   # Player levels per difficulty tier increase
ENEMY_HP_SCALE_PER_TIER = 0.15        # +15% enemy HP per difficulty tier above base
ENEMY_DAMAGE_SCALE_PER_TIER = 0.10    # +10% enemy damage per difficulty tier above base
# ── Smooth Inter-Tier Difficulty Interpolation ── Instead of stepping difficulty
# in hard tiers at every 5 levels (which makes enemies suddenly jump in toughness
# at levels 6, 11, 16...), the scaling now interpolates smoothly between tiers. The
# fractional portion of the tier calculation is used to blend toward the next
# tier, producing a continuous difficulty curve. At level 6 you get 20% of the
# tier-1 bonus; at level 8 you get 60%; at level 10 you get the full tier-1 bonus.
# This makes progression feel more natural — enemies gradually get tougher rather
# than abruptly stepping up at milestone levels, reducing the "sudden difficulty
# spike" frustration and making the power curve feel polished.

# ─── Damage Numbers ──────────────────────────────────────────────────────────
DMG_NUMBER_LIFETIME = 1.0
DMG_NUMBER_RISE_SPEED = 3.0
DMG_NUMBER_SCALE = 1.2
# ── Damage Number Horizontal Drift ── Damage numbers don't just rise straight
# up — they also drift slightly to the side, giving each number a gentle arc
# instead of a rigid vertical line. The drift direction is random per number
# and the drift speed decays over the number's lifetime so it eases to a stop,
# producing a natural floating-leaf feel rather than a mechanical elevator.
DMG_NUMBER_DRIFT_SPEED = 1.2   # Max horizontal drift speed (world units/sec)
DMG_NUMBER_DRIFT_DECAY = 2.0   # How fast drift decays (higher = stops sooner)

# ─── HP Bar Heal Pulse ───────────────────────────────────────────────────────
# When the player heals from any source (Health Potion, fragment, regen, level-up,
# idle regen, shrine, spawn zone), the HP bar briefly glows brighter green and
# pulses in scale — a positive counterpart to the existing damage shake. This
# makes every heal feel rewarding and visible at the HUD level, not just through
# the screen flash that only fires at low HP. The pulse decays smoothly over
# HP_BAR_HEAL_PULSE_DURATION seconds.
HP_BAR_HEAL_PULSE_DURATION = 0.5   # How long the heal pulse lasts (seconds)
HP_BAR_HEAL_PULSE_SCALE = 1.4      # Peak Y-scale multiplier during the pulse
HP_BAR_HEAL_PULSE_GLOW_ALPHA = 120  # Peak glow alpha on the HP bar background

# ─── Kill Score Popup ────────────────────────────────────────────────────────
# When an enemy is killed, a small "+N pts" floating number appears at the kill
# location in bright cyan-white — distinct from the yellow damage/kill number.
# This makes the score reward tangible and immediate: you see exactly how many
# points each kill was worth, which is especially satisfying at high combo
# multipliers where the score scales up significantly. The popup uses the
# existing DamageNumber system with a dedicated flag for clean rendering.
KILL_SCORE_POPUP_COLOR = color.rgb(120, 255, 255)  # Bright cyan-white

# ─── Per-Enemy Bob Variation ─────────────────────────────────────────────────
# Enemies bob up and down while alive, but previously all used the same frequency
# (2.0 rad/s) with only phase variation via id() % 100. This made groups of
# enemies look synchronized — all breathing in unison. Now each enemy gets a
# random bob frequency and amplitude within a range, so the world feels more
# alive and organic. Small/fast enemies bob quicker; large enemies bob slower.
ENEMY_BOB_FREQ_MIN = 1.4     # Minimum bob frequency (rad/s)
ENEMY_BOB_FREQ_MAX = 3.0     # Maximum bob frequency (rad/s)
ENEMY_BOB_AMP_MIN = 0.12     # Minimum bob amplitude (world units)
ENEMY_BOB_AMP_MAX = 0.32     # Maximum bob amplitude (world units)

# ─── Low-HP Danger Overlay ──────────────────────────────────────────────────
LOW_HP_VIGNETTE_THRESHOLD = 0.30   # HP ratio below which the danger vignette appears
LOW_HP_VIGNETTE_MAX_ALPHA = 90     # Peak alpha of red vignette at 0 HP
LOW_HP_HEARTBEAT_SPEED = 8.0      # How fast the vignette pulses (mimics heartbeat)
LOW_HP_HEARTBEAT_SPEED_MAX = 14.0 # Heartbeat speeds up as HP approaches 0 for escalating tension

# ─── Level-Up Feedback ──────────────────────────────────────────────────────
LEVEL_UP_SCALE_BOUNCE_DURATION = 0.6    # How long the player bounces on level-up
LEVEL_UP_SCALE_BOUNCE_FACTOR = 1.6      # Peak scale multiplier on level-up bounce
LEVEL_UP_TEXT_SCALE = 3.5               # Larger text for level-up announcement
LEVEL_UP_COLOR_FLASH_DURATION = 0.5     # How long the player model flashes yellow on level-up
LEVEL_UP_SCREEN_SHAKE = 0.2             # Small screen shake on level-up for impact
# ── Level-Up Speed Burst ── On level-up, the player gets a brief movement speed
# burst — making leveling feel immediately empowering rather than just a passive
# stat increase. The burst is short (2s) and modest (1.3x) so it's a satisfying
# "surge of energy" without being overpowered. Uses a dedicated timer so it
# composes cleanly with other speed buffs (Speed Boost, Monolith, Adrenaline).
LEVEL_UP_SPEED_BURST_DURATION = 2.0     # How long the speed burst lasts (seconds)
LEVEL_UP_SPEED_BURST_MULT = 1.3         # Speed multiplier during the burst

# ─── Death Screen ────────────────────────────────────────────────────────────
DEATH_SCREEN_TITLE_COLOR = color.rgb(255, 40, 40)    # Brighter red for more impact
DEATH_SCREEN_STATS_COLOR = color.rgba(220, 220, 255, 255)  # Slightly blue-white for readability
# ── Death Screen Staggered Fade-In ── When the player dies, the death screen
# elements (title, subtitle, stats, restart prompt) cascade in with a staggered
# fade-in instead of all snapping visible at once. Each element starts at 0
# alpha and ramps to full over DEATH_SCREEN_FADE_DURATION seconds, with a
# DEATH_SCREEN_FADE_STAGGER delay between successive elements. This makes
# death feel cinematic and weighty — the title hits first, then the score
# counts up, then the full stats materialize, then the restart prompt appears
# — instead of a jarring instant full-screen reveal. The score in the subtitle
# also rolls up from 0 to the final value (using the same lerp as the HUD score
# rollup) so the final number feels earned, not just dumped on screen.
DEATH_SCREEN_FADE_DURATION = 0.5    # Seconds for each element to fade from 0 to full alpha
DEATH_SCREEN_FADE_STAGGER = 0.25    # Delay between successive elements starting their fade
DEATH_SCREEN_SCORE_ROLLUP_SPEED = 8.0  # Lerp speed for the death-screen score count-up

# ─── Crosshair Enemy-Proximity Tint ──────────────────────────────────────────
# When the mouse cursor's world position is near an enemy, the crosshair
# subtly tints toward a warm red-orange — giving target-acquisition feedback
# BEFORE you fire. This makes aiming feel more connected to the world: you can
# see at a glance that your crosshair is "on target" without needing to shoot
# first. The tint smoothly interpolates based on how close the cursor is to
# the nearest enemy, so it's subtle at the edge of the proximity radius and
# full-strength when directly over a target. Only checks nearby enemies
# (within CROSSHAIR_PROXIMITY_CHECK_RADIUS of the player) to avoid iterating
# the entire enemy list every frame.
CROSSHAIR_PROXIMITY_RADIUS = 3.5       # How close cursor must be to an enemy to trigger tint (world units)
CROSSHAIR_PROXIMITY_CHECK_RADIUS = 40  # Only check enemies within this distance of the player
CROSSHAIR_PROXIMITY_TINT_COLOR = color.rgb(255, 100, 60)  # Warm red-orange target hint
CROSSHAIR_PROXIMITY_TINT_ALPHA = 200   # Max alpha boost when directly over an enemy

# ─── Ground Aim Reticle ───────────────────────────────────────────────────────
# A visible 3D ring on the ground at the mouse world_point position, showing
# exactly where the player's tentacle laser shots are aimed in the 3D world.
# The reticle is a thin cyan ring that sits flat on the ground, pulses gently
# to feel alive, and brightens when near an enemy (matching the crosshair
# proximity tint). This gives the player a clear, glanceable ground-level aim
# indicator — especially useful in a 3D third-person game where the screen
# crosshair doesn't map 1:1 to the ground target. Makes precision aiming at
# distant enemies far more readable.
GROUND_RETICLE_RADIUS = 0.6            # Base ring radius (world units)
GROUND_RETICLE_ALPHA = 140             # Base ring alpha
GROUND_RETICLE_COLOR = (0, 220, 255)   # Cyan — matches the laser/energy aesthetic
GROUND_RETICLE_PULSE_SPEED = 6.0       # How fast the reticle pulses (Hz)
GROUND_RETICLE_PULSE_AMOUNT = 0.15    # Scale pulse amount (0.15 = ±15%)
GROUND_RETICLE_ENEMY_ALPHA = 230      # Brighter alpha when near an enemy
GROUND_RETICLE_ENEMY_SCALE = 1.3      # Scale multiplier when near an enemy
GROUND_RETICLE_Y = 0.06               # Y position (just above ground to avoid z-fighting)

# ─── Enemy Health Fragment Drops ──────────────────────────────────────────────
# When an enemy dies, there's a chance it drops a small green "health fragment"
# orb that heals the player when collected. This adds a combat-sustain loop —
# aggressive players who chain kills can recover HP from the battlefield itself,
# rewarding proactive combat instead of forcing retreats to find Health Potions.
# The fragments are small green orbs that bob and glow, use the existing
# collectible pickup system, and scale their heal amount with enemy max HP
# (tougher enemies drop more potent fragments). A subtle green particle burst
# marks the spawn so the player notices them.
HEALTH_FRAGMENT_DROP_CHANCE = 0.18    # 18% chance per enemy death
HEALTH_FRAGMENT_DROP_CHANCE_ELITE = 0.30  # 30% for high-HP enemies
HEALTH_FRAGMENT_ELITE_HP_THRESHOLD = 100  # HP above which the elite drop chance applies
HEALTH_FRAGMENT_HEAL_BASE = 5         # Base heal amount
HEALTH_FRAGMENT_HEAL_PER_MAX_HP = 0.1 # Heal scales with enemy max HP (0.1 HP per max HP)
HEALTH_FRAGMENT_HEAL_MAX = 15          # Cap so high-HP bosses don't drop full-heal orbs
HEALTH_FRAGMENT_RADIUS = 0.35         # Visual orb radius (world units)
HEALTH_FRAGMENT_COLOR = (80, 255, 100)  # Bright green
HEALTH_FRAGMENT_GLOW_ALPHA = 80       # Glow ring alpha
HEALTH_FRAGMENT_GLOW_RADIUS = 1.2     # Glow ring radius around the fragment
HEALTH_FRAGMENT_PICKUP_RADIUS = 2.0   # How close the player must be to collect it
HEALTH_FRAGMENT_LIFETIME = 20.0       # Seconds before the fragment despawns
HEALTH_FRAGMENT_DESPAWN_FADE = 3.0   # Seconds of fade-out before despawn
HEALTH_FRAGMENT_BOB_HEIGHT = 0.3     # How high the orb bobs above ground
HEALTH_FRAGMENT_BOB_SPEED = 3.0       # Bob oscillation speed
HEALTH_FRAGMENT_SPIN_SPEED = 120.0    # Rotation speed (degrees/sec)
HEALTH_FRAGMENT_PARTICLE_COUNT = 6   # Particles on spawn

