FACING_ARROW_DASH_COLOR = (0, 220, 255)  # Cyan during dash — matches dash VFX
FACING_ARROW_Y = 0.05                # Y position (just above ground)
FACING_ARROW_ROT_LERP = 12.0         # How fast the arrow rotates to face direction

