# ── Dash-End FOV Ease-Out ── When the dash ends, the FOV transitions from the
# wide dash FOV back to normal. Instead of a flat linear lerp (which feels
# mechanical and abrupt), we split the recovery into two phases: a fast
# initial snap (covers most of the gap quickly for a snappy "landing") then
# a slower ease-out for the final few degrees (a gentle settle that feels
# like decelerating from the dash speed). This makes the FOV recovery feel
# like a natural deceleration rather than a robotic slide.
DASH_FOV_EASE_FAST_SPEED = 16.0   # Fast initial FOV recovery speed
DASH_FOV_EASE_SLOW_SPEED = 5.0    # Slower ease-out speed for the final settle
DASH_FOV_EASE_SPLIT = 0.5          # FOV gap (degrees) at which fast→slow transition occurs
DASH_CAMERA_LERP_SPEED = 12.0  # Tighter camera follow during dash (faster than normal 6.0)
DASH_INVULN_DURATION = 0.3  # Seconds of invulnerability during dash — makes dash a dodge tool
DASH_READY_FLASH_DURATION = 0.4  # How long the dash-ready flash pulse lasts
DASH_READY_FLASH_COLOR = color.rgba(0, 255, 255, 0)  # Brief cyan flash when dash comes off cooldown

# ─── Ability Cooldown Bars ──────────────────────────────────────────────────────
# Visual progress bars beneath the dash and pulse wave HUD text that fill up
# as the ability comes off cooldown — so players can see at a glance how close
# a cooldown is to finishing instead of only reading a number.
ABILITY_BAR_BG_COLOR = color.rgba(60, 60, 60, 180)
ABILITY_BAR_FILL_COLOR = color.rgba(0, 255, 255, 220)  # Cyan for dash
ABILITY_BAR_WIDTH = 0.18
ABILITY_BAR_HEIGHT = 0.01
ABILITY_BAR_POS_DASH = (-0.65, 0.345)     # Beneath the dash HUD text
ABILITY_BAR_POS_PULSE = (-0.65, 0.185)    # Beneath the pulse wave HUD text
# ── Ability Bar Near-Ready Anticipation Glow ── When an ability cooldown bar
# is >85% filled (nearly ready), a gentle pulsing brightness is added to the
# fill color so the player can see at a glance that the ability is about to
# come off cooldown — matching the XP bar anticipation glow pattern. The
# pulse speed ramps up as the bar fills closer to 100%, creating escalating
# anticipation in the final ~0.3s before readiness. This makes ability
# cooldowns feel more alive and readable instead of a flat linear fill.
ABILITY_BAR_ANTICIPATION_THRESHOLD = 0.85  # Fill ratio where anticipation glow begins
ABILITY_BAR_ANTICIPATION_PULSE_MIN = 6.0   # Min pulse speed (Hz) at threshold
ABILITY_BAR_ANTICIPATION_PULSE_MAX = 18.0   # Max pulse speed (Hz) at 100% ready
ABILITY_BAR_ANTICIPATION_GLOW = 60         # Max brightness added to fill at peak pulse

# ─── Power-Up Durations ───────────────────────────────────────────────────────
SPEED_BOOST_DURATION = 6.0              # Longer speed boost — feels too short at 5s
SPEED_BOOST_MULTIPLIER = 1.8
SHIELD_DURATION = 5.0                    # Longer shield — 4s was too brief to enjoy
SHIELD_PULSE_WARNING_THRESHOLD = 1.5     # Seconds remaining before shield pulses warm/red
SHIELD_PULSE_WARNING_SPEED = 14.0        # How fast the warning pulse accelerates near expiry
HEALTH_POTION_HEAL = 55                 # More healing — 50 felt underwhelming for mid-game enemies
# ── Health Potion Level Scaling ── Health Potions heal a flat base amount plus
# a small per-level bonus so they remain relevant throughout the game. At early
# game (120 max HP) the base 55 is generous (~46% heal); at level 15 (max HP
# ~300) the bonus adds +30, making potions heal 85 — still a meaningful ~28%
# heal instead of the un-scaled 18%. The bonus is linear and modest so potions
# supplement (not replace) level-up heals and combat sustain.
HEALTH_POTION_HEAL_PER_LEVEL = 2        # Bonus heal per player level

# ─── Combo System ────────────────────────────────────────────────────────────
COMBO_TIMEOUT = 5.0        # seconds before combo resets (slightly more forgiving for smoother chaining)
COMBO_XP_BONUS_PER_TIER = 0.15  # +15% XP per combo tier (up from 12% — rewards skillful chains)
COMBO_SCORE_BONUS_PER_TIER = 0.08  # +8% score per combo tier (up from 6%)
COMBO_DISPLAY_LIFETIME = 2.5
COMBO_MAX_TIER = 20  # Combo XP/score multipliers scale up to tier 20 (was 10) — rewards high-skill sustained chains
# ── High-Combo Timeout Scaling ── As the combo grows, the timeout window gently
# extends — making it slightly easier to maintain long kill streaks. At low
# combos the base 5s timeout applies (unchanged). Starting at combo x5, each
# tier adds COMBO_TIMEOUT_BONUS_PER_TIER seconds (capped at
# COMBO_TIMEOUT_BONUS_MAX). This rewards high-skill sustained chains: the
# higher your combo, the more breathing room you have to find the next kill —
# which matters most when most nearby enemies are already dead. The scaling is
# gentle (max +2.5s at x12+) so it doesn't make combos trivial to maintain,
# just less punishing for the highest streaks where kills are hardest to chain.
COMBO_TIMEOUT_SCALING_START = 5      # Combo count where timeout scaling begins
COMBO_TIMEOUT_BONUS_PER_TIER = 0.3   # Extra seconds per tier above the start
COMBO_TIMEOUT_BONUS_MAX = 2.5        # Maximum extra seconds (cap at +2.5s)
COMBO_BAR_REFRESH_FLASH_DURATION = 0.25  # How long the combo timer bar flashes green on each kill that extends the combo
# ── Combo Break Shatter ── When a combo of x3+ expires (timer runs out without
# a kill to refresh it), a red "COMBO BROKEN!" text pops and shatter particles
# burst from Zorp. This makes losing a high combo feel impactful instead of
# the combo silently disappearing — the player gets clear feedback that their
# streak ended, which makes maintaining combos feel more meaningful. Only
# triggers for combos of x3 or higher so early small combos don't spam the
# screen. The announcement uses the same pop-in/hold/fade-out animation
# pattern as the multi-kill announcement for visual consistency.
COMBO_BREAK_MIN_TIER = 3          # Minimum combo count to trigger the break effect
COMBO_BREAK_ANNOUNCE_DURATION = 1.2  # How long the "COMBO BROKEN!" text stays visible
COMBO_BREAK_PARTICLE_COUNT = 14   # Red shatter particles on combo break
COMBO_BREAK_SCREEN_SHAKE = 0.25   # Screen shake intensity on combo break

# ─── Enemy Pack Aggro ──────────────────────────────────────────────────────────
# When an enemy detects the player, nearby idle (non-alerted) enemies within
# PACK_AGGRO_RADIUS also get alerted — creating dynamic pack behavior where
# aggroing one enemy can cascade to nearby enemies. This makes combat more
# tactical: the player must consider which enemies are near each other before
# engaging, and dense enemy clusters become more dangerous than isolated foes.
# Only alerts enemies that are already within their own detect range of the
# player, so far-away enemies don't magically aggro through walls. The chain
# has a cooldown per source enemy so it doesn't fire every frame.
PACK_AGGRO_RADIUS = 12.0          # How far aggro chains to nearby idle enemies
PACK_AGGRO_MAX_CHAIN = 4          # Max additional enemies alerted per trigger
PACK_AGGRO_COOLDOWN = 3.0         # Cooldown before an enemy can chain-aggro again

