# ─── Boss Death Slow-Motion ──────────────────────────────────────────────────
# When a boss-tier enemy (Plasma Drake, 350 HP) is killed, the game enters a
# brief slow-motion effect — time.dt is scaled down for a fraction of a second
# so the boss's death animation, particle explosion, and screen shake play out
# in dramatic cinematic slow-mo. This makes boss kills feel like momentous,
# memorable events instead of just another enemy death. The slow-mo tapers
# smoothly back to normal speed (no abrupt snap) and only triggers for the
# toughest enemies so it stays special.
BOSS_DEATH_SLOWMO_DURATION = 0.5     # How long the slow-motion lasts (seconds, real-time)
BOSS_DEATH_SLOWMO_SCALE = 0.35       # Time scale during slow-mo (0.35 = 35% speed)
BOSS_DEATH_SLOWMO_RECOVER_SPEED = 3.0  # How fast time scale recovers to 1.0
BOSS_DEATH_HP_THRESHOLD = 300        # Enemy max_hp at or above this triggers slow-mo

# ─── Enemy Spawn Materialization Flash ────────────────────────────────────────
# When an enemy materializes from a spawn warning, a bright expanding flash
# sphere appears at the spawn point in addition to the existing vertical
# particle burst. The flash pops to full size instantly and fades over a
# fraction of a second, giving the materialization a punchy "light burst"
# effect that makes enemy appearances feel more dramatic and noticeable —
# especially in dark biomes or at distance where the particle column alone
# might be hard to see.
SPAWN_FLASH_DURATION = 0.18          # How long the flash sphere lasts (seconds)
SPAWN_FLASH_SCALE = 2.5             # Peak scale of the flash sphere
SPAWN_FLASH_COLOR = color.rgba(255, 180, 100, 200)  # Warm orange-white flash

# ─── Player Footstep Ground Ripples ──────────────────────────────────────────
# While running, Zorp periodically emits small expanding ground rings from his
# position — subtle "footstep ripples" that give movement more visual weight
# and ground connection. The ripples are biome-tinted (matching the movement
# dust color) and expand outward quickly before fading, so they don't clutter
# the screen but add a sense of momentum and physicality to running. They
# fire at a steady interval while moving and stop when standing still.
FOOTSTEP_RIPPLE_INTERVAL = 0.28     # Seconds between footstep ripples while moving
FOOTSTEP_RIPPLE_DURATION = 0.35     # How long each ripple expands before fading
FOOTSTEP_RIPPLE_START_SCALE = 0.6   # Starting scale of the footstep ring
FOOTSTEP_RIPPLE_MAX_SCALE = 2.0     # Max scale the ripple reaches
FOOTSTEP_RIPPLE_ALPHA = 60          # Starting alpha of the footstep ring

# ─── Collectible Beacon Pulse ──────────────────────────────────────────────────
# In addition to the normal glow pulse, collectibles periodically emit a
# larger, brighter "beacon" pulse — a brief expansion of the glow ring well
# beyond its normal range. This makes items easier to spot from far away,
# especially rare+ collectibles that are worth seeking out. The beacon fires
# at random intervals so items don't all beacon in sync, and the expansion
# is larger and faster than the normal breathing pulse for clear visibility.
COLLECT_BEACON_INTERVAL_MIN = 4.0   # Min seconds between beacon pulses
COLLECT_BEACON_INTERVAL_MAX = 8.0   # Max seconds between beacon pulses
COLLECT_BEACON_DURATION = 0.6       # How long the beacon expansion lasts
COLLECT_BEACON_SCALE_MULT = 2.2     # Max glow scale multiplier during beacon (relative to max_scale)
COLLECT_BEACON_ALPHA_MULT = 1.8     # Brightness multiplier during beacon peak

# ─── Overkill System ──────────────────────────────────────────────────────────
OVERKILL_DAMAGE_THRESHOLD = 25  # Minimum excess damage to trigger Overkill
OVERKILL_XP_BONUS = 20            # Bonus XP for overkill
OVERKILL_SCREEN_SHAKE = 0.3      # Screen shake on overkill
OVERKILL_PARTICLE_COUNT = 15     # Particle burst on overkill
# ── Overkill Surge ── When the overkill damage exceeds OVERKILL_SURGE_THRESHOLD
# (50+ excess damage), a guaranteed chain lightning arcs from the killed enemy
# to nearby enemies — bypassing the normal combo requirement and chance roll.
# This makes massive overkill hits (high-level crits, combo-buffed shots, etc.)
# feel truly explosive: the excess energy literally leaps from the corpse to
# nearby enemies. A special "OVERKILL SURGE!" announcement and extra orange
# particles celebrate the cascade. The surge uses a wider range and more
# targets than normal chain lightning so it feels distinctly more powerful.
OVERKILL_SURGE_THRESHOLD = 50       # Excess damage needed to trigger the surge
OVERKILL_SURGE_RANGE = 12.0         # How far the surge lightning reaches (wider than normal)
OVERKILL_SURGE_MAX_TARGETS = 6      # More targets than normal chain lightning
OVERKILL_SURGE_DAMAGE_MULT = 1.5   # Damage multiplier vs normal chain lightning
OVERKILL_SURGE_PARTICLE_COUNT = 20  # Extra orange particles on surge
OVERKILL_SURGE_SCREEN_SHAKE = 0.4  # Screen shake on surge
OVERKILL_SURGE_ANNOUNCE_DURATION = 1.5  # How long the announcement stays

# ─── First Blood Bonus ───────────────────────────────────────────────────────
# The very first enemy kill of each run grants bonus XP and a dramatic
# "FIRST BLOOD!" announcement with a red particle burst. This gives the opening
# moments of a run a more impactful kickoff — the first kill feels special
# instead of being just another number ticking up. The bonus is a flat amount
# so it's meaningful early (when XP is scarce) without being unbalancing later.
FIRST_BLOOD_XP_BONUS = 40          # Bonus XP awarded for the first kill of a run
FIRST_BLOOD_PARTICLE_COUNT = 18    # Red particle burst on first blood
FIRST_BLOOD_SCREEN_SHAKE = 0.3     # Screen shake on first blood

# ─── Combo Sustain Heal ──────────────────────────────────────────────────────
# At combo x10+, every COMBO_SUSTAIN_HEAL_INTERVAL kills within the combo heals
# Zorp a small amount. This rewards sustained combat with survivability — a
# player who maintains a high kill streak is rewarded with passive healing,
# making aggressive playstyles more viable in long fights and creating a
# risk/reward dynamic (keep fighting to heal, but risk taking damage). The heal
# only triggers at high combos so it doesn't trivialize early combat, and the
# amount is small enough that it supplements (not replaces) Health Potions.
COMBO_SUSTAIN_HEAL_THRESHOLD = 10  # Combo count needed to start healing
COMBO_SUSTAIN_HEAL_INTERVAL = 5    # Every N kills within the combo heals
COMBO_SUSTAIN_HEAL_AMOUNT = 8       # HP healed per interval
COMBO_SUSTAIN_HEAL_MAX_FRACTION = 0.05  # Heal capped at 5% of max HP per tick

# ─── Swarm Escape ────────────────────────────────────────────────────────────
# When the player is surrounded (SWARM_ESCAPE_COUNT or more enemies within
# SWARM_ESCAPE_RADIUS), Zorp gets a temporary movement speed boost — a
# "swarm escape" instinct that helps break out of being mobbed. This makes
# being surrounded less frustrating (you can always escape if you move) while
# keeping the danger real (the boost only applies while surrounded, so you
# must actually move away). The boost is modest so it doesn't trivialize
# melee enemies, but enough to create a window of opportunity.
SWARM_ESCAPE_COUNT = 4             # Min enemies within radius to trigger escape
SWARM_ESCAPE_RADIUS = 12.0         # Radius to count enemies for swarm detection
SWARM_ESCAPE_SPEED_MULT = 1.2       # +20% movement speed while surrounded
SWARM_ESCAPE_CHECK_INTERVAL = 0.25  # How often to recount (seconds)

# ─── HP Bar Damage Shake ──────────────────────────────────────────────────────
# ── Player Damage Ground Impact Ring ── When Zorp takes damage, a brief
# expanding red ring radiates outward from his position on the ground —
# matching the established visual language of heal pulse rings (green),
# dash landing rings (biome-tinted), footstep ripples, muzzle flash rings
# (cyan), enemy death rings, and pickup rings. Every other gameplay event
# has a ground ring, but player damage didn't — making hits feel less
# grounded than they should. The red impact ring makes each hit feel like
# it has physical presence in the world: you see the damage ripple outward
# from where Zorp was standing, complementing the existing screen shake,
# HP bar shake, damage particles, danger vignette, and damage direction
# indicator with a ground-level visual that's visible from the third-person
# camera even when looking straight down.
PLAYER_DAMAGE_RING_DURATION = 0.35    # How long the ring expands (seconds)
PLAYER_DAMAGE_RING_START_SCALE = 0.5  # Starting scale of the impact ring
PLAYER_DAMAGE_RING_MAX_SCALE = 3.0    # Max scale the impact ring reaches
PLAYER_DAMAGE_RING_ALPHA = 120        # Starting alpha of the impact ring
HP_BAR_SHAKE_DURATION = 0.4      # How long the HP bar shakes after taking damage
HP_BAR_SHAKE_INTENSITY = 0.012  # Max pixel offset of the HP bar shake

