# ─── Combo Orb Drops ───────────────────────────────────────────────────────────
# When the player kills an enemy at a high combo (x10+), there's a chance to drop
# a special golden "Combo Orb" collectible. This orb grants bonus XP and score
# proportional to the current combo count — the higher your streak, the more
# valuable the orb. This rewards sustained combat streaks with a tangible,
# collectible reward that's visually distinct from regular loot. The orb uses
# the existing collectible pickup system (magnetic pull, vacuum pulse, etc.)
# so it integrates naturally. The drop chance scales with combo count so higher
# combos are more likely to produce an orb.
COMBO_ORB_COMBO_THRESHOLD = 10         # Minimum combo to potentially drop an orb
COMBO_ORB_DROP_CHANCE_BASE = 0.08      # 8% base drop chance at threshold
COMBO_ORB_DROP_CHANCE_PER_TIER = 0.02  # +2% per combo tier above threshold
COMBO_ORB_DROP_CHANCE_MAX = 0.25       # Capped at 25%
COMBO_ORB_XP_BASE = 50                 # Base bonus XP from a combo orb
COMBO_ORB_XP_PER_COMBO = 3             # Additional XP per current combo count
COMBO_ORB_SCORE_BASE = 100             # Base bonus score from a combo orb
COMBO_ORB_SCORE_PER_COMBO = 10         # Additional score per current combo count
COMBO_ORB_COLOR = color.rgb(255, 200, 60)  # Golden-orange — distinct from regular loot

# ─── Adrenaline Overheal Conversion ───────────────────────────────────────────
# When Adrenaline Rush is active (triggered at low HP), excess healing is
# converted to overheal at a boosted rate instead of being wasted. Normally,
# healing beyond max HP is lost. During Adrenaline Rush, the "fight or flight"
# state channels excess healing into a temporary overheal barrier at 150%
# efficiency — so a 30 HP heal when you're 10 HP from max gives 10 HP to real
# health plus 30 HP of overheal (20 excess * 1.5 = 30). This makes clutch
# adrenaline moments more survivable and rewards the risk of playing at low HP
# by turning overhealing into a tactical advantage rather than a waste.
ADRENALINE_OVERHEAL_CONVERSION_RATE = 1.5  # Excess healing → overheal multiplier during adrenaline

# ─── Enemy Hit Slow Chance ────────────────────────────────────────────────────
# Each projectile hit has a chance to briefly slow the enemy's movement speed,
# simulating the laser energy disrupting the enemy's locomotion. This adds
# tactical depth to combat — lucky shots temporarily slow fast enemies like
# Swarm Mites and Void Wisps, making them easier to hit and kite. The slow
# applies a brief blue tint to the enemy so the player can see it's working.
# The chance and duration are modest so it's a nice bonus rather than a
# reliable strategy — you can't count on it, but when it procs on a fast
# enemy it feels great. Distinct from Time Warp (which slows ALL enemies
# as a power-up) — this is a per-hit random proc on individual enemies.
ENEMY_HIT_SLOW_CHANCE = 0.20          # 20% chance per projectile hit to slow the enemy
ENEMY_HIT_SLOW_DURATION = 1.5         # How long the slow lasts (seconds)
ENEMY_HIT_SLOW_MULT = 0.5             # Speed multiplier while slowed (50% of normal)
ENEMY_HIT_SLOW_TINT = color.rgb(100, 180, 255)  # Blue tint applied to slowed enemies
# ── Hit Slow Crack Particles ── When the hit slow procs, a burst of small
# ice-blue crack particles spawns around the enemy in addition to the blue
# tint, making the slow immediately visually readable — you see the enemy
# get "frozen" by the laser energy as crack-like particles burst from the
# impact point. The particles use a bright blue-white color that's distinct
# from the hit flash (which uses the enemy's own color) so the slow proc is
# instantly distinguishable from a normal hit.
ENEMY_HIT_SLOW_CRACK_PARTICLES = 8   # Number of crack particles on slow proc
ENEMY_HIT_SLOW_CRACK_COLOR = color.rgb(150, 220, 255)  # Ice-blue crack particles

# ─── Speed Boost Energy Trail ─────────────────────────────────────────────────
# When the Speed Boost power-up is active, a vibrant green energy trail with
# sparkle particles follows Zorp — making the speed boost visually exciting and
# distinct from the normal subtle movement trail. The trail spawns more
# frequently and with brighter, larger particles than the normal movement trail,
# and includes occasional upward sparkles that make Zorp look like he's glowing
# with speed energy. This makes the Speed Boost feel like a significant power-up
# visually, not just a stat change — you SEE the difference immediately.
SPEED_BOOST_TRAIL_INTERVAL = 0.04     # Seconds between trail particles while speed-boosted
SPEED_BOOST_TRAIL_SCALE = 0.3         # Size of trail particles
SPEED_BOOST_TRAIL_LIFETIME = 0.4      # How long each trail particle lives
SPEED_BOOST_SPARKLE_INTERVAL = 0.12   # Seconds between upward sparkle spawns
SPEED_BOOST_SPARKLE_COUNT = 2         # Sparkles per spawn
SPEED_BOOST_SPARKLE_RISE_SPEED = 3.0  # Upward speed of sparkles
SPEED_BOOST_TRAIL_COLOR = color.rgb(80, 255, 80)  # Bright green — matching Speed Boost

# ─── Idle HP Regeneration ──────────────────────────────────────────────────────
# When Zorp stands still for a few seconds without taking damage, HP slowly
# regenerates — rewarding tactical pauses and reducing frustration from chip
# damage in long fights. Encourages hit-and-run playstyle.
IDLE_REGEN_DELAY = 3.0                # Seconds of inactivity before regen starts
IDLE_REGEN_HP_PER_SECOND = 4           # HP restored per second while idle
IDLE_REGEN_PARTICLE_INTERVAL = 1.0    # Seconds between idle regen heal particles
# ── Idle Regen Sparkle Stream ── While idle HP regeneration is active, a
# gentle continuous stream of small green sparkles rises from Zorp's body —
# making the healing feel magical and alive instead of a silent HP number
# ticking up. The sparkles spawn at a faster interval than the 1-second heal
# tick, so there's always visible healing energy flowing even between the
# actual HP-gaining moments. Each sparkle is a tiny green sphere that drifts
# upward and fades, like healing motes being absorbed into Zorp.
IDLE_REGEN_SPARKLE_INTERVAL = 0.18   # Seconds between sparkle spawns while regenerating
IDLE_REGEN_SPARKLE_COUNT = 1         # Sparkles per spawn
IDLE_REGEN_SPARKLE_RISE_SPEED = 2.5  # Upward drift speed of regen sparkles
IDLE_REGEN_SPARKLE_LIFETIME = 0.6    # How long each sparkle lives (seconds)
IDLE_REGEN_SPARKLE_SCALE = 0.08     # Size of regen sparkle particles

# ─── Overheal Barrier ──────────────────────────────────────────────────────────
# When the player picks up a Health Potion at full HP (or the heal would exceed
# max HP), the excess healing converts into a temporary "overheal" barrier —
# extra HP that decays over time. This makes Health Potions valuable even in
# late-game when the player is often at full HP, instead of being wasted.
# The barrier is displayed as a golden extension of the HP bar and a golden
# ring around the player.
OVERHEAL_MAX = 60                   # Maximum overheal barrier amount
OVERHEAL_DECAY_PER_SECOND = 6       # How much overheal decays per second
OVERHEAL_DECAY_DELAY = 3.0          # Seconds before overheal starts decaying
OVERHEAL_RING_COLOR = color.rgb(255, 200, 60)  # Golden ring for overheal visual
# ── Overheal Absorption Burst ── When the Overheal Barrier absorbs damage,
# a golden particle burst and expanding ring fire from the player so the
# barrier's protection is clearly visible. Without this, overheal just
# silently depletes — the player has no feedback that the barrier saved
# them. The burst uses the same golden color as the overheal ring for
# visual cohesion, making it instantly readable as "your overheal absorbed
# that hit" rather than generic damage feedback.
OVERHEAL_ABSORB_PARTICLE_COUNT = 10
OVERHEAL_ABSORB_RING_DURATION = 0.4
OVERHEAL_ABSORB_RING_MAX_SCALE = 3.5

# ─── Adrenaline Rush ──────────────────────────────────────────────────────────
# When the player drops below ADRENALINE_HP_THRESHOLD, they enter an adrenaline
# state: movement speed and fire rate increase briefly, and a red-orange screen
# edge pulse appears. This creates dramatic clutch moments — a "fight or flight"
# response that rewards skilled play under pressure and gives a last chance to
# turn the tide. Triggers once per HP drop; re-triggers after recovering above
# the threshold and dropping again.
ADRENALINE_HP_THRESHOLD = 0.20      # HP ratio below which adrenaline triggers
ADRENALINE_DURATION = 4.0           # How long the adrenaline buff lasts
ADRENALINE_SPEED_MULT = 1.35        # Speed multiplier during adrenaline
ADRENALINE_FIRE_RATE_MULT = 1.5     # Fire rate multiplier (cooldown divided by this)
ADRENALINE_VIGNETTE_MAX_ALPHA = 50  # Peak alpha of the red-orange adrenaline vignette
ADRENALINE_VIGNETTE_PULSE_SPEED = 6.0  # How fast the vignette pulses
ADRENALINE_AURA_COLOR = color.rgba(255, 140, 30, 55)   # Orange-gold adrenaline aura
ADRENALINE_AURA_SCALE = 1.6                              # Aura sphere scale
ADRENALINE_AURA_PULSE_SPEED = 10.0                       # How fast the 3D aura pulses

# ─── Kill Streak Milestone Rewards ─────────────────────────────────────────────
# Every KILL_STREAK_MILESTONE total kills, the player is awarded bonus XP and a
# special announcement with a golden particle celebration. This rewards long-term
# progression and makes reaching kill count milestones feel momentous — by kill
# 100 you've gotten 4 milestone rewards, making the arc of the run feel rewarding
# beyond individual kills and combos. The bonus scales linearly with the milestone
# tier so later milestones (which are harder to reach) give bigger rewards.
KILL_STREAK_MILESTONE = 25             # Total kills per milestone reward
KILL_STREAK_XP_BASE = 60               # Base bonus XP per milestone
KILL_STREAK_XP_PER_TIER = 30           # Additional XP per milestone tier (kill 50 = tier 2 = 60+30)
KILL_STREAK_PARTICLE_COUNT = 25        # Golden particle burst on milestone
KILL_STREAK_SCREEN_SHAKE = 0.35        # Screen shake on milestone

# ─── Treasure Compass ──────────────────────────────────────────────────────────
# When the player stands still for a few seconds, a subtle golden arrow appears
# on the HUD pointing toward the nearest rare-or-better collectible. This makes
# downtime useful, encourages exploration, and helps players find valuable loot
# without a minimap cluttered with item markers. The arrow updates in real-time
# and fades out when the player starts moving again.
COMPASS_IDLE_DELAY = 2.0            # Seconds of standing still before compass appears
COMPASS_SCAN_RADIUS = 80.0          # How far to search for rare+ collectibles
COMPASS_RARE_TIERS = {'rare', 'very_rare', 'legendary', 'mythic'}  # Tiers worth pointing to
COMPASS_ARROW_COLOR = color.rgb(255, 200, 60)  # Golden arrow color
COMPASS_ARROW_FADE_SPEED = 5.0      # How fast the arrow fades in/out

# ─── Enemy Spawn Portal Vortex ──────────────────────────────────────────────
# A spinning flat disc appears beneath the spawn warning ring, rotating faster
# as the enemy materializes. This creates a visual "portal" effect that makes
# enemy spawns feel more dramatic and otherworldly — like the enemy is emerging
# from a dimensional rift rather than just popping into existence.
