SPAWN_VORTEX_END_SPEED = 400     # Final rotation speed (degrees/sec) — spins rapidly as enemy appears
SPAWN_VORTEX_COLOR = color.rgba(180, 40, 200, 0)  # Purple-magenta vortex disc

# ─── Pickup Milestone Celebrations ──────────────────────────────────────────
# When the player collects 50, 100, 200, or 500 total items, a celebratory
# golden particle burst + announcement appears — rewarding dedicated collectors
# and making item gathering feel meaningful beyond individual pickups.
PICKUP_MILESTONES = [50, 100, 200, 500]
PICKUP_MILESTONE_PARTICLES = 30
PICKUP_MILESTONE_SCREEN_SHAKE = 0.3
PICKUP_MILESTONE_ANNOUNCE_DURATION = 2.5
PICKUP_MILESTONE_COLOR = color.rgb(255, 200, 60)  # Golden celebration color

# ─── Pickup Streak System ────────────────────────────────────────────────────
# Tracks consecutive rapid item pickups (like the kill combo system, but for
# collecting items). Each pickup within PICKUP_STREAK_WINDOW seconds extends the
# streak. At milestone streak counts, bonus XP is awarded, making item-gathering
# runs feel rewarding and encouraging players to keep moving and collecting
# rather than picking up one item and pausing.
PICKUP_STREAK_WINDOW = 3.0           # Seconds between pickups before streak resets
PICKUP_STREAK_MILESTONE_INTERVAL = 5 # Bonus XP every 5 pickups in the streak
PICKUP_STREAK_XP_PER_MILESTONE = 15  # Bonus XP per milestone
PICKUP_STREAK_DISPLAY_LIFETIME = 2.5 # How long the streak text stays visible
# ── Pickup Streak Break Feedback ── When a pickup streak of 5+ ends (the
# timer expires without another pickup), a brief "STREAK ENDED xN" message
# appears so the player gets gentle closure on their gathering run instead
# of the streak silently resetting. This is softer than the rapid chain
# break — no particles, just a HUD message — because pickup streaks are
# longer and more casual, so a particle burst would feel disproportionate.
# Only triggers for streaks of 5+ (one full milestone cycle) so short
# streaks don't clutter the feed.
PICKUP_STREAK_BREAK_MIN = 5          # Minimum streak count to trigger break message
PICKUP_STREAK_BAR_FLASH_DURATION = 0.25  # Green flash on the streak bar on each pickup
