# radiates outward from Zorp's position — making heals feel visceral and
# satisfying instead of just a number ticking up silently.
HEAL_PULSE_DURATION = 0.5
HEAL_PULSE_EXPAND_SPEED = 8.0
HEAL_PULSE_MAX_SCALE = 3.5
