# ─── Critical Hit Projectile Pierce ───────────────────────────────────────────
# Critical hits have a chance to pierce through the struck enemy and continue
# flying, potentially hitting enemies behind it. This rewards precision aim —
# lining up enemies for a piercing crit is a high-skill play that can hit
# multiple enemies with a single shot. The pierced enemy still takes full
# damage; the projectile just doesn't get destroyed on crit hits. A visual
# gold trail effect marks pierced projectiles so the player can see the
# shot passing through.
CRIT_PIERCE_CHANCE = 0.40            # 40% chance for a crit to pierce
CRIT_PIERCE_MAX_HITS = 3             # Max enemies a single piercing shot can hit

# ─── Chain Lightning on Kill ────────────────────────────────────────────────
# When the player kills an enemy while on a combo of CHAIN_LIGHTNING_MIN_COMBO
# or higher, there's a chance for lightning to arc from the killed enemy to
# nearby enemies, dealing damage to each. This makes high combos feel
# electrically charged — your kill streaks literally jump between enemies,
# rewarding sustained combat with crowd-clearing power. The damage scales
# with combo count so higher combos produce stronger arcs. A bright cyan
# visual line connects the killed enemy to each struck enemy for clarity.
CHAIN_LIGHTNING_MIN_COMBO = 3        # Combo count needed to trigger
CHAIN_LIGHTNING_CHANCE = 0.35        # Base probability per kill at min combo
CHAIN_LIGHTNING_CHANCE_MAX = 0.65    # Max probability at high combo
CHAIN_LIGHTNING_RANGE = 8.0          # How far lightning arcs
CHAIN_LIGHTNING_MAX_TARGETS = 4      # Max enemies struck per arc
CHAIN_LIGHTNING_DAMAGE_BASE = 10     # Base damage per arc
CHAIN_LIGHTNING_DAMAGE_PER_COMBO = 1 # Extra damage per combo tier above min
CHAIN_LIGHTNING_COLOR = color.rgba(100, 200, 255, 200)  # Bright cyan-white
# ── Jagged Bolt Visual ── The chain lightning now renders as a multi-segment
# zigzag bolt instead of a straight line, making the arc look like actual
# crackling electricity. CHAIN_LIGHTNING_BOLT_SEGMENTS controls how many
# short segments make up the bolt (more = denser crackle), and
# CHAIN_LIGHTNING_BOLT_JITTER controls how far each segment can deviate
# perpendicular to the bolt direction (higher = wider zigzag). The jitter
# uses a sine envelope so it's zero at the endpoints and maximum in the
# middle, producing the classic forked lightning shape that connects
# cleanly at source and target while crackling wildly in between.
CHAIN_LIGHTNING_BOLT_SEGMENTS = 5    # Number of jagged segments per bolt
CHAIN_LIGHTNING_BOLT_JITTER = 0.8    # Max perpendicular offset per segment (world units)

