# ─── Color Helper ──────────────────────────────────────────────────────────────
# BUG FIX: Ursina's color.rgb()/color.rgba() store component values in 0-255
# range, but named colors (color.lime, color.yellow, etc.) store them in 0-1
# range. Any code that reads color components and feeds them to color.rgba()
# or does arithmetic on them MUST normalize first. _c255() converts any color
# component to the 0-255 integer range regardless of which system it came from.

def _c255(component):
    """Normalize a Ursina color component to 0-255 integer range.
    
    Ursina stores named colors (color.lime, color.red, etc.) with 0-1 float
    values, but color.rgb()/color.rgba() use 0-255 integer values. This
    helper safely converts either format to 0-255 for use with color.rgba()
    or arithmetic operations that expect 0-255.
    
    Args:
        component: A single color channel value (R, G, or B), either 0-1 float
                   or 0-255 integer/float.
    Returns:
        Integer in 0-255 range.
    """
    if component > 1.0:
        # Already in 0-255 range (from color.rgb() or color.rgba())
        return int(min(255, max(0, component)))
    else:
        # In 0-1 range (from a named color like color.lime)
        return int(min(255, max(0, component * 255)))


def _c255_color(col):
    """Return (r, g, b) tuple from any Ursina Color, all values normalized to 0-255.
    
    Works correctly regardless of whether the color was created with
    color.rgb()/color.rgba() (0-255 range) or is a named color (0-1 range).
    """
    return (_c255(col[0]), _c255(col[1]), _c255(col[2]))


def _effective_combo_timeout(combo_count):
    """Return the effective combo timeout for the given combo count.

    At low combos (below COMBO_TIMEOUT_SCALING_START), the base COMBO_TIMEOUT
    applies unchanged. Starting at COMBO_TIMEOUT_SCALING_START (x5), each tier
    adds COMBO_TIMEOUT_BONUS_PER_TIER seconds, capped at COMBO_TIMEOUT_BONUS_MAX.
    This makes high combos slightly more forgiving to maintain — the higher
    your streak, the more breathing room to find the next kill.
    """
    if combo_count < COMBO_TIMEOUT_SCALING_START:
        return COMBO_TIMEOUT
    tiers_above = combo_count - COMBO_TIMEOUT_SCALING_START
    bonus = min(COMBO_TIMEOUT_BONUS_MAX, tiers_above * COMBO_TIMEOUT_BONUS_PER_TIER)
    return COMBO_TIMEOUT + bonus


def _set_biome_tinted_glow(player, game):
    """Set the player's ground glow ring to a biome-tinted green color.
    
    The glow ring is normally green (0, 200, 80). This function blends 30% of
    the current biome's color into the green base, so the glow ring subtly
    shifts hue as the player crosses biome boundaries — warm orange on lava,
    cyan on crystal, etc. The blend lerps smoothly between biomes for a
    natural transition. The green base remains dominant (70%) so the signature
    Zorp glow is always recognizable.
    """
    biome_color = BIOME_COLORS.get(game.current_biome, C_GRASS)
    br, bg, bb = _c255_color(biome_color)
    # Target: 70% green base + 30% biome color
    target_r = int(0 * (1 - PLAYER_GLOW_BIOME_BLEND) + br * PLAYER_GLOW_BIOME_BLEND)
    target_g = int(200 * (1 - PLAYER_GLOW_BIOME_BLEND) + bg * PLAYER_GLOW_BIOME_BLEND)
    target_b = int(80 * (1 - PLAYER_GLOW_BIOME_BLEND) + bb * PLAYER_GLOW_BIOME_BLEND)
    # Smoothly lerp the current glow color toward the target biome-tinted color
    if not hasattr(game, '_glow_biome_lerp'):
        game._glow_biome_lerp = (0, 200, 80)
    lerp_alpha = 1.0 - math.exp(-PLAYER_GLOW_BIOME_LERP_SPEED * time.dt)
    cr = lerp(game._glow_biome_lerp[0], target_r, lerp_alpha)
    cg = lerp(game._glow_biome_lerp[1], target_g, lerp_alpha)
    cb = lerp(game._glow_biome_lerp[2], target_b, lerp_alpha)
    game._glow_biome_lerp = (cr, cg, cb)
    player.glow_ring.color = color.rgba(int(cr), int(cg), int(cb), 50)
    player.glow_ring.scale = 2.5

# ─── World Generation ─────────────────────────────────────────────────────────
class WorldGenerator:
    """Procedural terrain generation for a 3D open world."""

    @staticmethod
    def generate(size, seed=None):
        """Generate a 2D grid of biome names for the world.

        Args:
            size: World grid dimensions (tiles per side).
            seed: Optional random seed for reproducibility.

        Returns:
            2D list of biome name strings.
        """
        if seed is not None:
            random.seed(seed)
        grid = [['grass' for _ in range(size)] for _ in range(size)]

        # Place biome blobs
        biomes = ['desert', 'water', 'lava', 'forest', 'crystal', 'snow', 'swamp', 'mushroom', 'floating_islands', 'toxic_bog']
        for _ in range(BIOME_BLOB_COUNT):
            bx = random.randint(0, size - 1)
            by = random.randint(0, size - 1)
            btype = random.choice(biomes)
            radius = random.randint(BIOME_BLOB_RADIUS_MIN, BIOME_BLOB_RADIUS_MAX)
            for dy in range(-radius, radius + 1):
                for dx in range(-radius, radius + 1):
                    nx, ny = bx + dx, by + dy
                    if 0 <= nx < size and 0 <= ny < size:
                        dist = math.sqrt(dx * dx + dy * dy)
                        if dist <= radius + random.uniform(-BIOME_BLOB_JITTER, BIOME_BLOB_JITTER):
                            # Keep spawn area clear
                            spawn = size // 2
                            if abs(nx - spawn) < SPAWN_CLEAR_RADIUS and abs(ny - spawn) < SPAWN_CLEAR_RADIUS:
                                continue
                            grid[ny][nx] = btype

        # Ensure spawn area is grass
        spawn = size // 2
        for dy in range(-SPAWN_PAD_RADIUS, SPAWN_PAD_RADIUS + 1):
            for dx in range(-SPAWN_PAD_RADIUS, SPAWN_PAD_RADIUS + 1):
                grid[spawn + dy][spawn + dx] = 'grass'

        return grid


# ─── Player ───────────────────────────────────────────────────────────────────
class Player(Entity):
    """The player-controlled alien character with HP, XP, and tentacle aesthetics."""

    def __init__(self, position):
        super().__init__(
            model='sphere',
            color=C_ALIEN,
            scale=1.2,
            position=position,
            collider='sphere',
        )
        self.hp = PLAYER_START_HP
        self.max_hp = PLAYER_START_HP
        self.speed = PLAYER_SPEED
        self.score = 0
        self.level = 1
        self.xp = 0
        self.xp_to_next = PLAYER_START_XP
        self.shoot_timer = 0
        self.invuln_timer = 0
        self.inventory = {}
        self.kills = {}
        self.completed_missions = 0
        self.facing = Vec3(0, 0, 1)
        self.level_up_pending = False
        self.milestone_level_pending = False  # Set by gain_xp at milestone levels (5, 10, 15...)
        self.damage_taken_flag = False  # Set by take_damage, checked by game_update for HP bar shake
        self.hp_heal_flag = False       # Set by heal(), checked by game_update for HP bar heal pulse
        self.xp_gained_flag = False      # Set by gain_xp, checked by _update_hud for XP bar flash
        self.flawless_reset_flag = False  # Set by take_damage, checked by game_update to reset flawless streak
        self.vengeful_surge_trigger_flag = False  # BUG FIX: Set by take_damage, checked by game_update for Vengeful Surge — was missing from __init__, causing potential AttributeError if game_update ran before any take_damage() call

        # Dash ability
        self.dash_timer = 0
        self.dash_cooldown = 0
        self.dash_direction = Vec3(0, 0, 0)
        self._dash_strike_hit = set()  # Enemy IDs already hit during the current dash

        # Movement velocity for smooth acceleration/deceleration
        self.velocity = Vec3(0, 0, 0)
        # Dash landing squish — 1.0 = normal, < 1.0 = compressed Y from landing impact
        self.dash_land_squish = 1.0

        # Power-up timers
        self.speed_boost_timer = 0
        self.shield_timer = 0
        self.weapon_upgrade_timer = 0  # Spread shot duration
        self.magnet_timer = 0  # Magnet Core pull boost
        self.float_timer = 0  # Star Fruit float over water/lava
        self.drain_timer = 0   # Cosmic Leech drain DoT timer

        # Monolith buff timers
        self.monolith_speed_timer = 0.0    # Speed buff from monolith
        self.monolith_damage_timer = 0.0   # Damage buff from monolith
        self.monolith_xp_timer = 0.0       # XP multiplier buff from monolith

        # Fireball Scroll timer — projectiles explode on impact
        self.fireball_timer = 0.0

        # Regen Crystal timer — regenerates HP over time
        self.regen_timer = 0.0
        # Move-regen accumulators — trickle HP regen while moving at speed
        self.move_regen_accum = 0.0
        self.move_regen_fx_timer = 0.0

        # Lucky Clover timer — boosts critical hit chance
        self.crit_boost_timer = 0.0

        # Mirror Shard timer — reflects enemy projectiles back at enemies
        self.mirror_timer = 0.0

        # Photon Boots timer — grants continuous dash (resets cooldown each frame)
        self.photon_boots_timer = 0.0

        # Berserk Mode timer — >0 while berserk is active (damage + speed boost)
        self.berserk_timer = 0.0

        # Overheal Barrier — temporary extra HP from excess healing that decays
        # over time. Displayed as a golden HP bar extension and player ring.
        self.overheal = 0               # Current overheal barrier amount
        self.overheal_decay_delay = 0.0 # Time before decay starts (set when overheal is gained)
        self.overheal_absorbed_flag = False  # Set by take_damage when overheal absorbs a hit

        # Adrenaline Rush — triggered when HP drops below ADRENALINE_HP_THRESHOLD.
        # Grants temporary speed + fire rate boost for clutch moments.
        self.adrenaline_timer = 0.0     # >0 while adrenaline is active
        self.adrenaline_cooldown = False  # True after adrenaline ends; resets when HP recovers above threshold

        # ── Vengeful Surge ── When the player takes damage while at a high
        # combo (x5+), a brief speed + fire rate buff activates, rewarding
        # aggressive counterplay. The surge_timer counts down while active;
        # surge_cooldown prevents re-triggering too frequently. The aura
        # visual entity is created lazily on first surge.
        self.vengeful_surge_timer = 0.0    # >0 while surge is active
        self.vengeful_surge_cooldown = 0.0  # Cooldown before surge can trigger again
        self.vengeful_surge_visual = Entity(model='sphere', color=color.rgba(255, 80, 160, 50),
                                             scale=1.6, parent=self, visible=False)

        # Tentacle entities
        self.tentacles = []
        for i in range(4):
            t = Entity(
                model='cube',
                color=color.rgb(0, 200, 80),
                scale=(0.15, 0.15, 1.2),
                parent=self,
            )
            self.tentacles.append(t)

        # Eyes
        self.eye_l = Entity(model='sphere', color=color.white, scale=(0.4, 0.5, 0.4),
                            parent=self, position=(-0.3, 0.4, -0.6))
        self.eye_r = Entity(model='sphere', color=color.white, scale=(0.4, 0.5, 0.4),
                            parent=self, position=(0.3, 0.4, -0.6))
        self.pupil_l = Entity(model='sphere', color=color.black, scale=(0.2, 0.25, 0.2),
                              parent=self.eye_l, position=(0, 0, -0.3))
        self.pupil_r = Entity(model='sphere', color=color.black, scale=(0.2, 0.25, 0.2),
                              parent=self.eye_r, position=(0, 0, -0.3))

        # ── Eye Blink State ── Zorp periodically blinks both eyes (Y-scale
        # squish) for personality. The blink timer counts down to the next
        # blink; while blink_active is True, update_pupils() applies the
        # squish animation. The eye base Y scales are stored so the blink
        # can compose cleanly with the existing pupil-tracking offset.
        self._eye_base_scale_y = 0.5  # Original eye Y scale (from init above)
        self.blink_timer = random.uniform(PLAYER_BLINK_INTERVAL_MIN, PLAYER_BLINK_INTERVAL_MAX)
        self.blink_active = 0.0  # 0 = not blinking, ramps to 1 then back to 0

        # Shield visual (invisible by default)
        self.shield_visual = Entity(model='sphere', color=color.rgba(100, 200, 255, 60),
                                    scale=1.6, parent=self, visible=False)

        # Fireball aura visual (invisible by default)
        self.fireball_visual = Entity(model='sphere', color=color.rgba(255, 80, 20, 50),
                                     scale=1.8, parent=self, visible=False)

        # Regen glow visual (invisible by default)
        self.regen_visual = Entity(model='sphere', color=color.rgba(50, 255, 120, 50),
                                   scale=1.5, parent=self, visible=False)

        # Lucky Clover crit aura visual (invisible by default)
        self.crit_visual = Entity(model='sphere', color=color.rgba(50, 255, 50, 50),
                                  scale=1.4, parent=self, visible=False)

        # Mirror Shard reflective aura visual (invisible by default) — silver ring
        self.mirror_visual = Entity(model='sphere', color=color.rgba(200, 230, 255, 50),
                                    scale=1.7, parent=self, visible=False)

        # Photon Boots aura visual (invisible by default) — cyan-blue energy
        self.photon_boots_visual = Entity(model='sphere', color=color.rgba(100, 220, 255, 50),
                                          scale=1.5, parent=self, visible=False)

        # Berserk Mode aura visual (invisible by default) — red-orange rage
        self.berserk_visual = Entity(model='sphere', color=BERSERK_AURA_COLOR,
                                     scale=BERSERK_AURA_SCALE, parent=self, visible=False)

        # Adrenaline Rush aura visual (invisible by default) — orange-gold
        # fight-or-flight energy sphere on the player model. Complements the
        # existing ground ring and screen vignette with a 3D body-level aura
        # so the adrenaline state is visible from all camera angles.
        self.adrenaline_visual = Entity(model='sphere', color=ADRENALINE_AURA_COLOR,
                                        scale=ADRENALINE_AURA_SCALE, parent=self, visible=False)

        # ── Collection Rush Aura ── A mint-cyan energy sphere on the player
        # model, visible while the Collection Rush speed boost is active.
        # Complements the HUD text and speed boost with a 3D body-level visual
        # so the rush state is visible from all camera angles.
        self.collection_rush_visual = Entity(model='sphere', color=COLLECTION_RUSH_AURA_COLOR,
                                            scale=COLLECTION_RUSH_AURA_SCALE, parent=self, visible=False)

        # Ground shadow beneath player for spatial awareness
        self.ground_shadow = Entity(
            model='quad',
            color=color.rgba(0, 0, 0, 40),
            scale=2.0,
            position=(self.x, 0.05, self.z),
            rotation_x=90,
        )

        # Player glow aura — soft green ring under the player
        self.glow_ring = Entity(
            model='quad',
            color=color.rgba(0, 200, 80, 50),
            scale=2.5,
            position=(self.x, 0.06, self.z),
            rotation_x=90,
        )
        # Player glow point light (faint green)
        # BUG FIX: Removed PointLight — entities use unlit_with_fog_shader by
        # default, so PointLight/DirectionalLight/AmbientLight have NO effect on
        # them. This was a wasted resource (light entity with zero visual impact).
        # The glow_ring quad above already provides the green glow visual.
        self.glow_light = None  # Set to None so _cleanup() hasattr check works

        # Power-up aura ring — pulses with the active buff's color for visual clarity
        self.powerup_ring = Entity(
            model='quad',
            color=color.rgba(0, 200, 80, 0),
            scale=3.0,
            position=(self.x, 0.07, self.z),
            rotation_x=90,
        )

        # Squish/stretch animation state
        self.squish_current = 1.0  # Current Y scale (1.0 = normal)
        self.is_moving = False
        # Previous-frame velocity magnitude — used to detect deceleration-to-stop
        # for the stop squish reaction
        self._prev_speed = 0.0
        # Stop squish timer — decays from 1.0 to 0; while > 0, a gentle squish
        # is applied in animate_bob() for a weighty "landing" feel on stop
        self.stop_squish = 0.0
        # ── Direction-Change Lean ── When the player changes movement direction
        # sharply, Zorp briefly tilts (rolls) into the new direction — a subtle
        # banking/leaning effect that makes directional changes feel more dynamic
        # and alive. The current roll angle lerps back to 0 each frame, and the
        # game_update loop sets a target roll when a sharp direction change is
        # detected. The effect is very subtle (max ~8°) so it adds personality
        # without being disorienting.
        self._prev_move_dir = Vec3(0, 0, 0)  # Previous frame's movement direction
        self._lean_roll = 0.0  # Current roll angle in degrees (lerps toward 0)
        self._lean_target = 0.0  # Target roll angle set on direction change
        # Level-up scale bounce timer — integrates with animate_bob for satisfying pop
        self.level_up_scale_timer = 0.0
        # Damage scale punch — brief squish reaction when the player takes damage,
        # making hits feel visceral (similar to enemy hit_scale_punch)
        self.damage_scale_punch = 0.0
        # Muzzle flash tint timer — when > 0, the per-frame color logic keeps Zorp
        # tinted bright cyan-white (firing reaction) instead of overriding to the
        # normal alien green or low-HP danger pulse. Set by Game.shoot().
        self.muzzle_tint_timer = 0.0

        # Tentacle recoil timer — set by Game.shoot(), decays exponentially.
        # While > 0, update_tentacles() adds a backward whip rotation that
        # springs back to normal, simulating weapon recoil on the character model.
        self.tentacle_recoil_timer = 0.0

        # ── Player Movement Trail ── While running at high speed, a subtle
        # fading afterimage trail appears behind Zorp — thin green ghost copies
        # that fade over a fraction of a second, giving movement a dynamic feel.
        # The trail accumulator counts time between ghost spawns, and the ghosts
        # are managed by the Game class's particle-like system for cleanup.
        self._trail_accumulator = 0.0  # Time since last trail ghost spawn

        # ── Shield Break Detection ── Tracks whether the shield was active
        # last frame so we can detect the natural expiry transition (shield
        # going from active to inactive without absorbing a hit). When the
        # shield expires naturally, a crystal shatter particle effect plays.
        self._shield_was_active = False

        # Combo Shield — earned at combo x15, absorbs one hit without
        # resetting the combo. The shield is a one-time charge that must be
        # re-earned by reaching x15 again after being consumed.
        self.combo_shield_active = False  # True while the shield is charged
        self.combo_shield_absorbed_flag = False  # Set by take_damage, checked by game_update for VFX

        # ── Glow Ring Pickup Pulse ── When the player picks up a collectible,
        # the green ground glow ring briefly flashes in the item's color and
        # expands. Set by game_update on pickup, decays in animate_bob.
        self.glow_pulse_timer = 0.0
        self.glow_pulse_color = None  # (r, g, b) tuple in 0-255 range
        # Pickup scale punch — brief Y stretch + XZ bulge on collectible pickup
        # for tactile "got it!" feedback on the character model itself.
        self.pickup_punch = 0.0  # Decays from 1.0 to 0; while > 0, animate_bob applies the punch
        # Level-up speed burst — brief movement speed surge on level-up for an
        # empowering "surge of energy" feel. Decays over LEVEL_UP_SPEED_BURST_DURATION.
        self.level_up_speed_burst_timer = 0.0

        # ── Last Stand ── One-time per run "cheat death" that triggers when a
        # lethal hit would kill the player while at a high combo (x10+). The
        # hit is absorbed and the player is left at 1 HP with brief
        # invulnerability. A flag signals game_update to trigger the VFX and
        # announcement. last_stand_used prevents re-triggering.
        self.last_stand_used = False        # True once Last Stand has fired this run
        self.last_stand_trigger_flag = False  # Set by take_damage, checked by game_update

    def gain_xp(self, amount):
        """Add XP and level up if threshold reached. Sets level_up_pending flag."""
        self.xp += amount
        self.xp_gained_flag = True  # Signal HUD to flash the XP bar
        while self.xp >= self.xp_to_next:
            self.xp -= self.xp_to_next
            self.level += 1
            self.xp_to_next = int(self.xp_to_next * XP_SCALE_FACTOR)
            self.max_hp += LEVEL_UP_HP_BONUS
            # ── Level-Up Heal Scaling ── The heal is the LARGER of a flat base
            # amount and a percentage of max HP. This keeps level-ups rewarding
            # at all stages: early game the flat 40 HP is generous (33% of 120
            # HP), but late game when max HP is 240+, the 15% percentage heal
            # (36+ HP) takes over so level-ups never feel insignificant.
            heal_amt = max(LEVEL_UP_HEAL_AMOUNT, int(self.max_hp * LEVEL_UP_HEAL_PERCENT))
            # Use heal() so the HP bar heal pulse fires on level-up too
            actual_level_heal = min(heal_amt, self.max_hp - self.hp)
            if actual_level_heal > 0:
                self.heal(actual_level_heal)
            self.speed += LEVEL_UP_SPEED_BONUS
            self.level_up_pending = True
            # ── Milestone Level Cooldown Reset ── At every LEVEL_MILESTONE_INTERVAL
            # levels (5, 10, 15, 20...), set a flag that game_update checks to
            # instantly reset all ability cooldowns and trigger a golden
            # celebration. This makes milestone levels feel like momentous
            # power surges — you get a fresh dash, pulse wave, and vacuum
            # pulse ready to use immediately.
            if self.level % LEVEL_MILESTONE_INTERVAL == 0:
                self.milestone_level_pending = True

    def take_damage(self, amount):
        """Apply damage to the player. Returns True if player died.

        The Overheal Barrier absorbs damage before real HP is reduced —
        excess healing stored as overheal acts as a temporary shield that
        decays over time. This makes overhealed Health Potions valuable in
        combat instead of just being a cap-waste.

        The Combo Shield (earned at combo x15) absorbs one hit entirely
        without reducing HP or resetting the combo — a reward for skillful
        sustained kill chains.

        Args:
            amount: Damage points to subtract from HP.

        Returns:
            True if HP dropped to 0 (player is dead), False otherwise.
        """
        if self.invuln_timer > 0:
            return False
        # ── Combo Shield Absorption ── If the combo shield is active (earned
        # at combo x15), it absorbs the next hit entirely — no HP loss, no
        # invulnerability frames, and critically, the combo is NOT reset.
        # The shield is consumed and must be re-earned. The combo_shield_active
        # flag is checked by the caller (game_update) to spawn a golden burst
        # and prevent combo reset.
        if self.combo_shield_active:
            self.combo_shield_active = False
            self.combo_shield_absorbed_flag = True  # Signal game_update for VFX
            return False
        # ── Overheal Barrier Absorption ── Damage is absorbed by the overheal
        # barrier first, then any remaining damage hits real HP. This gives
        # the player a temporary buffer from excess healing.
        if self.overheal > 0:
            absorbed = min(self.overheal, amount)
            self.overheal -= absorbed
            amount -= absorbed
            # Flag for the game_update to spawn a golden absorption burst so
            # the player can see the barrier is working — without this, the
            # overheal just silently depletes with no visual feedback.
            self.overheal_absorbed_flag = True
            # BUG FIX: If overheal fully absorbed the damage, return early
            # without setting damage-taken flags. Previously, even when amount
            # reached 0, the code fell through and set flawless_reset_flag
            # (resetting the flawless kill streak), damage_taken_flag (shaking
            # the HP bar), invuln_timer, and damage_scale_punch — even though
            # the player took zero real HP damage. This is inconsistent with
            # the Combo Shield handling above, which returns early.
            if amount <= 0:
                return False
        self.hp -= amount
        self.invuln_timer = PLAYER_INVULN_DURATION
        self.damage_taken_flag = True  # Flag for HP bar shake trigger
        # Flawless streak reset flag — game_update checks this to reset the
        # flawless kill streak. Using a flag instead of direct game reference
        # because Player doesn't hold a reference to the Game object.
        self.flawless_reset_flag = True
        # ── Vengeful Surge Trigger Flag ── Set when the player takes real HP
        # damage. The game_update loop checks this flag along with the current
        # combo count to decide whether to trigger the Vengeful Surge buff.
        # Using a flag because Player doesn't hold a Game reference.
        self.vengeful_surge_trigger_flag = True
        # Damage scale punch — trigger a brief squish reaction so the player
        # model visibly reacts to being hit, not just the HP bar
        self.damage_scale_punch = 1.0
        # Flash red
        self.color = color.rgb(255, 100, 100)
        invoke(setattr, self, 'color', C_ALIEN, delay=0.15)
        if self.hp <= 0:
            # ── Last Stand ── If this lethal hit would kill the player while
            # they have a high combo (x10+), absorb the hit and leave them at
            # 1 HP with extended invulnerability. This is a one-time per run
            # safety net that rewards sustained combat streaks — your combo
            # literally keeps you alive. The flag signals game_update to spawn
            # the golden VFX and announcement.
            if (not self.last_stand_used
                    and self.last_stand_trigger_flag is False):
                # We need the game's combo_count — Player doesn't hold a Game
                # reference, so we access the module-level global 'game' which
                # is set at the bottom of this file (game = Game()). This is
                # safe because take_damage is only ever called after Game()
                # initialization, during gameplay.
                _g = globals().get('game', None)
                _combo = getattr(_g, 'combo_count', 0) if _g is not None else 0
                if _combo >= LAST_STAND_COMBO_MIN:
                    self.last_stand_used = True
                    self.last_stand_trigger_flag = True
                    self.hp = LAST_STAND_HP_AFTER
                    self.invuln_timer = LAST_STAND_INVULN_DURATION
                    return False  # survived
            self.hp = 0
            return True  # dead
        return False

    def heal(self, amount):
        """Heal the player by a given amount (capped at max_hp).

        Sets the hp_heal_flag so game_update can trigger the HP bar heal pulse
        — a bright green glow on the HP bar that makes every heal feel
        rewarding and visible at the HUD level. This centralizes healing
        through a single method so the heal pulse fires consistently from
        all heal sources (potions, fragments, regen, level-up, shrines, etc.)
        without each call site needing to set the flag individually.

        Args:
            amount: HP to restore (clamped to max_hp - hp).
        """
        if amount > 0 and self.hp < self.max_hp:
            self.hp = min(self.max_hp, self.hp + amount)
            self.hp_heal_flag = True

    def add_item(self, name, count=1):
        """Add an item to the player's inventory."""
        self.inventory[name] = self.inventory.get(name, 0) + count

    def add_kill(self, name):
        """Record an enemy kill in the player's kill log."""
        self.kills[name] = self.kills.get(name, 0) + 1

    def update_tentacles(self, t):
        """Animate tentacles with a sinusoidal wave pattern.

        When tentacle_recoil_timer is active (set by shoot()), all tentacles
        whip backward and spring back to normal — a physical weapon-recoil
        reaction on the character model that makes each shot feel impactful.
        The recoil is applied as an additive rotation on top of the normal
        wave animation, and decays exponentially for a quick snap-then-recover.
        """
        # Compute recoil offset — decays from max to 0 over TENTACLE_RECOIL_DURATION
        recoil_offset = 0.0
        if self.tentacle_recoil_timer > 0:
            self.tentacle_recoil_timer -= time.dt
            if self.tentacle_recoil_timer < 0:
                self.tentacle_recoil_timer = 0
            recoil_progress = self.tentacle_recoil_timer / TENTACLE_RECOIL_DURATION
            # Exponential decay — strong at start, quick recovery
            recoil_offset = TENTACLE_RECOIL_ANGLE * recoil_progress ** 0.5

        for i, tent in enumerate(self.tentacles):
            angle_offset = (i - 1.5) * 0.5
            wave = math.sin(t * 5 + i * 1.5) * 0.3
            tent.rotation_x = wave * 40 + recoil_offset
            tent.rotation_y = angle_offset * 30 + math.sin(t * 3 + i) * 10

    def update_pupils(self):
        """Make pupils track the mouse/facing direction for personality and feedback.

        Pupils shift slightly in the direction Zorp is facing, giving a lively
        'looking where you aim' feel that connects the player to the character.

        Also handles periodic eye blinking — both eyes squish to ~10% Y scale
        and recover smoothly, giving Zorp personality and making the character
        feel alive. The blink uses a triangle wave (0→1→0) so it closes and
        opens naturally within the blink duration.
        """
        # ── Eye Blink Animation ── Count down to the next blink, then run the
        # blink squish over PLAYER_BLINK_DURATION seconds. The blink uses a
        # triangle wave (0→1→0) mapped to a Y-scale squish from full to ~10%
        # and back, so the eye closes and opens smoothly. Pupils are parented
        # to the eyes, so they squish along automatically.
        self.blink_timer -= time.dt
        if self.blink_timer <= 0 and self.blink_active <= 0:
            # Trigger a new blink
            self.blink_active = PLAYER_BLINK_DURATION
            self.blink_timer = random.uniform(PLAYER_BLINK_INTERVAL_MIN, PLAYER_BLINK_INTERVAL_MAX)
        if self.blink_active > 0:
            self.blink_active -= time.dt
            if self.blink_active < 0:
                self.blink_active = 0
            # Triangle wave: 0 at start/end, 1 at midpoint
            blink_phase = 1.0 - (self.blink_active / PLAYER_BLINK_DURATION)  # 0→1
            blink_intensity = 1.0 - abs(blink_phase * 2 - 1)  # Triangle: 0→1→0
            # Squish eye Y scale from full down to 10% at peak blink
            squish_y = self._eye_base_scale_y * (1.0 - 0.9 * blink_intensity)
            self.eye_l.scale_y = squish_y
            self.eye_r.scale_y = squish_y
        else:
            # Not blinking — ensure eyes are at full Y scale
            self.eye_l.scale_y = self._eye_base_scale_y
            self.eye_r.scale_y = self._eye_base_scale_y

        # ── Dash Eye Squint ── While dashing, squint the eyes to a determined
        # "speed face" — taking the minimum of the current Y scale and the
        # squint value so it composes cleanly with the blink (whichever is
        # more squished wins). This gives Zorp a visible expression change
        # during the dash burst, adding character personality to the ability.
        if self.dash_timer > 0:
            squint_y = self._eye_base_scale_y * PLAYER_DASH_SQUINT_Y
            self.eye_l.scale_y = min(self.eye_l.scale_y, squint_y)
            self.eye_r.scale_y = min(self.eye_r.scale_y, squint_y)

        # Map facing direction to a small pupil offset (max 0.12 units)
        fx, fz = self.facing.x, self.facing.z
        mag = max(0.001, math.sqrt(fx * fx + fz * fz))
        ox = (fx / mag) * 0.12
        oz = (fz / mag) * 0.12
        # BUG FIX: Pupils are parented to the eyes (parent=self.eye_l/r), so
        # .position is LOCAL relative to the eye — NOT relative to the player.
        # The eye's local position is (-0.3, 0.4, -0.6) for eye_l, but the pupil's
        # local position should be (0, 0, -0.3) (set in __init__). Previously the
        # code used the eye's position as the pupil's base, which doubled the
        # offset — placing pupils at (-0.6, 0.8, -1.2) relative to the player
        # instead of (-0.3, 0.4, -0.9), making them float off the eyes entirely.
        self.pupil_l.position = Vec3(0, 0, -0.3) + Vec3(ox * 0.5, 0, oz * 0.5)
        self.pupil_r.position = Vec3(0, 0, -0.3) + Vec3(ox * 0.5, 0, oz * 0.5)

    def animate_bob(self, t):
        """Apply vertical bob and squish/stretch animation to the player.

        Also integrates the level-up scale bounce so it doesn't conflict
        with the normal squish/stretch cycle — the bounce multiplier is
        applied on top of the base squish, creating a satisfying pop effect.
        """
        self.y = 1.2 + math.sin(t * 3) * 0.15
        # Squish/stretch: stretch Y and squish XZ when moving, compress Y and bulge XZ when idle
        if self.is_moving:
            target_squish = PLAYER_STRETCH_FACTOR
        else:
            target_squish = 1.0
        # Frame-rate-independent exponential smoothing — the old
        # lerp(a, b, dt * rate) formula overshot at high framerates (144Hz
        # squish snapped ~1.4x faster than at 60Hz). The exp form is exact
        # at any framerate, matching the fix already applied to camera and
        # movement smoothing throughout the codebase.
        _squish_alpha = 1.0 - math.exp(-PLAYER_SQUISH_SPEED * time.dt)
        self.squish_current += (target_squish - self.squish_current) * _squish_alpha
        # ── Idle Breathing ── When not moving, Zorp gently breathes — a subtle
        # Y scale oscillation that makes the character feel alive rather than
        # frozen between movements. Applied as a small multiplier on top of the
        # normal scale so it composes cleanly with level-up bounce and damage punch.
        breathe_mult = 1.0
        if not self.is_moving:
            breathe_mult = 1.0 + math.sin(t * PLAYER_IDLE_BREATHE_SPEED) * PLAYER_IDLE_BREATHE_AMOUNT
        # Level-up bounce: exponential decay scale multiplier for satisfying pop
        bounce_mult = 1.0
        if self.level_up_scale_timer > 0:
            self.level_up_scale_timer -= time.dt
            progress = 1.0 - max(0, self.level_up_scale_timer) / LEVEL_UP_SCALE_BOUNCE_DURATION
            # Elastic ease-out: starts big, overshoots, then settles to 1.0
            bounce_mult = 1.0 + (LEVEL_UP_SCALE_BOUNCE_FACTOR - 1.0) * math.exp(-5.0 * progress) * math.cos(progress * math.pi * 1.5)
            bounce_mult = max(1.0, bounce_mult)
        y_scale = 1.2 * self.squish_current * bounce_mult * breathe_mult
        xz_scale = 1.0 / self.squish_current  # Inverse for XZ to preserve volume
        # Apply dash landing squish on top of the normal animation.
        # Recovers exponentially so it's a quick pop-then-fade, not a linger.
        self.scale = Vec3(xz_scale, y_scale * self.dash_land_squish, xz_scale)
        if self.dash_land_squish < 1.0:
            # Frame-rate-independent exponential smoothing for consistent recovery
            # speed at any framerate (matching the squish animation fix above).
            _dash_squish_alpha = 1.0 - math.exp(-DASH_LAND_SQUISH_RECOVERY * time.dt)
            self.dash_land_squish += (1.0 - self.dash_land_squish) * _dash_squish_alpha
            if self.dash_land_squish > 0.998:
                self.dash_land_squish = 1.0

        # ── Damage Scale Punch ── When the player takes damage, the model briefly
        # squashes flat (compressed Y, bulged XZ) and recovers elastically — a
        # visceral on-model reaction that complements the HP bar shake and screen
        # shake. Decays exponentially for a quick pop-then-recover feel.
        if self.damage_scale_punch > 0:
            self.damage_scale_punch -= time.dt * PLAYER_DAMAGE_PUNCH_RECOVERY
            if self.damage_scale_punch < 0:
                self.damage_scale_punch = 0
            punch_t = self.damage_scale_punch  # 1.0 → 0.0
            y_compression = 1.0 - PLAYER_DAMAGE_PUNCH_AMOUNT * punch_t
            xz_bulge = 1.0 + PLAYER_DAMAGE_PUNCH_AMOUNT * 0.6 * punch_t
            self.scale = Vec3(xz_scale * xz_bulge, y_scale * self.dash_land_squish * y_compression, xz_scale * xz_bulge)

        # ── Stop Squish ── When the player decelerates from a run to a near-stop,
        # Zorp briefly squishes (compressed Y, bulged XZ) and recovers elastically
        # — a subtle "landing" feel that makes stopping feel weighty and grounded
        # instead of just freezing in place. The squish is triggered in
        # game_update when velocity drops below the threshold from a running speed,
        # and decays here for a quick pop-then-recover. Much gentler than the
        # damage punch and dash landing squish so it composes cleanly with them.
        if self.stop_squish > 0:
            self.stop_squish -= time.dt * PLAYER_STOP_SQUISH_RECOVERY
            if self.stop_squish < 0:
                self.stop_squish = 0
            stop_t = self.stop_squish  # 1.0 → 0.0
            stop_y_comp = 1.0 - PLAYER_STOP_SQUISH_AMOUNT * stop_t
            stop_xz_bulge = 1.0 + PLAYER_STOP_SQUISH_AMOUNT * 0.5 * stop_t
            # Compose with whatever scale was already set (squish or damage punch)
            self.scale = Vec3(
                self.scale_x * stop_xz_bulge,
                self.scale_y * stop_y_comp,
                self.scale_z * stop_xz_bulge,
            )

        # ── Pickup Scale Punch ── When the player collects an item, Zorp briefly
        # stretches upward (Y) and bulges slightly (XZ) — a tactile "yum!" pop
        # that makes pickups feel physically rewarding on the character model,
        # complementing the glow ring pulse and particle burst. The punch uses
        # a sine-based elastic curve (peaks early, settles smoothly) so it feels
        # bouncy rather than linear. Decays quickly so rapid pickups chain into
        # a satisfying sequence of pops. Composes on top of any existing scale.
        if self.pickup_punch > 0:
            self.pickup_punch -= time.dt * PLAYER_PICKUP_PUNCH_RECOVERY
            if self.pickup_punch < 0:
                self.pickup_punch = 0
            # punch_t goes from 1.0 → 0.0; use a sine curve so the pop peaks
            # near the start and settles smoothly (more elastic than linear decay)
            punch_t = self.pickup_punch
            elastic = math.sin(punch_t * math.pi * 0.5)  # 0→1→0 smooth arc
            y_stretch = 1.0 + PLAYER_PICKUP_PUNCH_STRETCH * elastic
            xz_bulge = 1.0 + PLAYER_PICKUP_PUNCH_BULGE * elastic
            self.scale = Vec3(
                self.scale_x * xz_bulge,
                self.scale_y * y_stretch,
                self.scale_z * xz_bulge,
            )

        # ── Direction-Change Lean ── The lean target is set by game_update when
        # the player changes direction sharply. Here we smoothly lerp the actual
        # roll toward the target, then decay the target back to 0 so the lean is
        # a brief impulse that springs back to upright. The roll is applied as a
        # Z-axis rotation on the player model AFTER look_at_2d sets the facing,
        # so it composes as a banking tilt on top of the facing direction.
        # Frame-rate-independent exponential smoothing.
        lean_snap = 1.0 - math.exp(-PLAYER_LEAN_SMOOTH * time.dt)
        self._lean_roll += (self._lean_target - self._lean_roll) * lean_snap
        # Decay the target back to 0 so the lean recovers
        lean_decay = 1.0 - math.exp(-PLAYER_LEAN_RECOVERY * time.dt)
        self._lean_target += (0.0 - self._lean_target) * lean_decay
        # Apply the roll — only when not dashing (dash has its own visual)
        if self.dash_timer <= 0 and abs(self._lean_roll) > 0.01:
            self.rotation_z = self._lean_roll
        else:
            self.rotation_z = 0.0

    def set_facing_from_mouse(self, cam_pivot):
        """Point the alien toward where the mouse ray hits the ground.

        Updates the facing vector instantly for accurate shooting, but
        smoothly interpolates the model rotation toward the aim direction
        for a more organic turning feel.
        """
        hit_info = mouse.world_point
        if hit_info:
            direction = Vec3(hit_info.x - self.x, 0, hit_info.z - self.z)
            if direction.length() > 0.1:
                self.facing = direction.normalized()
                # Smooth rotation toward aim (matching the game_update path)
                target_angle = math.degrees(math.atan2(direction.x, direction.z))
                current = self.rotation_y
                diff = (target_angle - current + 180) % 360 - 180
                max_turn = PLAYER_TURN_SPEED * time.dt
                if abs(diff) < max_turn:
                    self.rotation_y = target_angle
                else:
                    self.rotation_y = current + max_turn * (1 if diff > 0 else -1)


# ─── Enemy ─────────────────────────────────────────────────────────────────────
class Enemy(Entity):
    """An enemy entity that chases the player when in detection range."""

    TYPES = {
        'Slime Blob':      {'color': color.lime,         'hp': 25,  'speed': 3,  'damage': 8,  'scale': 1.0,  'model': 'sphere', 'decor': 'none'},
        'Space Beetle':    {'color': color.brown,         'hp': 45,  'speed': 4.5,'damage': 12, 'scale': 1.2,  'model': 'cube',    'decor': 'wings'},
        'Void Wraith':     {'color': color.violet,        'hp': 70,  'speed': 4,  'damage': 22, 'scale': 1.4,  'model': 'diamond', 'decor': 'aura'},
        'Lava Crawler':    {'color': color.orange,        'hp': 100, 'speed': 5.5,'damage': 28, 'scale': 1.1,  'model': 'cube',    'decor': 'spikes'},
        'Crystal Guardian': {'color': color.cyan,         'hp': 180, 'speed': 2.2,'damage': 38, 'scale': 1.8,  'model': 'diamond', 'decor': 'shards'},
        'Plasma Drake':    {'color': color.magenta,       'hp': 350, 'speed': 6.5,'damage': 45, 'scale': 2.2,  'model': 'diamond', 'decor': 'wings'},
        'Phase Shifter':   {'color': color.rgba(180, 0, 255, 200), 'hp': 60,  'speed': 5,  'damage': 18, 'scale': 1.3,  'model': 'diamond', 'decor': 'aura'},
        'Spore Spitter':   {'color': color.rgb(200, 100, 0),       'hp': 80,  'speed': 3,  'damage': 12, 'scale': 1.4,  'model': 'sphere', 'decor': 'spikes'},
        'Swarm Mite':      {'color': color.rgb(150, 200, 50),      'hp': 12,  'speed': 7,  'damage': 3,  'scale': 0.5,  'model': 'sphere', 'decor': 'none', 'detect': 28},
        'Void Bomber':     {'color': color.rgb(80, 0, 40),        'hp': 50,  'speed': 3.5,'damage': 15, 'scale': 1.1,  'model': 'sphere', 'decor': 'spikes', 'detect': 28},
        'Nebula Phantom':  {'color': color.rgba(100, 150, 255, 150), 'hp': 90,  'speed': 5.5,'damage': 25, 'scale': 1.3,  'model': 'sphere', 'decor': 'aura', 'detect': 38},
        'Starburst Sentinel': {'color': color.rgb(255, 200, 50), 'hp': 60,  'speed': 0, 'damage': 12, 'scale': 1.5,  'model': 'diamond', 'decor': 'shards', 'detect': 28},
        'Cosmic Leech':    {'color': color.rgb(80, 0, 80),          'hp': 30,  'speed': 5.5,'damage': 4,  'scale': 0.7,  'model': 'sphere', 'decor': 'aura', 'detect': 22},
        'Void Stalker':     {'color': color.rgb(40, 40, 60),        'hp': 55,  'speed': 6.5,'damage': 15, 'scale': 1.1,  'model': 'diamond', 'decor': 'aura', 'detect': 32},
        'Plasma Serpent':   {'color': color.rgb(0, 255, 200),       'hp': 120,  'speed': 3.5,'damage': 20, 'scale': 1.0,  'model': 'sphere', 'decor': 'aura', 'detect': 34},
        'Graviton':         {'color': color.rgb(180, 0, 255),       'hp': 75,   'speed': 2.8,'damage': 10, 'scale': 1.5,  'model': 'sphere', 'decor': 'aura', 'detect': 30},
        'Void Wisp':        {'color': color.rgba(100, 255, 200, 160), 'hp': 18,  'speed': 8,  'damage': 5,  'scale': 0.4,  'model': 'sphere', 'decor': 'aura', 'detect': 26},
        'Echo Wraith':      {'color': color.rgb(120, 200, 220),       'hp': 65,  'speed': 4.5,'damage': 16, 'scale': 1.3, 'model': 'diamond', 'decor': 'aura', 'detect': 30},
        'Shard Golem':      {'color': color.rgb(100, 180, 220),      'hp': 160, 'speed': 1.8,'damage': 22, 'scale': 1.6, 'model': 'cube',    'decor': 'shards', 'detect': 26},
    }

    def __init__(self, position, enemy_type=None):
        if enemy_type is None:
            enemy_type = random.choice(list(self.TYPES.keys()))
        info = self.TYPES[enemy_type]
        super().__init__(
            model=info['model'],
            color=info['color'],
            scale=info['scale'],
            position=position,
            collider='sphere',
        )
        self.name = enemy_type
        self.model_name = info['model']  # Store model name for death shatter fragments
        self.hp = info['hp']
        self.max_hp = info['hp']
        self.speed = info['speed']
        self.damage = info['damage']
        self.alive = True
        self.dying = False
        self.death_timer = 0.0
        self.original_scale = info['scale']
        self.original_color = info['color']
        self.attack_cd = 0
        self.detect_range = info.get('detect', ENEMY_DETECT_RANGE)
        self.wander_dir = Vec3(random.uniform(-1, 1), 0, random.uniform(-1, 1)).normalized()
        self.wander_target_dir = Vec3(self.wander_dir)  # Smoothly lerped toward for organic turning
        self.wander_timer = random.uniform(ENEMY_WANDER_INTERVAL_MIN, ENEMY_WANDER_INTERVAL_MAX)
        self.hit_flash = 0
        self.hit_scale_punch = 0.0   # Timer for scale punch animation on hit
        self.hit_flinch = 0.0        # Timer for vertical flinch on hit (decays to 0)
        self._hit_stretch_dir = None  # Direction of the last hit (for directional stretch)
        self.decor_entities = []
        self.knockback_vel = Vec3(0, 0, 0)  # Knockback velocity from being hit
        # ── Smooth Attack Lunge ── When the enemy attacks, it gets a brief
        # forward lunge velocity that decays over time, producing a smooth
        # slide toward the player instead of an instant teleport. The
        # lunge_stretch_dir stores the lunge direction for the directional
        # stretch visual that accompanies the slide.
        self.lunge_vel = Vec3(0, 0, 0)
        self.lunge_stretch_dir = None  # Direction of active lunge for stretch visual
        self.alerted = False                  # Whether enemy has detected the player (for alert flash)
        self.alert_flash_timer = 0.0          # Timer for the detection alert flash
        self.alert_indicator = None           # Billboard "!" Text entity shown on first detection
        self.alert_indicator_timer = 0.0      # How long the alert "!" stays visible
        self.spawn_time = 0.0                  # Set by game_update when spawned — tracks spawn age for grace period
        self._attack_windup_active = False    # True while attack windup telegraph is visually applying

        # ── Pack Aggro Cooldown ── Cooldown before this enemy can chain-aggro
        # nearby idle enemies when it detects the player. Prevents every frame
        # from re-triggering the chain. Set to 0 initially so the first
        # detection can chain immediately.
        self.pack_aggro_cd = 0.0

        # ── Chase Acceleration Ramp ── When the enemy first detects the player,
        # this timer counts down from ENEMY_CHASE_RAMP_DURATION to 0. While > 0,
        # the chase speed multiplier is smoothly interpolated from
        # ENEMY_CHASE_RAMP_START to 1.0, so the enemy "winds up" into the chase
        # instead of snapping from wander speed to full sprint instantly.
        self.chase_ramp_timer = 0.0

        # ── Hit Slow ── When a projectile hits this enemy, there's a chance the
        # laser energy disrupts its locomotion, briefly slowing its movement.
        # The hit_slow_timer counts down while the slow is active; while > 0,
        # the enemy's movement speed is multiplied by ENEMY_HIT_SLOW_MULT.
        # The enemy also gets a brief blue tint so the player can see the slow.
        self.hit_slow_timer = 0.0

        # Type-specific special behaviors
        self.is_phase_shifter = (enemy_type == 'Phase Shifter')
        self.phase_timer = random.uniform(4, 8) if self.is_phase_shifter else 0
        self.is_spore_spitter = (enemy_type == 'Spore Spitter')
        self.spit_timer = random.uniform(2, 4) if self.is_spore_spitter else 0
        # ── Spore Spitter Spit Charge-Up ── Tracks the active charge-up
        # telegraph so we can restore normal scale/color when it ends without
        # firing (e.g., player moved out of range). Set True while the
        # charge-up visual is applying; the spit code resets it on fire or when
        # the player leaves range.
        self._spit_charge_active = False
        self.is_swarm_mite = (enemy_type == 'Swarm Mite')

        # Void Bomber: kamikaze that explodes near player
        self.is_void_bomber = (enemy_type == 'Void Bomber')
        self.fuse_timer = 0
        self.fuse_active = False
        self.pulse_speed = 0
        # ── Void Bomber Warning Ring ── A ground ring showing the explosion
        # radius. Created when the fuse activates and destroyed on explosion.
        self.warning_ring = None
        # ── Enemy Enrage ── When HP drops below ENRAGE_HP_THRESHOLD, the enemy
        # enters a rage state with faster movement and red color shift.
        # enraged flag prevents re-triggering, and enrage_particle_timer
        # controls the periodic red particle emission.
        self.enraged = False
        self.enrage_particle_timer = 0.0

        # ── Near-Death Shudder ── When HP drops below ENEMY_SHUDDER_HP_THRESHOLD
        # (10%), the enemy periodically shudders — a brief rapid X/Z scale
        # jitter signaling it's one hit from death. The shudder_timer counts
        # down to the next burst; while shudder_active > 0, the update loop
        # applies the tremor. Each enemy gets a random initial timer so
        # multiple near-death enemies don't shudder in sync.
        self.shudder_timer = random.uniform(ENEMY_SHUDDER_INTERVAL_MIN, ENEMY_SHUDDER_INTERVAL_MAX)
        self.shudder_active = 0.0  # >0 while a shudder burst is playing

        # ── Per-Enemy Bob Variation ── Each enemy gets a random bob frequency
        # and amplitude so groups of enemies don't breathe in perfect sync.
        # Small/fast enemies bob quicker with smaller amplitude; large/slow
        # enemies bob slower with larger amplitude. This makes the world feel
        # more alive and organic — a pack of Slime Blobs all bobbing at the
        # same frequency looked mechanical; now each has its own rhythm.
        self.bob_freq = random.uniform(ENEMY_BOB_FREQ_MIN, ENEMY_BOB_FREQ_MAX)
        self.bob_amp = random.uniform(ENEMY_BOB_AMP_MIN, ENEMY_BOB_AMP_MAX)
        self.bob_phase = random.uniform(0, math.pi * 2)

        # Nebula Phantom: flying enemy that orbits and dive-attacks
        self.is_nebula_phantom = (enemy_type == 'Nebula Phantom')
        self.orbit_angle = random.uniform(0, math.pi * 2) if self.is_nebula_phantom else 0
        self.orbit_state = 'orbit' if self.is_nebula_phantom else None  # 'orbit' or 'dive'
        self.dive_timer = random.uniform(NEBULA_PHANTOM_DIVE_COOLDOWN_MIN, NEBULA_PHANTOM_DIVE_COOLDOWN_MAX) if self.is_nebula_phantom else 0
        self.dive_target = Vec3(0, 0, 0) if self.is_nebula_phantom else None

        # Starburst Sentinel: stationary turret that fires expanding shockwave rings
        self.is_starburst = (enemy_type == 'Starburst Sentinel')
        self.shockwave_timer = random.uniform(STARBURST_SHOCKWAVE_INTERVAL_MIN, STARBURST_SHOCKWAVE_INTERVAL_MAX) if self.is_starburst else 0

        # Cosmic Leech: fast enemy that applies a drain DoT on contact
        self.is_cosmic_leech = (enemy_type == 'Cosmic Leech')

        # Void Stalker: stealth enemy that cloaks and ambushes
        self.is_void_stalker = (enemy_type == 'Void Stalker')
        self.cloak_state = 'cloaked' if self.is_void_stalker else None  # 'cloaked' or 'decloaked'
        self.cloak_timer = random.uniform(2, VOID_STALKER_CLOAK_SPEED) if self.is_void_stalker else 0
        self.ambush_hit = False  # Whether the first hit from stealth has been delivered

        # Plasma Serpent: segmented snake that splits into mini-enemies on death
        self.is_plasma_serpent = (enemy_type == 'Plasma Serpent')
        self.segment_entities = []  # Visual segment entities (for rendering only)
        self.segment_positions = []  # Position history for segment following
        if self.is_plasma_serpent:
            # Initialize position history for smooth following
            for i in range(PLASMA_SERPENT_SEGMENTS + 1):
                self.segment_positions.append(Vec3(position.x, 1, position.z))
            # Create visual segment entities
            for i in range(PLASMA_SERPENT_SEGMENTS):
                seg_scale = max(0.3, self.original_scale * 0.8 - i * 0.12)
                seg_color_choices = [color.rgb(0, 220, 180), color.rgb(0, 200, 160), color.rgb(0, 180, 140)]
                seg = Entity(
                    model='sphere',
                    color=seg_color_choices[i % len(seg_color_choices)],
                    scale=seg_scale,
                    position=position,
                    collider=None,  # Segments are visual only — no independent collision
                )
                seg_eye_l = Entity(model='sphere', color=color.cyan, scale=0.15, parent=seg, position=(-0.15, 0.15, -0.3))
                seg_eye_r = Entity(model='sphere', color=color.cyan, scale=0.15, parent=seg, position=(0.15, 0.15, -0.3))
                self.segment_entities.append(seg)

        # Graviton: floating enemy that periodically pulls the player toward it
        self.is_graviton = (enemy_type == 'Graviton')
        self.graviton_pull_active = False
        self.graviton_pull_timer = 0.0
        self.graviton_cooldown_timer = random.uniform(GRAVITON_PULL_COOLDOWN_MIN, GRAVITON_PULL_COOLDOWN_MAX)

        # Void Wisp: tiny, fast, semi-transparent enemy that teleports when hit
        self.is_void_wisp = (enemy_type == 'Void Wisp')
        self.wisp_teleport_cooldown = 0.0  # Cooldown between teleport-on-hit
        self.wisp_just_teleported = False  # Flag set by take_damage, read by game_update

        # Echo Wraith: spawns decoy clones to confuse the player
        self.is_echo_wraith = (enemy_type == 'Echo Wraith')
        self.echo_clone_timer = random.uniform(
            ECHO_WRAITH_CLONE_INTERVAL_MIN, ECHO_WRAITH_CLONE_INTERVAL_MAX
        ) if self.is_echo_wraith else 0
        self.echo_clone_entities = []  # Active decoy clone Entity objects

        # Shard Golem: periodically raises a crystal shield that blocks frontal shots
        self.is_shard_golem = (enemy_type == 'Shard Golem')
        self.shield_active = False
        self.shield_cycle_timer = random.uniform(
            SHARD_GOLEM_SHIELD_COOLDOWN * 0.5, SHARD_GOLEM_SHIELD_COOLDOWN
        ) if self.is_shard_golem else 0  # Time until next shield toggle
        self.shield_entity = None  # The shield dome visual (created when shield goes up)
        self._bypass_shield = False  # Set True by dash strikes to bypass the Shard Golem shield
        # Visual indicator ring for gravity pull (hidden by default)
        if self.is_graviton:
            self.pull_ring = Entity(
                model='quad',
                color=color.rgba(180, 0, 255, 0),
                scale=GRAVITON_PULL_RADIUS,
                position=(self.x, 0.1, self.z),
                rotation_x=90,
            )

        # Eyes for all enemies
        eye_y = 0.3 if info['model'] == 'sphere' else 0.4
        self.eye_l = Entity(model='sphere', color=color.red, scale=0.3, parent=self, position=(-0.25, eye_y, -0.5))
        self.eye_r = Entity(model='sphere', color=color.red, scale=0.3, parent=self, position=(0.25, eye_y, -0.5))

        # Type-specific decorations
        decor = info['decor']
        # BUG FIX: Use _c255_color() to normalize color components from mixed
        # color sources. Named colors (color.lime, etc.) store 0-1 floats, but
        # color.rgb()/color.rgba() store 0-255 ints. Blindly multiplying by 255
        # double-scales color.rgb() colors (e.g. 200*255=51000 → washed out).
        if decor == 'wings':
            wr, wg, wb = _c255_color(info['color'])
            wing_l = Entity(model='quad', color=color.rgba(wr, wg, wb, 180),
                            scale=(1.0, 0.5), parent=self, position=(-0.8, 0.2, 0.2), rotation_y=-30)
            wing_r = Entity(model='quad', color=color.rgba(wr, wg, wb, 180),
                            scale=(1.0, 0.5), parent=self, position=(0.8, 0.2, 0.2), rotation_y=30)
            self.decor_entities.extend([wing_l, wing_r])
        elif decor == 'aura':
            ar, ag, ab = _c255_color(info['color'])
            aura = Entity(model='sphere', color=color.rgba(ar, ag, ab, 60),
                          scale=1.5, parent=self)
            self.decor_entities.append(aura)
        elif decor == 'spikes':
            for angle in [0, 72, 144, 216, 288]:
                rad = math.radians(angle)
                spike = Entity(model='cube', color=color.rgb(255, 100, 0),
                               scale=(0.15, 0.6, 0.15), parent=self,
                               position=(math.cos(rad) * 0.5, 0.5, math.sin(rad) * 0.5))
                self.decor_entities.append(spike)
        elif decor == 'shards':
            for angle in [0, 90, 180, 270]:
                rad = math.radians(angle)
                shard = Entity(model='cube', color=color.rgb(0, 255, 255),
                               scale=(0.1, 1.0, 0.1), parent=self,
                               position=(math.cos(rad) * 0.7, 0.7, math.sin(rad) * 0.7))
                self.decor_entities.append(shard)

        # HP bar — scaled to look consistent regardless of enemy size.
        # Since the bar is parented to the enemy (whose scale = original_scale),
        # we divide the base width by the scale so the visual size stays ~2 units
        # wide in world space for all enemies. Tiny Swarm Mites and huge Plasma
        # Drakes both get a readable, same-size HP bar.
        # Clamp to prevent absurd values for very small or very large enemies.
        hp_bar_base_width = 2.0
        hp_bar_base_height = 0.15
        hp_bar_scaled_width = max(0.5, min(4.0, hp_bar_base_width / max(0.3, self.original_scale)))
        hp_bar_scaled_height = max(0.06, min(0.3, hp_bar_base_height / max(0.3, self.original_scale)))
        self.hp_bar_base_width = hp_bar_scaled_width  # Store for update_hp_bar
        self.hp_bar_base_height = hp_bar_scaled_height
        # ── Smooth HP Bar Drain ── The displayed HP smoothly lerps toward the
        # actual HP each frame, so the green HP bar visibly "drains" instead of
        # snapping instantly. This makes each hit feel more impactful — you see
        # the bar shrink in real-time, giving a stronger sense of damage dealt.
        self.displayed_hp = float(self.hp)
        # Position the bar above the enemy, also scaled so it sits at a consistent
        # height above the model regardless of enemy scale
        hp_bar_y = 1.5 / max(0.3, self.original_scale)
        self.hp_bar_bg = Entity(model='quad', color=color.red,
                                scale=(hp_bar_scaled_width, hp_bar_scaled_height),
                                parent=self, position=(0, hp_bar_y, 0), billboard=True)
        self.hp_bar = Entity(model='quad', color=color.green,
                             scale=(hp_bar_scaled_width, hp_bar_scaled_height),
                             parent=self, position=(0, hp_bar_y, -0.01), billboard=True)

        # Ground shadow for spatial awareness — dark disc beneath the enemy
        self.ground_shadow = Entity(
            model='quad',
            color=color.rgba(0, 0, 0, 50),
            scale=self.original_scale * 2.0,
            position=(self.x, 0.05, self.z),
            rotation_x=90,
        )

        # ── Enrage Aura ── A persistent red aura sphere that becomes visible
        # when the enemy enters its enraged state (below 25% HP). This makes
        # enraged enemies instantly identifiable at a glance — you can see
        # which enemies are in their dangerous "cornered" state without needing
        # to check their HP bar. The aura is hidden by default and shown/hidden
        # by the enrage logic in game_update.
        self.enrage_aura = Entity(
            model='sphere',
            color=color.rgba(255, 30, 30, ENRAGE_AURA_ALPHA),
            scale=ENRAGE_AURA_SCALE,
            parent=self,
            visible=False,
        )

        # ── Spawn Grace Shield ── A translucent cyan dome that's visible during
        # the spawn grace period (ENEMY_SPAWN_GRACE_PERIOD) and fades out as
        # the enemy becomes active. This makes it visually clear to the player
        # that the enemy is still "materializing" and not yet a threat — you
        # can distinguish a passive newly-spawned enemy from an active enemy
        # that's just not chasing you yet. The dome is hidden once the grace
        # period ends and the enemy starts normal AI behavior.
        self.grace_shield = Entity(
            model='sphere',
            color=color.rgba(100, 200, 255, ENEMY_SPAWN_GRACE_SHIELD_ALPHA),
            scale=ENEMY_SPAWN_GRACE_SHIELD_SCALE,
            parent=self,
            visible=False,
        )

        # ── Hit Slow Visual Ring ── A ground ring at the enemy's feet that
        # becomes visible while the hit slow is active, giving a persistent
        # visual indicator of the slow state — complementing the brief blue
        # tint with an ongoing ground-level effect that's visible from the
        # third-person camera even after the tint fades. The ring pulses
        # gently in the ice-blue crack color, making it easy to track which
        # enemies are currently slowed during combat.
        self.hit_slow_ring = Entity(
            model='quad',
            color=color.rgba(150, 220, 255, 0),
            scale=self.original_scale * 2.0,
            position=(self.x, 0.04, self.z),
            rotation_x=90,
            visible=False,
        )

    def take_damage(self, amount, hit_direction=None):
        """Apply damage to the enemy. Returns True if killed.

        Args:
            amount: Damage points to subtract from HP.
            hit_direction: Optional direction vector for knockback (from projectile source).
        """
        # BUG FIX: Defensive guard — if take_damage is called on an enemy that's
        # already dying or dead, return False immediately. Without this, a second
        # hit landing in the same frame (e.g. multi-projectile spread, AOE blast)
        # could re-process the death: double XP, double loot, double combo.
        if self.dying or not self.alive:
            return False
        # ── Shard Golem Crystal Shield ── When the shield is active, frontal
        # shots are blocked. The shield blocks damage from projectiles coming
        # from the enemy's front (hit_direction points FROM the projectile source
        # TOWARD the enemy, so if it's roughly aligned with the enemy's facing,
        # it's a frontal hit). Dash strikes pass through the shield (hit_direction
        # is the dash direction, which comes from a different angle, and the
        # dash_strike code path sets hit_direction to the dash direction). We
        # detect dash strikes by checking if hit_direction is roughly perpendicular
        # to the enemy-player line (dash comes from the side, not from the front).
        # SIMPLER APPROACH: The shield blocks all projectile damage when active.
        # Dash strikes bypass the shield because they set a special flag. We
        # use a simple _bypass_shield flag that dash strikes set before calling
        # take_damage. If the shield is active and the hit doesn't bypass it,
        # the damage is absorbed with a visual feedback (spark) but no HP loss.
        if self.is_shard_golem and self.shield_active and not getattr(self, '_bypass_shield', False):
            # Shield absorbed the hit — visual feedback only
            if self.shield_entity and self.shield_entity.enabled:
                # Flash the shield brighter briefly
                self.shield_entity.color = color.rgba(150, 250, 255, 180)
                invoke(setattr, self.shield_entity, 'color', SHARD_GOLEM_SHIELD_COLOR, delay=0.1)
            return False
        # Reset the bypass flag after each hit
        self._bypass_shield = False
        # Void Wisp: chance to teleport away when hit (dodge the damage)
        if self.is_void_wisp and self.wisp_teleport_cooldown <= 0 and self.hp > 0:
            if random.random() < VOID_WISP_TELEPORT_CHANCE:
                # Teleport away — the hit still lands but the wisp blinks to a new position
                self.wisp_teleport_cooldown = VOID_WISP_TELEPORT_COOLDOWN
                self.wisp_just_teleported = True  # Flag for game_update to move the wisp

        self.hp -= amount
        self.hit_flash = ENEMY_HIT_FLASH_DURATION
        self.hit_scale_punch = 1.0  # Trigger scale punch animation
        self.hit_flinch = 1.0       # Trigger vertical flinch pop
        # ── Enemy Hit Directional Stretch ── Store the hit direction (in world
        # space XZ) so the hit scale punch code can stretch the enemy along the
        # shot direction. The direction is normalized and the Y component is
        # zeroed since the stretch is applied in the XZ plane. Stored as None
        # when no direction is provided (e.g., AOE without a direction), in
        # which case the stretch is skipped and only the uniform punch applies.
        if hit_direction and hit_direction.length() > 0.01:
            hd = Vec3(hit_direction.x, 0, hit_direction.z)
            hd_len = hd.length()
            if hd_len > 0.01:
                self._hit_stretch_dir = hd / hd_len
            else:
                self._hit_stretch_dir = None
        else:
            self._hit_stretch_dir = None
        # ── Enemy Hit Flash Tint ── Flash a brightened version of the enemy's
        # own color instead of pure white — hitting a Lava Crawler produces a
        # bright orange flash, hitting a Crystal Guardian produces bright cyan.
        # This makes each impact feel tailored to the target instead of a
        # generic white wash, producing more cohesive and polished feedback.
        # BUG FIX: Use _c255_color() to normalize — original_color may be a
        # named color (0-1 range) or color.rgb() (0-255 range). Arithmetic on
        # 0-1 values produces wrong results (e.g. 0.196*0.85+255*0.15=38.4
        # instead of the correct 170*0.15+255*0.85=242).
        or_, og, ob = _c255_color(self.original_color)
        b = ENEMY_HIT_FLASH_BRIGHTNESS
        flash_col = color.rgb(
            min(255, int(or_ * (1 - b) + 255 * b)),
            min(255, int(og * (1 - b) + 255 * b)),
            min(255, int(ob * (1 - b) + 255 * b)),
        )
        self.color = flash_col
        invoke(setattr, self, 'color', self.original_color, delay=ENEMY_HIT_FLASH_DURATION)
        # Apply knockback if a direction is provided
        if hit_direction and hit_direction.length() > 0.01:
            kb_dir = hit_direction.normalized()
            self.knockback_vel = Vec3(
                kb_dir.x * ENEMY_KNOCKBACK_FORCE,
                ENEMY_KNOCKBACK_UP,
                kb_dir.z * ENEMY_KNOCKBACK_FORCE,
            )
        # ── Hit Slow Chance ── Each projectile hit has a chance to briefly slow
        # the enemy's movement speed, simulating the laser energy disrupting the
        # enemy's locomotion. The slow applies a blue tint so the player can see
        # it's working. This is a per-hit random proc, distinct from Time Warp
        # (which is a global power-up that slows ALL enemies). When the slow
        # triggers, the enemy's movement speed is halved for 1.5 seconds —
        # making fast enemies like Swarm Mites and Void Wisps much easier to
        # hit and kite during the slow window.
        if random.random() < ENEMY_HIT_SLOW_CHANCE:
            self.hit_slow_timer = ENEMY_HIT_SLOW_DURATION
            # BUG FIX: Previously this immediately set self.color = slow_tint,
            # overriding the hit flash color that was just set above. The hit
            # flash (a brightened version of the enemy's own color) was never
            # visible when the slow triggered. Now we schedule the blue slow
            # tint to appear AFTER the hit flash duration ends, so both effects
            # are visible in sequence: hit flash → blue slow tint → original.
            # The slow tint lasts for a brief moment to indicate the slow is
            # active; the speed reduction itself lasts the full duration.
            invoke(setattr, self, 'color', ENEMY_HIT_SLOW_TINT, delay=ENEMY_HIT_FLASH_DURATION)
            invoke(setattr, self, 'color', self.original_color, delay=ENEMY_HIT_FLASH_DURATION + 0.3)
            # ── Hit Slow Crack Particles ── Spawn a burst of ice-blue crack
            # particles around the enemy so the slow proc is immediately
            # visually distinct from a normal hit. The particles burst from
            # the enemy's position in a small radial pattern, making it look
            # like the laser energy "froze" the enemy — you see the crackle
            # of the slow taking effect, not just a color tint. The game
            # reference is accessed via globals() since Enemy doesn't hold a
            # Game reference (same pattern used by Player.take_damage for
            # Last Stand combo check).
            _g = globals().get('game', None)
            if _g is not None:
                _g._spawn_particles(self.position + Vec3(0, 1, 0),
                                    ENEMY_HIT_SLOW_CRACK_COLOR,
                                    count=ENEMY_HIT_SLOW_CRACK_PARTICLES)
        if self.hp <= 0:
            self.alive = False
            self.dying = True
            self.death_timer = DEATH_ANIM_DURATION
            # Hide the enrage aura when the enemy starts dying so it doesn't
            # linger through the death animation
            if hasattr(self, 'enrage_aura') and self.enrage_aura:
                self.enrage_aura.visible = False
            # Hide the hit slow ring when the enemy starts dying so it doesn't
            # linger through the death animation
            if hasattr(self, 'hit_slow_ring') and self.hit_slow_ring is not None:
                self.hit_slow_ring.visible = False
            return True
        return False

    def update_hp_bar(self):
        """Update the HP bar scale and color based on current health ratio.

        Uses a smoothly-interpolated 'displayed_hp' that lerps toward the
        actual HP each frame, so the green HP bar visibly drains instead of
        snapping instantly. This makes each hit feel more impactful — you
        see the bar shrink in real-time, giving a stronger sense of the
        damage dealt.

        When HP drops below ENEMY_LOW_HP_THRESHOLD (25%), the HP bar pulses
        bright red with a subtle scale jitter — a clear "finish them off"
        visual cue that helps players prioritize near-death targets.
        """
        # ── Smooth HP Bar Drain ── Lerp the displayed HP toward actual HP so
        # the bar smoothly shrinks over a few frames instead of snapping. The
        # lerp speed is high enough that the drain is quick (feels responsive)
        # but slow enough that the eye tracks the shrink. Only lerps DOWNWARD
        # (on damage); healing snaps instantly so the bar never appears to
        # lag behind recovery.
        if self.displayed_hp > self.hp:
            # Frame-rate-independent exponential smoothing — the old
            # lerp(a, b, dt * rate) formula overshot at high framerates (144Hz
            # drained ~1.4x faster than at 60Hz). The exp form is exact at
            # any framerate, so the HP bar drain feels identical at 30 or 240 FPS.
            _drain_alpha = 1.0 - math.exp(-ENEMY_HP_BAR_DRAIN_SPEED * time.dt)
            self.displayed_hp = lerp(self.displayed_hp, float(self.hp), _drain_alpha)
            # Clamp to avoid floating-point drift
            if abs(self.displayed_hp - self.hp) < 0.5:
                self.displayed_hp = float(self.hp)
        else:
            self.displayed_hp = float(self.hp)
        # Defensive: guard against division by zero if max_hp is somehow 0
        ratio = max(0, self.displayed_hp / self.max_hp) if self.max_hp > 0 else 0
        # Use the per-enemy scaled base width so the HP bar shrinks correctly
        # regardless of enemy size (set during __init__)
        base_w = getattr(self, 'hp_bar_base_width', 2.0)
        base_h = getattr(self, 'hp_bar_base_height', 0.15)
        self.hp_bar.scale_x = base_w * ratio
        self.hp_bar.x = -(base_w / 2) * (1 - ratio)
        # Color gradient: green → yellow → red
        if ratio > 0.5:
            t = (ratio - 0.5) * 2  # 1.0 at full, 0.0 at half
            self.hp_bar.color = color.rgb(int(255 * (1 - t)), 255, 0)
        else:
            t = ratio * 2  # 1.0 at half, 0.0 at empty
            self.hp_bar.color = color.rgb(255, int(255 * t), 0)
        # ── Low-HP Warning Pulse ── When the enemy's HP drops below 25%, the HP
        # bar pulses bright red with a subtle scale jitter. This creates a clear
        # visual "finish them off" cue — you can instantly see which enemies
        # are about to die, making it easier to prioritize targets and adding
        # urgency to the final blow. The pulse uses game time (t) via id() for
        # phase variation so multiple low-HP enemies don't pulse in sync.
        if ratio < ENEMY_LOW_HP_THRESHOLD and ratio > 0:
            pulse = 0.5 + 0.5 * math.sin(
                time.t * ENEMY_LOW_HP_PULSE_SPEED + (id(self) % 628) / 100.0
            )
            # Bright red pulse color (overrides the normal gradient)
            self.hp_bar.color = color.rgb(255, int(30 * (1 - pulse)), int(30 * (1 - pulse)))
            # Subtle scale jitter — bar appears to "throb"
            scale_jitter = 1.0 + ENEMY_LOW_HP_BAR_SCALE_PULSE * pulse
            self.hp_bar.scale_y = base_h * scale_jitter
            self.hp_bar_bg.scale_y = base_h * scale_jitter
        else:
            # Reset to normal bar height when not in low-HP state
            self.hp_bar.scale_y = base_h
            self.hp_bar_bg.scale_y = base_h

    def update_death_animation(self, dt):
        """Animate enemy death: pop upward, shrink, flash between white and enemy color,
        then dissolve with a fade. Returns True when the animation is complete.

        The animation has three phases:
        1. Pop (0–25%): enemy bounces upward dramatically
        2. Flash & shrink (25–70%): alternates white/original color while shrinking
        3. Dissolve (70–100%): fades to transparent with enemy's tinted color

        The enemy also spins during the death animation — a randomized rotation
        that accelerates as it shrinks, making kills feel more dynamic and
        chaotic instead of the enemy just shrinking in place. The spin direction
        is random per enemy so group kills don't look synchronized.
        """
        if not self.dying:
            return True
        self.death_timer -= dt
        progress = 1.0 - (self.death_timer / DEATH_ANIM_DURATION)
        # Pop upward at start, then fall — bigger initial pop for impact
        if progress < 0.25:
            pop_height = math.sin(progress / 0.25 * math.pi) * 2.0
        else:
            pop_height = max(0, 2.0 * (1.0 - (progress - 0.25) / 0.75))
        self.y = 1 + pop_height
        # ── Death Burst Scale Pop ── In the first 10% of the death animation,
        # the enemy briefly INFLATES beyond its original scale before shrinking.
        # This creates a "burst" visual — like the enemy is exploding outward from
        # the killing blow — that makes kills feel far more punchy and impactful
        # than a pure shrink. The inflation uses a sine curve peaking at 1.25x
        # original scale at progress=0.05, then blends smoothly into the normal
        # shrink curve by progress=0.10. Bigger enemies burst proportionally
        # larger so the effect is visible across all enemy types.
        if progress < 0.10:
            burst_t = progress / 0.10  # 0→1 over the burst phase
            burst_mult = 1.0 + 0.25 * math.sin(burst_t * math.pi)  # peaks at 1.25x
            self.scale = self.original_scale * burst_mult
        else:
            # Shrink with easing (fast start, slow end)
            ease_progress = 1.0 - (1.0 - progress) ** 2
            shrink = max(0.01, self.original_scale * (1.0 - ease_progress))
            self.scale = shrink
        # ── Death Spin ── The enemy spins during death, accelerating as it
        # shrinks. The spin direction is randomized per enemy so multiple
        # simultaneous deaths (AOE kills, Pulse Wave) don't look synchronized.
        # Spin speed ramps from a gentle start to a fast twirl as the enemy
        # dissolves, making the death feel chaotic and dynamic.
        if not hasattr(self, '_death_spin_dir'):
            self._death_spin_dir = random.choice([-1, 1])
        spin_speed = 180 + 420 * progress  # 180°/s at start → 600°/s at end
        self.rotation_y += self._death_spin_dir * spin_speed * dt
        # ── Death Tilt Wobble ── Add a wobbling tilt on the X and Z axes so the
        # enemy appears to tumble chaotically rather than spinning flat. The tilt
        # amplitude scales with progress (starts gentle, peaks mid-death, fades
        # at the very end as the enemy dissolves). Uses a sine wobble with a
        # per-enemy random phase offset so group kills don't wobble in sync.
        tilt_amp = DEATH_TILT_MAX * math.sin(progress * math.pi)  # 0→max→0 over lifetime
        wobble_phase = (id(self) % 628) / 100.0
        self.rotation_x = tilt_amp * math.sin(time.t * DEATH_TILT_WOBBLE_SPEED + wobble_phase)
        self.rotation_z = tilt_amp * math.cos(time.t * DEATH_TILT_WOBBLE_SPEED + wobble_phase * 1.3)
        # Flash between white and original color, dissolving at end
        # BUG FIX: Use _c255_color() to normalize — original_color may be a named
        # color (0-1 range) or color.rgb() (0-255 range). Arithmetic on 0-1 values
        # produces wrong results (e.g. 1.0*1.3+60=61 instead of 255*1.3+60=391).
        if progress < 0.7:
            if int(self.death_timer * 15) % 2 == 0:
                self.color = color.white
            else:
                # Use a brightened version of original color for more vivid flashing
                or_, og, ob = _c255_color(self.original_color)
                self.color = color.rgb(
                    min(255, int(or_ * 1.3) + 60),
                    min(255, int(og * 1.3) + 60),
                    min(255, int(ob * 1.3) + 60),
                )
        else:
            # Dissolve to faded color with a warm glow
            fade = max(0, 1.0 - (progress - 0.7) / 0.3)
            or_, og, ob = _c255_color(self.original_color)
            self.color = color.rgba(
                min(255, int(or_ * fade) + int(40 * fade)),
                min(255, int(og * fade) + int(20 * fade)),
                min(255, int(ob * fade) + int(10 * fade)),
                int(255 * fade),
            )
        # ── HP Bar Death Fade-Out ── Instead of instantly hiding the HP bar when
        # the enemy starts dying, fade it out smoothly over the first 30% of the
        # death animation. This is more polished than a hard cut — the bar shrinks
        # and becomes transparent in sync with the enemy's death dissolve, so the
        # UI elements don't pop out of existence while the enemy is still visible.
        death_fade = max(0.0, 1.0 - (progress / 0.3))  # 1.0→0.0 over first 30%
        if death_fade <= 0:
            self.hp_bar_bg.visible = False
            self.hp_bar.visible = False
        else:
            # Shrink the bar toward zero width and fade alpha
            bar_alpha = int(220 * death_fade)
            self.hp_bar_bg.color = color.rgba(80, 0, 0, bar_alpha)
            self.hp_bar.color = color.rgba(255, 255, 0, bar_alpha)
            self.hp_bar.scale_x = self.hp_bar_base_width * death_fade
            self.hp_bar.x = -(self.hp_bar_base_width / 2) * (1.0 - death_fade)
        return self.death_timer <= 0


# ─── Collectible ───────────────────────────────────────────────────────────────

def _weighted_random_collectible():
    """Pick a random collectible type using weighted probabilities.

    Common items like Space Gloop appear more often, while rare items
    like Plasma Core and Cosmic Jelly appear infrequently. This makes
    exploration more rewarding and power-ups a pleasant surprise.
    """
    names = list(COLLECTIBLE_WEIGHTS.keys())
    weights = list(COLLECTIBLE_WEIGHTS.values())
    return random.choices(names, weights=weights, k=1)[0]


class Collectible(Entity):
    """A collectible item that bobs and spins in the world."""

    ITEMS = {
        'Space Gloop':    {'color': C_PURPLE, 'value': 10,  'model': 'sphere'},
        'Meteor Shard':   {'color': color.orange, 'value': 25,  'model': 'diamond'},
        'Quantum Fuzz':   {'color': color.cyan,   'value': 50,  'model': 'sphere'},
        'Nebula Dust':    {'color': C_PINK,       'value': 100, 'model': 'diamond'},
        'Cosmic Jelly':   {'color': C_GOLD,       'value': 200, 'model': 'diamond'},
        'Plasma Core':    {'color': color.magenta, 'value': 350, 'model': 'diamond'},
        'Health Potion':  {'color': color.rgb(255, 50, 50),  'value': 15,  'model': 'sphere'},
        'Speed Boost':    {'color': color.rgb(50, 255, 50),  'value': 15,  'model': 'diamond'},
        'Shield Crystal': {'color': color.rgb(100, 200, 255),'value': 15,  'model': 'diamond'},
        'Weapon Upgrade': {'color': color.rgb(255, 150, 0),  'value': 20,  'model': 'diamond'},
        'Magnet Core':    {'color': color.rgb(200, 50, 255),'value': 20,  'model': 'sphere'},
        'Time Warp':      {'color': color.rgb(150, 220, 255),'value': 25,  'model': 'diamond'},
        'Star Fruit':     {'color': color.rgb(255, 255, 100), 'value': 20,  'model': 'diamond'},
        'XP Orb':         {'color': color.rgb(100, 200, 255), 'value': 25,  'model': 'sphere'},
        'Fireball Scroll': {'color': color.rgb(255, 80, 20),  'value': 25,  'model': 'diamond'},
        'Regen Crystal':  {'color': color.rgb(50, 255, 120),  'value': 20,  'model': 'diamond'},
        'Lucky Clover':   {'color': color.rgb(50, 255, 50),   'value': 20,  'model': 'diamond'},
        'Mirror Shard':   {'color': color.rgb(200, 230, 255), 'value': 25, 'model': 'diamond'},
        'Photon Boots':   {'color': color.rgb(100, 220, 255), 'value': 25, 'model': 'diamond'},
        'Combo Orb':      {'color': color.rgb(255, 200, 60), 'value': 300, 'model': 'diamond'},
    }

    def __init__(self, position, item_type=None):
        if item_type is None:
            item_type = _weighted_random_collectible()
        info = self.ITEMS[item_type]
        super().__init__(
            model=info['model'],
            color=info['color'],
            scale=0.6,
            position=position,
            collider='sphere',
        )
        self.name = item_type
        self.value = info['value']
        self.bob_offset = random.uniform(0, math.pi * 2)
        self.item_color = info['color']
        self.popping = False
        self.pop_timer = 0.0
        # Spawn animation: collectibles scale up from 0 over COLLECT_SPAWN_DURATION seconds
        # for a polished fade-in instead of popping into existence
        self.spawn_timer = COLLECT_SPAWN_DURATION
        # Rarity-based glow configuration
        self.rarity = RARITY_TIER.get(item_type, 'common')
        glow_cfg = RARITY_GLOW_CONFIG.get(self.rarity, RARITY_GLOW_CONFIG['common'])
        self.glow_pulse_speed = glow_cfg['pulse_speed']
        self.glow_min_scale = glow_cfg['min_scale']
        self.glow_max_scale = glow_cfg['max_scale']
        # Rarity-based bob amplitude and spin speed — rarer items bob higher
        # and spin faster, making them visually distinct and more enticing.
        self.bob_amplitude = RARITY_BOB_AMPLITUDE.get(self.rarity, 0.4)
        self.spin_speed = RARITY_SPIN_SPEED.get(self.rarity, 60)
        # Glow ring — alpha scales with rarity
        # BUG FIX: Use _c255_color() to normalize — info['color'] may be a named
        # color (0-1 range, e.g. color.orange) or color.rgb() (0-255 range).
        # Using .r/.g/.b directly mixes the two systems and produces wrong colors
        # for items like Meteor Shard (color.orange) and Plasma Core (color.magenta).
        glow_alpha = glow_cfg['glow_alpha']
        gr, gg, gb = _c255_color(info['color'])
        self.glow = Entity(model='quad', color=color.rgba(gr, gg, gb, glow_alpha),
                           scale=glow_cfg['min_scale'], parent=self, rotation_x=90, position=(0, -0.3, 0))
        # Spawn animation: start tiny and invisible, scale up over COLLECT_SPAWN_DURATION
        self.scale = 0.01
        self.glow.visible = False
        # Sparkle trail timer — rare+ collectibles emit occasional sparkle particles
        self.sparkle_timer = random.uniform(0, SPARKLE_INTERVAL)
        # Spawn-finished flag — set True for one frame when the spawn animation
        # completes, so the game loop can emit a spawn sparkle burst
        self.spawn_just_finished = False
        # Pull trail timer — tracks time between trail dot spawns while the
        # collectible is being magnetically pulled toward the player
        self.pull_trail_timer = 0.0
        # Beacon pulse timer — periodically emits a larger, brighter glow
        # expansion so the item is easier to spot from far away. Each item
        # gets a random initial timer so beacons don't all fire in sync.
        self.beacon_timer = random.uniform(COLLECT_BEACON_INTERVAL_MIN, COLLECT_BEACON_INTERVAL_MAX)
        self.beacon_active = 0.0  # >0 while the beacon expansion is playing
        # ── Loot Burst Velocity ── When set (by _drop_loot), the collectible
        # flies outward from the kill point during its spawn animation. The
        # velocity decays exponentially and is applied in animate() during the
        # spawn phase, so loot visibly scatters before settling into normal
        # bob/spin. Set to Vec3(0,0,0) for normal world-spawned collectibles.
        self.burst_vel = Vec3(0, 0, 0)
        self.burst_active = False  # True while burst velocity is still decaying

    def animate(self, t):
        """Bob, spin, and pulse glow on the collectible each frame."""
        # ── Loot Burst Velocity ── Apply outward burst velocity from the
        # kill point. The velocity decays exponentially and only applies while
        # burst_active is True. The position is moved in the XZ plane (plus a
        # small upward arc that gravity pulls back down), making loot fly
        # outward from the corpse before settling into normal bob/spin.
        if self.burst_active:
            self.x += self.burst_vel.x * time.dt
            self.z += self.burst_vel.z * time.dt
            # Upward arc — apply Y velocity then apply gravity to bring it back down
            self.y += self.burst_vel.y * time.dt
            self.burst_vel.y -= 15.0 * time.dt  # Gravity pulls the arc back down
            # Exponential decay of horizontal velocity
            decay_alpha = 1.0 - math.exp(-LOOT_BURST_DECAY * time.dt)
            self.burst_vel.x = lerp(self.burst_vel.x, 0, decay_alpha)
            self.burst_vel.z = lerp(self.burst_vel.z, 0, decay_alpha)
            # Floor the Y so loot doesn't go below ground level
            if self.y < 0.5:
                self.y = 0.5
                self.burst_vel.y = 0
            # Stop the burst when velocity is negligible
            if abs(self.burst_vel.x) < 0.5 and abs(self.burst_vel.z) < 0.5 and abs(self.burst_vel.y) < 0.5:
                self.burst_active = False
                self.burst_vel = Vec3(0, 0, 0)
                self.y = 1.0  # Reset to normal bob height
        # Spawn animation: scale up from tiny to full size with an elastic overshoot
        if self.spawn_timer > 0:
            self.spawn_timer -= time.dt
            progress = 1.0 - max(0, self.spawn_timer / COLLECT_SPAWN_DURATION)
            # Elastic ease-out: overshoot then settle
            if progress < 0.6:
                # Scale up rapidly
                self.scale = 0.01 + 0.59 * (progress / 0.6) ** 0.5
            else:
                # Overshoot: scale past 0.6 then settle back
                overshoot = (progress - 0.6) / 0.4  # 0 to 1
                self.scale = 0.6 + 0.15 * math.sin(overshoot * math.pi)  # peaks at ~0.75
            # Show glow once mostly visible
            if progress > 0.3 and not self.glow.visible:
                self.glow.visible = True
            return
        elif self.spawn_timer > -0.01:
            # Just finished spawning — snap to normal scale
            self.scale = 0.6
            self.glow.visible = True
            self.spawn_timer = -1  # Mark as done
            self.spawn_just_finished = True  # Signal game loop to emit spawn sparkle
        if not self.burst_active:
            self.y = 1.0 + math.sin(t * 2 + self.bob_offset) * self.bob_amplitude
        self.rotation_y += self.spin_speed * time.dt
        # Rarity-scaled glow pulse — faster pulse and wider range for rarer items
        pulse = self.glow_min_scale + (self.glow_max_scale - self.glow_min_scale) * (0.5 + 0.5 * math.sin(t * self.glow_pulse_speed + self.bob_offset))
        self.glow.scale = pulse
        # ── Beacon Pulse ── Periodically emit a larger, brighter glow expansion
        # so the item is easier to spot from far away. The beacon fires at random
        # intervals (4-8s) and expands the glow ring well beyond its normal range
        # over 0.6 seconds, then settles back. The expansion uses a sine-based
        # ease-out curve so it bursts outward quickly and settles smoothly.
        self.beacon_timer -= time.dt
        if self.beacon_timer <= 0 and self.beacon_active <= 0:
            self.beacon_active = COLLECT_BEACON_DURATION
            self.beacon_timer = random.uniform(COLLECT_BEACON_INTERVAL_MIN, COLLECT_BEACON_INTERVAL_MAX)
        if self.beacon_active > 0:
            self.beacon_active -= time.dt
            if self.beacon_active < 0:
                self.beacon_active = 0
            beacon_phase = 1.0 - (self.beacon_active / COLLECT_BEACON_DURATION)  # 0→1
            # Ease-out: burst outward fast, settle slowly (1 - (1-t)^2)
            beacon_t = 1.0 - (1.0 - beacon_phase) ** 2
            beacon_scale = self.glow_max_scale + (self.glow_max_scale * COLLECT_BEACON_SCALE_MULT - self.glow_max_scale) * beacon_t
            # Take the max of the normal pulse and the beacon so the beacon
            # always overrides (never shrinks the glow below the normal pulse)
            self.glow.scale = max(pulse, beacon_scale)
            # Brighten the glow alpha during the beacon peak
            beacon_intensity = 1.0 - abs(beacon_phase * 2 - 1)  # Triangle: 0→1→0
            glow_cfg = RARITY_GLOW_CONFIG.get(self.rarity, RARITY_GLOW_CONFIG['common'])
            base_alpha = glow_cfg['glow_alpha']
            beacon_alpha = min(255, int(base_alpha * (1.0 + (COLLECT_BEACON_ALPHA_MULT - 1.0) * beacon_intensity)))
            ir, ig, ib = _c255_color(self.item_color)
            self.glow.color = color.rgba(ir, ig, ib, beacon_alpha)
        else:
            # BUG FIX: Restore glow color to its base alpha when the beacon is
            # not active. Without this, the glow stays stuck at the beacon's
            # boosted alpha after the beacon expires, making items glow far
            # brighter than intended between beacon pulses.
            glow_cfg_base = RARITY_GLOW_CONFIG.get(self.rarity, RARITY_GLOW_CONFIG['common'])
            ir, ig, ib = _c255_color(self.item_color)
            self.glow.color = color.rgba(ir, ig, ib, glow_cfg_base['glow_alpha'])


# ─── Health Fragment ─────────────────────────────────────────────────────
class HealthFragment(Entity):
    """A small green orb dropped by enemies on death that heals the player on pickup.

    Bobs and spins above the ground with a subtle glow ring. Heals the player
    for a scaled amount based on the enemy's max HP. Despawns after a lifetime
    with a fade-out. Uses the existing collectible pickup radius check, so it
    integrates with the magnetic pull and vacuum pulse systems naturally.
    """

    def __init__(self, position, heal_amount):
        super().__init__(
            model='sphere',
            color=color.rgb(*HEALTH_FRAGMENT_COLOR),
            scale=HEALTH_FRAGMENT_RADIUS,
            position=position + Vec3(0, HEALTH_FRAGMENT_BOB_HEIGHT, 0),
        )
        self.heal_amount = heal_amount
        self.lifetime = HEALTH_FRAGMENT_LIFETIME
        self.spawn_time = 0.0
        self._base_y = position.y + HEALTH_FRAGMENT_BOB_HEIGHT
        self._glow_ring = Entity(
            model='quad',
            color=color.rgba(*HEALTH_FRAGMENT_COLOR, HEALTH_FRAGMENT_GLOW_ALPHA),
            scale=HEALTH_FRAGMENT_GLOW_RADIUS,
            position=Vec3(position.x, 0.04, position.z),
            rotation_x=90,
        )
        self._collected = False

    def update(self):
        self.spawn_time += time.dt
        self.lifetime -= time.dt

        # Bob up and down
        self.y = self._base_y + math.sin(self.spawn_time * HEALTH_FRAGMENT_BOB_SPEED) * 0.15
        # Spin
        self.rotation_y += HEALTH_FRAGMENT_SPIN_SPEED * time.dt

        # Glow ring pulse
        glow_pulse = 0.5 + 0.5 * math.sin(self.spawn_time * 4.0)
        glow_scale = HEALTH_FRAGMENT_GLOW_RADIUS * (0.85 + 0.15 * glow_pulse)
        if self._glow_ring is not None and self._glow_ring.enabled:
            self._glow_ring.scale = (glow_scale, 1, glow_scale)
            # Fade glow as lifetime runs out
            remaining_ratio = max(0, self.lifetime / HEALTH_FRAGMENT_DESPAWN_FADE) if self.lifetime < HEALTH_FRAGMENT_DESPAWN_FADE else 1.0
            self._glow_ring.color = color.rgba(
                HEALTH_FRAGMENT_COLOR[0], HEALTH_FRAGMENT_COLOR[1],
                HEALTH_FRAGMENT_COLOR[2], int(HEALTH_FRAGMENT_GLOW_ALPHA * remaining_ratio)
            )

        # Despawn with fade
        if self.lifetime < HEALTH_FRAGMENT_DESPAWN_FADE:
            fade_ratio = max(0, self.lifetime / HEALTH_FRAGMENT_DESPAWN_FADE)
            r, g, b = HEALTH_FRAGMENT_COLOR
            self.color = color.rgba(r, g, b, int(255 * fade_ratio))
            if self._glow_ring is not None and self._glow_ring.enabled:
                self._glow_ring.color = color.rgba(r, g, b, int(HEALTH_FRAGMENT_GLOW_ALPHA * fade_ratio))

        if self.lifetime <= 0:
            if self._glow_ring is not None:
                destroy(self._glow_ring)
            destroy(self)
            return

        # Player pickup check — integrate with the game's player reference
        p = game.player
        if p is not None and not self._collected:
            dx = p.x - self.x
            dz = p.z - self.z
            if dx * dx + dz * dz < HEALTH_FRAGMENT_PICKUP_RADIUS * HEALTH_FRAGMENT_PICKUP_RADIUS:
                # Only collect if the player actually needs healing
                if p.hp < p.max_hp:
                    self._collected = True
                    actual_heal = self.heal_amount
                    p.heal(actual_heal)
                    game.add_message(f"+{actual_heal} HP (Fragment)")
                    game._spawn_particles(p.position + Vec3(0, 1, 0),
                                          color.rgb(*HEALTH_FRAGMENT_COLOR), count=4)
                    # Heal pulse ring
                    game.heal_pulse_rings.append(HealPulseRing(position=Vec3(p.x, 0, p.z)))
                    if self._glow_ring is not None:
                        destroy(self._glow_ring)
                    destroy(self)


# ─── Pulse Wave Ring ─────────────────────────────────────────────────────
class PulseWaveRing(Entity):
    """An expanding teal shockwave ring emitted by the player's Pulse Wave ability.

    The ring expands outward, pushing enemies away and dealing minor damage.
    It fades as it expands, then disappears when it reaches max radius.
    """

    def __init__(self, position, base_color=(0, 255, 200), max_scale=None,
                 start_alpha=200, is_shockwave=False):
        """Initialize the pulse wave ring.

        Args:
            position: World position for the ring center.
            base_color: (r, g, b) tuple in 0-255 range for the ring's color.
                        Defaults to teal (0, 255, 200) for the Pulse Wave ability.
                        Pass gold (255, 220, 80) for the Vacuum Pulse ability.
            max_scale: Maximum scale before the ring expires. Defaults to
                       PULSE_WAVE_RING_MAX_SCALE. Override for larger rings
                       (e.g. level-up shockwave uses LEVEL_UP_SHOCKWAVE_RING_MAX_SCALE).
            start_alpha: Starting alpha for the ring (0-255). Defaults to 200.
            is_shockwave: If True, this ring is a visual-only shockwave (e.g.
                          level-up knockback) and will NOT deal damage in the
                          pulse wave enemy interaction loop. The knockback is
                          applied separately at spawn time.
        """
        super().__init__(
            model='quad',
            color=color.rgba(base_color[0], base_color[1], base_color[2], start_alpha),
            scale=PULSE_WAVE_RING_START_SCALE,
            position=position + Vec3(0, 0.15, 0),
            rotation_x=90,
        )
        self.lifetime = PULSE_WAVE_RING_LIFETIME
        self.max_lifetime = PULSE_WAVE_RING_LIFETIME
        self.current_radius = PULSE_WAVE_RING_START_SCALE
        self.hit_enemies = set()  # Track which enemies were already hit
        # BUG FIX: Store the base color so update_ring() can fade alpha without
        # overriding the ring's intended color. Previously update_ring() hardcoded
        # teal, which meant Vacuum Pulse rings (set to gold after construction)
        # were immediately overwritten back to teal on the next update frame.
        self._base_r, self._base_g, self._base_b = base_color
        # BUG FIX: Allow custom max_scale so rings like the level-up shockwave
        # can expand beyond PULSE_WAVE_RING_MAX_SCALE without being destroyed early.
        self._max_scale = max_scale if max_scale is not None else PULSE_WAVE_RING_MAX_SCALE
        self._start_alpha = start_alpha
        # BUG FIX: is_shockwave flag prevents the pulse wave enemy interaction
        # loop from dealing damage to enemies hit by this ring. Level-up
        # shockwave rings are knockback-only (no damage), but were previously
        # processed by the pulse wave damage loop because they share the same
        # game.pulse_wave_rings list.
        self.is_shockwave = is_shockwave

    def update_ring(self, dt):
        """Expand the ring. Returns True when expired."""
        self.current_radius += PULSE_WAVE_EXPAND_SPEED * dt
        self.scale = self.current_radius
        self.lifetime -= dt
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        alpha = max(0, int(self._start_alpha * (1.0 - progress)))
        # BUG FIX: Use the stored base color instead of hardcoded teal. This
        # allows vacuum pulse rings to appear gold (their intended color)
        # instead of being overridden to teal every frame.
        self.color = color.rgba(self._base_r, self._base_g, self._base_b, alpha)
        return self.lifetime <= 0 or self.current_radius >= self._max_scale


# ─── Spawn Warning Ring ─────────────────────────────────────────────────────
class SpawnWarningRing(Entity):
    """A pulsing red ring that appears at an enemy spawn location before the
    enemy materializes, giving the player time to react.

    The ring shrinks and intensifies in brightness as the countdown approaches
    zero, then disappears when the enemy spawns.
    """

    def __init__(self, position):
        super().__init__(
            model='quad',
            color=color.rgba(255, 60, 60, 0),
            scale=3.0,
            position=position + Vec3(0, 0.12, 0),
            rotation_x=90,
        )
        self.lifetime = SPAWN_WARNING_DURATION
        self.max_lifetime = SPAWN_WARNING_DURATION
        self.start_scale = 3.0
        self.end_scale = 1.0

    def update_warning(self, dt):
        """Animate the warning ring. Returns True when expired."""
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Shrink from start_scale to end_scale as the warning counts down
        current_scale = self.start_scale + (self.end_scale - self.start_scale) * progress
        # ── Urgency Wobble ── In the final 30% of the countdown, the ring
        # gains a subtle scale wobble — a rapid oscillation that communicates
        # "imminent!" more viscerally than a smooth shrink. The wobble
        # amplitude ramps from 0 to ~8% of the current scale as the timer
        # approaches zero, making the last moments feel tense and urgent.
        if progress > 0.7:
            urgency_t = (progress - 0.7) / 0.3  # 0→1 in final 30%
            wobble = math.sin(self.lifetime * 30) * 0.08 * urgency_t
            current_scale *= (1.0 + wobble)
        self.scale = current_scale
        # Alpha ramps up: starts faint, gets brighter and pulses faster near the end
        base_alpha = int(60 + 120 * progress)
        pulse_rate = 4 + progress * 12  # pulses faster as spawn approaches
        pulse = 0.5 + 0.5 * math.sin(self.lifetime * pulse_rate * math.pi)
        alpha = int(base_alpha * pulse)
        # ── Urgency Color Shift ── As the spawn warning counts down, the ring
        # color shifts from deep red toward bright orange-yellow, conveying
        # increasing urgency. Early on it's a calm "something is coming" red;
        # in the final moments it becomes a frantic "it's almost here!" orange-
        # yellow that grabs attention. The shift makes the final second of the
        # warning feel dramatically more urgent than the beginning, improving
        # readability of imminent spawns during busy combat.
        r = int(255)
        g = int(60 + 195 * progress)  # 60 → 255 (red → orange-yellow)
        b = int(60 + 40 * progress)   # 60 → 100 (slight warm shift)
        self.color = color.rgba(r, g, b, alpha)
        return False


# ─── Spawn Portal Vortex ───────────────────────────────────────────────────
class SpawnPortalVortex(Entity):
    """A spinning flat disc that appears beneath the spawn warning ring.

    Rotates faster as the enemy materializes, creating a dimensional portal
    effect — like the enemy is emerging from a rift rather than just appearing.
    The disc fades in, spins with accelerating speed, then fades out when the
    enemy spawns. Uses a separate quad from the warning ring so the vortex can
    spin independently while the ring shrinks.

    The vortex color is tinted to match the biome where the enemy is spawning,
    creating a cohesive "drawing energy from the environment" visual — a portal
    in the lava biome glows orange-red, in the crystal biome it shimmers cyan,
    in the toxic bog it pulses sickly green. This makes spawns feel tied to the
    world rather than using a generic out-of-place purple.
    """

    def __init__(self, position, biome_color=None):
        # Default to the original purple if no biome color provided
        if biome_color is not None:
            br, bg, bb = _c255_color(biome_color)
            # Blend biome color with purple (60% biome, 40% purple) so the
            # portal still reads as a dimensional rift but carries the
            # environment's hue — cohesive but otherworldly.
            vr = int(br * 0.6 + 180 * 0.4)
            vg = int(bg * 0.6 + 40 * 0.4)
            vb = int(bb * 0.6 + 200 * 0.4)
        else:
            vr, vg, vb = 180, 40, 200
        super().__init__(
            model='quad',
            color=color.rgba(vr, vg, vb, 0),
            scale=2.5,
            position=position + Vec3(0, 0.08, 0),
            rotation_x=90,
        )
        self.lifetime = SPAWN_WARNING_DURATION
        self.max_lifetime = SPAWN_WARNING_DURATION
        self._vortex_r = vr
        self._vortex_g = vg
        self._vortex_b = vb

    def update_vortex(self, dt):
        """Animate the vortex disc. Returns True when expired."""
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Spin accelerates from slow to fast as the enemy materializes
        spin_speed = SPAWN_VORTEX_START_SPEED + (SPAWN_VORTEX_END_SPEED - SPAWN_VORTEX_START_SPEED) * progress
        self.rotation_z += spin_speed * dt
        # Scale shrinks slightly as the vortex closes
        self.scale = 2.5 - 0.8 * progress
        # Alpha ramps up then fades at the very end
        if progress < 0.8:
            base_alpha = int(40 + 80 * progress)
        else:
            base_alpha = int(120 * (1.0 - (progress - 0.8) / 0.2))
        # Pulse for energy feel
        pulse = 0.7 + 0.3 * math.sin(self.lifetime * 15)
        alpha = max(0, int(base_alpha * pulse))
        self.color = color.rgba(self._vortex_r, self._vortex_g, self._vortex_b, alpha)
        return False


# ─── Healing Pulse Ring ────────────────────────────────────────────────────
class HealPulseRing(Entity):
    """A brief expanding green ring that radiates from the player when healed.

    Makes any healing source feel visceral — the green ring expands outward
    from Zorp's position and fades, giving a clear visual cue that HP was
    restored. Works for all heal sources: Health Potion, Regen Crystal, Spawn
    Healing Zone, Healing Shrine, and Idle Regen.
    """

    def __init__(self, position):
        super().__init__(
            model='quad',
            color=color.rgba(80, 255, 120, HEAL_PULSE_ALPHA),
            scale=HEAL_PULSE_START_SCALE,
            position=position + Vec3(0, 0.09, 0),
            rotation_x=90,
        )
        self.lifetime = HEAL_PULSE_DURATION
        self.max_lifetime = HEAL_PULSE_DURATION

    def update_pulse(self, dt):
        """Animate the healing pulse ring. Returns True when expired."""
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Expand outward
        self.scale = HEAL_PULSE_START_SCALE + (HEAL_PULSE_MAX_SCALE - HEAL_PULSE_START_SCALE) * progress
        # Fade out
        alpha = int(HEAL_PULSE_ALPHA * (1.0 - progress))
        self.color = color.rgba(80, 255, 120, max(0, alpha))
        return False


