# ─── Collectible Spawn Ring ────────────────────────────────────────────────
class CollectibleSpawnRing(Entity):
    """A brief expanding ground ring that radiates outward when a collectible
    finishes its spawn-in animation, in the item's color.

    Complements the sparkle burst with a ground-level visual that's visible
    even when looking down at the world from the third-person camera, making
    respawned items feel more alive and polished.
    """

    def __init__(self, position, col):
        cr, cg, cb = _c255_color(col)
        super().__init__(
            model='quad',
            color=color.rgba(cr, cg, cb, COLLECT_SPAWN_RING_ALPHA),
            scale=COLLECT_SPAWN_RING_START_SCALE,
            position=position + Vec3(0, 0.1, 0),
            rotation_x=90,
        )
        self.lifetime = COLLECT_SPAWN_RING_DURATION
        self.max_lifetime = COLLECT_SPAWN_RING_DURATION
        self._r, self._g, self._b = cr, cg, cb

    def update_ring(self, dt):
        """Expand and fade the ring. Returns True when expired."""
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Expand from start scale to max scale
        self.scale = COLLECT_SPAWN_RING_START_SCALE + (COLLECT_SPAWN_RING_MAX_SCALE - COLLECT_SPAWN_RING_START_SCALE) * progress
        # Fade alpha out smoothly
        alpha = max(0, int(COLLECT_SPAWN_RING_ALPHA * (1.0 - progress)))
        self.color = color.rgba(self._r, self._g, self._b, alpha)
        return False


# ─── Collectible Pickup Ring ────────────────────────────────────────────────
class CollectiblePickupRing(Entity):
    """A brief expanding ground ring that radiates outward when a collectible
    is picked up, in the item's color.

    Complements the existing pop animation and particle burst with a
    ground-level visual that's visible even when looking down at the world
    from the third-person camera — making pickups feel more satisfying and
    grounded. The ring is slightly faster and smaller than the spawn ring
    so pickups feel snappy rather than lingering.

    The ring briefly flashes bright white at the very start (over the first
    30% of its life) before blending into the item's color — a snappy "pop"
    of light that gives the pickup an extra layer of punch, catching the eye
    with a burst of energy before settling into the item's hue.
    """

    def __init__(self, position, col):
        cr, cg, cb = _c255_color(col)
        super().__init__(
            model='quad',
            color=color.rgba(255, 255, 255, COLLECT_PICKUP_RING_FLASH_ALPHA),
            scale=COLLECT_PICKUP_RING_START_SCALE,
            position=position + Vec3(0, 0.1, 0),
            rotation_x=90,
        )
        self.lifetime = COLLECT_PICKUP_RING_DURATION
        self.max_lifetime = COLLECT_PICKUP_RING_DURATION
        self._r, self._g, self._b = cr, cg, cb

    def update_ring(self, dt):
        """Expand and fade the ring. Returns True when expired.

        During the initial flash phase (first COLLECT_PICKUP_RING_FLASH_DURATION_RATIO
        of the ring's life), the ring is bright white. After that, it blends
        into the item's color and fades normally.
        """
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Expand from start scale to max scale with ease-out
        ease = 1.0 - (1.0 - progress) ** 2
        self.scale = COLLECT_PICKUP_RING_START_SCALE + (COLLECT_PICKUP_RING_MAX_SCALE - COLLECT_PICKUP_RING_START_SCALE) * ease
        # ── Initial White Flash ── During the first fraction of the ring's life,
        # render bright white for a snappy "pop" of light. Then blend into the
        # item's color and fade out smoothly.
        if progress < COLLECT_PICKUP_RING_FLASH_DURATION_RATIO:
            # White flash phase — high alpha, bright white
            flash_t = progress / COLLECT_PICKUP_RING_FLASH_DURATION_RATIO  # 0→1
            # Fade from flash alpha to normal alpha as the flash ends
            alpha = int(COLLECT_PICKUP_RING_FLASH_ALPHA * (1.0 - flash_t) + COLLECT_PICKUP_RING_ALPHA * flash_t)
            # Blend from white toward the item color
            blend_t = flash_t
            r = int(255 + (self._r - 255) * blend_t)
            g = int(255 + (self._g - 255) * blend_t)
            b = int(255 + (self._b - 255) * blend_t)
            self.color = color.rgba(r, g, b, max(0, alpha))
        else:
            # Normal phase — item color, fade out smoothly
            alpha = max(0, int(COLLECT_PICKUP_RING_ALPHA * (1.0 - progress)))
            self.color = color.rgba(self._r, self._g, self._b, alpha)
        return False


# ─── Enemy Death Ground Ring ────────────────────────────────────────────────
class EnemyDeathRing(Entity):
    """A brief expanding ground ring that radiates outward from an enemy's
    death point in the enemy's own color.

    Complements the existing death particle burst, pop-up animation, and
    screen shake with a ground-level visual that's visible even when looking
    down from the third-person camera. Matches the visual language of hit
    ripples, dash landing rings, collectible spawn/pickup rings, and heal
    pulse rings — giving kills a complete, satisfying visual arc. The ring
    scales with enemy size so tougher enemies produce a bigger death ring.
    """

    def __init__(self, position, col, enemy_scale=1.0):
        cr, cg, cb = _c255_color(col)
        super().__init__(
            model='quad',
            color=color.rgba(cr, cg, cb, ENEMY_DEATH_RING_ALPHA),
            scale=ENEMY_DEATH_RING_START_SCALE,
            position=position + Vec3(0, 0.1, 0),
            rotation_x=90,
        )
        self.lifetime = ENEMY_DEATH_RING_DURATION
        self.max_lifetime = ENEMY_DEATH_RING_DURATION
        self._r, self._g, self._b = cr, cg, cb
        # Scale the max ring size with enemy scale — bigger enemies get bigger rings
        self._max_scale = ENEMY_DEATH_RING_MAX_SCALE * max(0.6, min(2.0, enemy_scale))

    def update_ring(self, dt):
        """Expand and fade the ring. Returns True when expired."""
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Expand from start scale to enemy-scaled max with ease-out
        ease = 1.0 - (1.0 - progress) ** 2
        self.scale = ENEMY_DEATH_RING_START_SCALE + (self._max_scale - ENEMY_DEATH_RING_START_SCALE) * ease
        # Fade alpha out smoothly
        alpha = max(0, int(ENEMY_DEATH_RING_ALPHA * (1.0 - progress)))
        self.color = color.rgba(self._r, self._g, self._b, alpha)
        return False


