# ─── Shockwave Ring ────────────────────────────────────────────────────────
class ShockwaveRing(Entity):
    """An expanding ring projectile fired by the Starburst Sentinel.

    The ring starts small and expands outward in a flat disc, dealing damage
    to the player on contact. It expands until it reaches max radius, then
    fades out and is destroyed.
    """

    def __init__(self, position, damage=STARBURST_SHOCKWAVE_DAMAGE):
        super().__init__(
            model='quad',
            color=color.rgba(255, 220, 50, 180),
            scale=0.5,
            position=position + Vec3(0, 0.5, 0),
            rotation_x=90,
            billboard=False,
        )
        self.damage = damage
        self.current_radius = 0.5
        self.lifetime = STARBURST_SHOCKWAVE_MAX_RADIUS / STARBURST_SHOCKWAVE_EXPAND_SPEED + 0.5
        self.max_lifetime = self.lifetime
        # Bug fix: track whether this ring has already hit the player,
        # to prevent dealing damage every frame (60+ times per ring)
        self.hit_player = False

    def update_ring(self, dt):
        """Expand the ring. Returns True when expired."""
        self.current_radius += STARBURST_SHOCKWAVE_EXPAND_SPEED * dt
        self.scale = self.current_radius
        self.lifetime -= dt
        # Fade out alpha as the ring expands
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        alpha = max(0, int(180 * (1.0 - progress)))
        self.color = color.rgba(255, 220, 50, alpha)
        return self.lifetime <= 0 or self.current_radius >= STARBURST_SHOCKWAVE_MAX_RADIUS


# ─── Portal ──────────────────────────────────────────────────────────────────
class Portal:
    """A pair of linked portals for fast travel across the world.

    Stepping into one portal teleports the player to its linked partner,
    with a cooldown to prevent rapid back-and-forth.
    """

    def __init__(self, position, partner_position, portal_id):
        self.position = position
        self.partner_position = partner_position
        self.portal_id = portal_id
        self.cooldown = 0  # Cooldown timer after teleportation
        self.bob_offset = random.uniform(0, math.pi * 2)

        # Inner ring (cyan) — the main visual
        self.inner = Entity(
            model='quad',
            color=color.rgba(0, 255, 255, 150),
            scale=3.0,
            position=position + Vec3(0, 2.5, 0),
            rotation_x=90,
        )
        # Outer ring (purple) — glow border
        self.outer = Entity(
            model='quad',
            color=color.rgba(100, 0, 255, 80),
            scale=3.5,
            position=position + Vec3(0, 2.5, 0),
            rotation_x=90,
        )
        # Ground glow disc
        self.ground_glow = Entity(
            model='quad',
            color=color.rgba(0, 200, 255, 40),
            scale=4.0,
            position=position + Vec3(0, 0.1, 0),
            rotation_x=90,
        )
        # Pillar markers
        # Bug fix: initialize self.pillars before the loop instead of using
        # hasattr inside, which is fragile and inconsistent style.
        self.pillars = []
        for angle_deg in [0, 90, 180, 270]:
            rad = math.radians(angle_deg)
            pillar = Entity(
                model='cube',
                color=color.rgb(60, 180, 220),
                scale=(0.25, 3.0, 0.25),
                position=position + Vec3(math.cos(rad) * 1.8, 1.5, math.sin(rad) * 1.8),
            )
            self.pillars.append(pillar)

    def animate(self, t):
        """Animate portal rings and glow."""
        # Inner ring spins and pulses
        self.inner.rotation_y += 120 * time.dt
        pulse = 3.0 + math.sin(t * 4 + self.bob_offset) * 0.3
        self.inner.scale = pulse
        # Outer ring counter-rotates
        self.outer.rotation_y -= 80 * time.dt
        self.outer.scale = pulse + 0.5
        # Ground glow pulses
        ground_pulse = 4.0 + math.sin(t * 3 + self.bob_offset) * 0.5
        self.ground_glow.scale = ground_pulse
        # Update cooldown
        if self.cooldown > 0:
            self.cooldown -= time.dt
            # During cooldown, dim the portal
            self.inner.color = color.rgba(0, 100, 100, 80)
            self.outer.color = color.rgba(50, 0, 100, 30)
        else:
            self.inner.color = color.rgba(0, 255, 255, 150)
            self.outer.color = color.rgba(100, 0, 255, 80)

    def destroy_all(self):
        """Clean up all portal entities."""
        destroy(self.inner)
        destroy(self.outer)
        destroy(self.ground_glow)
        for p in self.pillars:
            destroy(p)


# ─── Alien Monolith (World Feature) ──────────────────────────────────────────
class AlienMonolith:
    """A mysterious ancient structure that grants temporary buffs when activated.

    Monoliths are found in crystal and snow biomes. When the player approaches
    within range, the monolith activates and randomly grants one of three buffs:
    - Speed Surge: 1.5x movement speed for 10 seconds
    - Power Surge: 1.4x projectile damage for 10 seconds
    - Wisdom Aura: 2x XP gain for 10 seconds

    After activation, a monolith enters a cooldown period before it can be used again.
    """

    BUFF_TYPES = ['speed', 'damage', 'xp']
    BUFF_NAMES = {
        'speed': 'Speed Surge',
        'damage': 'Power Surge',
        'xp': 'Wisdom Aura',
    }
    BUFF_COLORS = {
        'speed': color.rgb(50, 255, 50),
        'damage': color.rgb(255, 100, 50),
        'xp': color.rgb(100, 200, 255),
    }

    def __init__(self, position):
        self.position = position
        self.cooldown = 0.0  # Seconds until next activation
        self.bob_offset = random.uniform(0, math.pi * 2)
        self.active_buff = None  # Which buff is currently glowing
        self.glow_phase = random.uniform(0, math.pi * 2)

        # Main monolith body — tall, thin, ancient-looking structure
        self.body = Entity(
            model='cube',
            color=color.rgb(80, 60, 120),
            position=position + Vec3(0, 3, 0),
            scale=(0.8, 6, 0.8),
        )

        # Top crystal cap — glows and pulses when active
        self.cap = Entity(
            model='diamond',
            color=color.rgb(150, 100, 255),
            position=position + Vec3(0, 6.5, 0),
            scale=1.2,
        )

        # Floating ring around the monolith — rotates and changes color with buff
        self.ring = Entity(
            model='quad',
            color=color.rgba(150, 100, 255, 80),
            position=position + Vec3(0, 4, 0),
            scale=3.0,
            rotation_x=90,
        )

        # Ground glow disc
        self.ground_glow = Entity(
            model='quad',
            color=color.rgba(150, 100, 255, 30),
            position=position + Vec3(0, 0.1, 0),
            scale=4.0,
            rotation_x=90,
        )

        # Side rune panels — decorative markings
        # Bug fix: store rune entities in a list so they can be properly destroyed
        # in destroy_all(), preventing entity leaks and scene graph pollution.
        self.runes = []
        for angle_deg in [0, 90, 180, 270]:
            rad = math.radians(angle_deg)
            rune = Entity(
                model='quad',
                color=color.rgb(180, 140, 220),
                position=position + Vec3(math.cos(rad) * 0.5, 3, math.sin(rad) * 0.5),
                scale=(0.6, 2.5),
                rotation_y=angle_deg,
            )
            self.runes.append(rune)

    def animate(self, t):
        """Animate monolith: pulse glow, rotate ring, update cooldown."""
        # Pulse the cap crystal
        pulse = 0.8 + 0.4 * math.sin(t * 3 + self.glow_phase)
        self.cap.scale = pulse

        # Rotate ring
        # BUG FIX: Removed unnecessary hasattr checks — self.ring and
        # self.cooldown are always set in __init__, so the checks were dead
        # code that added confusion and overhead.
        self.ring.rotation_y += 90 * time.dt

        # If on cooldown, dim everything; otherwise, vibrant glow
        if self.cooldown > 0:
            self.cooldown -= time.dt
            # Dimmed state — gray and dormant
            dim_alpha = int(40 + 20 * math.sin(t * 2))
            self.cap.color = color.rgb(80, 60, 100)
            self.ring.color = color.rgba(80, 60, 100, dim_alpha)
            self.ground_glow.color = color.rgba(80, 60, 100, 15)
            # BUG FIX: When a monolith is activated, the body is flashed with
            # the buff color (line ~12451). But animate() ran every frame and
            # immediately overrode it with dim gray, so the buff color flash
            # was never visible. Now, if active_buff is set during cooldown,
            # blend the body color toward the buff color (dimmed) so the
            # player can see which buff they got.
            if self.active_buff:
                bc = self.BUFF_COLORS.get(self.active_buff, color.rgb(80, 60, 120))
                bcr, bcg, bcb = _c255_color(bc)
                # Dimmed version of the buff color
                self.body.color = color.rgb(int(bcr * 0.4), int(bcg * 0.4), int(bcb * 0.4))
            else:
                self.body.color = color.rgb(60, 45, 80)
        else:
            # Active state — glowing based on last buff or default purple
            if self.active_buff:
                bc = self.BUFF_COLORS.get(self.active_buff, color.rgb(150, 100, 255))
                glow_a = int(100 + 50 * math.sin(t * 4))
                self.cap.color = bc
                # BUG FIX: bc components are 0-1 normalized floats (Ursina stores
                # color.rgb() values as 0-1 internally). int(0.196)=0, int(1.0)=1,
                # etc. — so the ring/glow were always black (rgba(0,0,0,alpha))
                # instead of the buff color. Use _c255_color() to normalize.
                bcr, bcg, bcb = _c255_color(bc)
                self.ring.color = color.rgba(bcr, bcg, bcb, glow_a)
                self.ground_glow.color = color.rgba(bcr, bcg, bcb, 40)
            else:
                bright_a = int(80 + 40 * math.sin(t * 3))
                self.cap.color = color.rgb(180, 140, 255)
                self.ring.color = color.rgba(150, 100, 255, bright_a)
                self.ground_glow.color = color.rgba(150, 100, 255, 30)
                self.body.color = color.rgb(80, 60, 120)

    def destroy_all(self):
        """Clean up all monolith entities."""
        destroy(self.body)
        destroy(self.cap)
        destroy(self.ring)
        destroy(self.ground_glow)
        # Bug fix: also destroy rune entities that were previously leaked
        for rune in self.runes:
            destroy(rune)
        self.runes.clear()


# ─── Healing Crystal Shrine (World Feature) ──────────────────────────────────
class HealingCrystalShrine:
    """A glowing crystal shrine that heals the player when approached.

    Shrines are found in mushroom and swamp biomes — biomes that are far
    from the spawn healing zone. When the player approaches within range,
    the shrine instantly restores a substantial amount of HP, then enters
    a long cooldown. A safe haven deep in dangerous territory.

    Unlike Alien Monoliths (which grant temporary buffs), shrines provide
    a direct instant heal — a different kind of reward for exploration.
    """

    def __init__(self, position):
        self.position = position
        self.cooldown = 0.0  # Seconds until next activation
        self.bob_offset = random.uniform(0, math.pi * 2)
        self.glow_phase = random.uniform(0, math.pi * 2)

        # Base platform — a short stone-like cube
        self.base = Entity(
            model='cube',
            color=color.rgb(60, 80, 60),
            position=position + Vec3(0, 0.5, 0),
            scale=(2.0, 1.0, 2.0),
        )

        # Central healing crystal — tall glowing green diamond
        self.crystal = Entity(
            model='diamond',
            color=color.rgb(100, 255, 150),
            position=position + Vec3(0, 3, 0),
            scale=1.5,
        )

        # Floating ring around the shrine — rotates slowly
        self.ring = Entity(
            model='quad',
            color=color.rgba(100, 255, 150, 60),
            position=position + Vec3(0, 2.5, 0),
            scale=3.5,
            rotation_x=90,
        )

        # Ground glow disc — soft green light on the ground
        self.ground_glow = Entity(
            model='quad',
            color=color.rgba(100, 255, 150, 30),
            position=position + Vec3(0, 0.05, 0),
            scale=5.0,
            rotation_x=90,
        )

        # Four small corner crystals for decoration
        self.corner_crystals = []
        for angle_deg in [45, 135, 225, 315]:
            rad = math.radians(angle_deg)
            cc = Entity(
                model='diamond',
                color=color.rgb(120, 220, 160),
                position=position + Vec3(math.cos(rad) * 1.5, 1.2, math.sin(rad) * 1.5),
                scale=0.6,
            )
            self.corner_crystals.append(cc)

    def animate(self, t):
        """Animate shrine: pulse crystal, rotate ring, update cooldown."""
        # Pulse the central crystal
        pulse = 0.85 + 0.3 * math.sin(t * 2.5 + self.glow_phase)
        self.crystal.scale = 1.5 * pulse

        # Rotate ring slowly
        self.ring.rotation_y += 60 * time.dt

        # Update cooldown
        if self.cooldown > 0:
            self.cooldown -= time.dt
            # Dimmed/dormant state — crystal is gray
            dim_alpha = int(30 + 15 * math.sin(t * 1.5))
            self.crystal.color = color.rgb(80, 100, 90)
            self.ring.color = color.rgba(80, 100, 90, dim_alpha)
            self.ground_glow.color = color.rgba(80, 100, 90, 12)
            self.base.color = color.rgb(50, 60, 50)
            for cc in self.corner_crystals:
                cc.color = color.rgb(80, 100, 90)
        else:
            # Active state — vibrant green glow
            bright_a = int(60 + 30 * math.sin(t * 3))
            self.crystal.color = color.rgb(100, 255, 150)
            self.ring.color = color.rgba(100, 255, 150, bright_a)
            self.ground_glow.color = color.rgba(100, 255, 150, 35)
            self.base.color = color.rgb(60, 80, 60)
            for cc in self.corner_crystals:
                cc.color = color.rgb(120, 220, 160)

    def destroy_all(self):
        """Clean up all shrine entities."""
        destroy(self.base)
        destroy(self.crystal)
        destroy(self.ring)
        destroy(self.ground_glow)
        for cc in self.corner_crystals:
            destroy(cc)
        self.corner_crystals.clear()


# ─── Wandering Trader (NPC) ──────────────────────────────────────────────────
class Trader(Entity):
    """A friendly alien NPC that wanders the world and trades Space Gloop for rare items.

    Traders meander near the player's vicinity. When the player gets close
    and has enough Space Gloop, pressing E initiates a trade that converts
    5 Space Gloop into a random rare item.
    """

    TRADE_ITEMS = ['Meteor Shard', 'Quantum Fuzz', 'Shield Crystal', 'Weapon Upgrade', 'Nebula Dust', 'Magnet Core', 'Time Warp', 'Star Fruit', 'Fireball Scroll', 'Regen Crystal', 'Lucky Clover', 'Mirror Shard']

    def __init__(self, position, name=None):
        if name is None:
            name = random.choice(TRADER_NAMES)
        super().__init__(
            model='sphere',
            color=color.rgb(255, 200, 100),
            scale=1.0,
            position=position,
            collider='sphere',
        )
        self.trader_name = name
        self.wander_dir = Vec3(random.uniform(-1, 1), 0, random.uniform(-1, 1)).normalized()
        self.wander_timer = random.uniform(3, 6)
        self.home = Vec3(position.x, position.y, position.z)
        self.trade_prompt_shown = False

        # Hat (cone-shaped)
        self.hat = Entity(
            model='cube',
            color=color.rgb(200, 50, 200),
            scale=(0.8, 0.4, 0.8),
            parent=self,
            position=(0, 0.8, 0),
        )
        # Eyes (friendly blue)
        self.eye_l = Entity(model='sphere', color=color.cyan, scale=0.25, parent=self, position=(-0.25, 0.25, -0.5))
        self.eye_r = Entity(model='sphere', color=color.cyan, scale=0.25, parent=self, position=(0.25, 0.25, -0.5))
        # Smile
        self.smile = Entity(
            model='quad',
            color=color.rgba(255, 255, 200, 200),
            scale=(0.4, 0.1),
            parent=self,
            position=(0, 0.05, -0.55),
        )

        # Name label (floating above)
        self.name_label = Text(
            parent=camera.ui,
            text=f'[{name}]',
            scale=0.8,
            color=color.yellow,
            origin=(0, 0),
            visible=False,
        )
        self.trade_label = Text(
            parent=camera.ui,
            text='',
            scale=0.7,
            color=color.green,
            origin=(0, 0),
            visible=False,
        )


# ─── Projectile ────────────────────────────────────────────────────────────────
class ProjectileTrail(Entity):
    """A fading trail dot spawned behind a projectile for a satisfying laser streak effect.

    Each trail dot shrinks and fades over its lifetime, creating a smooth
    comet-tail visual behind the player's tentacle laser.
    """

    def __init__(self, position, col):
        """Initialize a trail dot at the given position with the projectile's color."""
        super().__init__(
            model='sphere',
            color=col,
            scale=PROJECTILE_TRAIL_START_SCALE,
            position=position,
        )
        self.lifetime = PROJECTILE_TRAIL_LIFETIME
        self.max_lifetime = PROJECTILE_TRAIL_LIFETIME

    def update_trail(self, dt):
        """Advance the trail animation. Returns True when expired and should be removed.

        Args:
            dt: Delta time in seconds.

        Returns:
            True if the trail dot has expired and should be destroyed.
        """
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Smoothly shrink from start scale to end scale
        current_scale = PROJECTILE_TRAIL_START_SCALE + (PROJECTILE_TRAIL_END_SCALE - PROJECTILE_TRAIL_START_SCALE) * progress
        self.scale = current_scale
        # Fade alpha out over lifetime
        alpha = max(0, int(200 * (1.0 - progress)))
        # BUG FIX: Use _c255_color() to normalize — self.color may be a named
        # color (0-1 range) or color.rgb() (0-255 range). int() on 0-1 values
        # gives 0 or 1, making the trail invisible. Same fix pattern as HitRipple.
        r, g, b = _c255_color(self.color)
        self.color = color.rgba(r, g, b, alpha)
        return False


class HitRipple(Entity):
    """An expanding ring effect spawned at enemy hit location for satisfying impact feedback.

    The ring starts small and bright, then expands outward and fades, giving
    the player a clear visual cue that their shot landed.
    """

    def __init__(self, position, col=None):
        """Initialize a hit ripple at the given world position.

        Args:
            position: 3D world position where the hit occurred.
            col: Optional color for the ripple (defaults to white/yellow).
        """
        if col is None:
            col = color.rgba(255, 255, 200, 180)
        super().__init__(
            model='quad',
            color=col,
            scale=ENEMY_HIT_RIPPLE_START_SCALE,
            position=position + Vec3(0, 0.15, 0),
            rotation_x=90,
        )
        self.lifetime = ENEMY_HIT_RIPPLE_DURATION
        self.max_lifetime = ENEMY_HIT_RIPPLE_DURATION
        self.base_color = col

    def update_ripple(self, dt):
        """Advance the ripple animation. Returns True when expired.

        Args:
            dt: Delta time in seconds.

        Returns:
            True if the ripple has expired and should be destroyed.
        """
        self.lifetime -= dt
        if self.lifetime <= 0:
            return True
        progress = 1.0 - (self.lifetime / self.max_lifetime)
        # Expand from start scale toward max scale
        current_scale = ENEMY_HIT_RIPPLE_START_SCALE + (ENEMY_HIT_RIPPLE_MAX_SCALE - ENEMY_HIT_RIPPLE_START_SCALE) * progress
        self.scale = current_scale
        # Fade alpha out over lifetime
        alpha = max(0, int(180 * (1.0 - progress)))
        # BUG FIX: Use _c255_color() to normalize base_color — could be
        # named (0-1) or color.rgba() (0-255). int() on 0-1 gives 0 or 1.
        r, g, b = _c255_color(self.base_color)
        self.color = color.rgba(r, g, b, alpha)
        return False


class Projectile(Entity):
    """A laser projectile fired by the player.

    A bright cyan core sphere with a soft translucent glow aura child entity
    that gives the shot a satisfying energy-ball appearance instead of a
    flat dot, making the tentacle laser feel more powerful.
    """

    def __init__(self, position, direction, damage=PROJECTILE_BASE_DAMAGE, speed=PROJECTILE_SPEED):
        super().__init__(
            model='sphere',
            color=C_LASER,
            scale=0.3,
            position=position,
        )
        self.direction = direction.normalized()
        self.damage = damage
        self.speed = speed
        self.lifetime = PROJECTILE_LIFETIME

        # ── Bolt Stretch ── Orient the projectile so its local Z axis aligns
        # with the travel direction, then apply a non-uniform scale that
        # stretches it along Z (length) and slightly compresses it along X/Y
        # (width). This turns the round sphere into a streaking energy bolt
        # that visibly points in the direction it's traveling — a dramatic
        # visual upgrade to the core combat feel.
        self.look_at(position + self.direction)
        self.scale = Vec3(PROJECTILE_BOLT_WIDTH, PROJECTILE_BOLT_WIDTH, PROJECTILE_BOLT_LENGTH)

        # Soft glow aura — a larger translucent sphere parented to the projectile
        # that gives the shot an energy-ball look without any lighting cost
        # (unlit shader ignores it, so it's pure additive-style visual).
        self.aura = Entity(
            model='sphere',
            color=PROJECTILE_AURA_COLOR,
            scale=PROJECTILE_AURA_SCALE,
            parent=self,
        )
        self.aura_base_alpha = PROJECTILE_AURA_COLOR[3]
        self._aura_phase = random.uniform(0, math.pi * 2)

        # Trail spawning timer
        self.trail_timer = 0.0

        # ── Projectile Spawn Scale-In ── Brief scale-up from small to full
        # size over the first few frames, making the shot feel *launched* from
        # the muzzle instead of popping in at full size. The timer counts down
        # from PROJECTILE_SPAWN_IN_DURATION to 0; while > 0, the bolt's scale
        # is multiplied by an ease-out factor from PROJECTILE_SPAWN_IN_START to 1.0.
        self.spawn_in_timer = PROJECTILE_SPAWN_IN_DURATION

        # ── Critical Hit Pierce ── When a crit triggers a pierce, this set
        # tracks which enemies the projectile has already passed through so
        # it doesn't hit the same enemy twice. is_piercing is set to True
        # by the collision code when a crit pierce is triggered. The aura
        # turns gold to visually mark the piercing shot.
        self._pierced_enemies = set()
        self.is_piercing = False

        # ── Combo Milestone Aura Surge ── When the player hits a combo milestone,
        # this timer is set to COMBO_MILESTONE_PROJ_SURGE_DURATION. While > 0,
        # the projectile's aura gets a temporary scale boost and brighter alpha
        # flash — making the milestone feel impactful through the player's
        # active shots. The surge decays over the duration and the aura returns
        # to its normal combo-scaling behavior.
        self._milestone_surge_timer = 0.0

    def move(self, dt, combo_count=0):
        """Move the projectile forward. Returns False when lifetime expires.

        Also pulses the glow aura's alpha for a living energy-ball effect
        rather than a static translucent sphere. The pulse speed and aura
        scale scale up with the player's combo count — at high combos the
        laser visibly "charges up", pulsing faster and glowing larger so
        kill streaks feel more powerful and give immediate visual feedback.
        """
        self.position += self.direction * self.speed * dt
        self.lifetime -= dt
        # ── Projectile Spawn Scale-In ── During the first few frames, scale
        # the bolt up from a small size to full size with an ease-out curve.
        # This makes the shot feel *launched* from the muzzle — you see the
        # bolt emerge and grow as it departs, adding a sense of momentum and
        # emergence to each shot. The effect is very brief so it doesn't
        # affect collision or aim perception.
        if self.spawn_in_timer > 0:
            self.spawn_in_timer -= dt
            if self.spawn_in_timer < 0:
                self.spawn_in_timer = 0
            spawn_progress = 1.0 - (self.spawn_in_timer / PROJECTILE_SPAWN_IN_DURATION)
            # Ease-out: snaps up fast then settles
            ease = 1.0 - (1.0 - spawn_progress) ** 2
            spawn_mult = PROJECTILE_SPAWN_IN_START + (1.0 - PROJECTILE_SPAWN_IN_START) * ease
            self.scale = Vec3(
                PROJECTILE_BOLT_WIDTH * spawn_mult,
                PROJECTILE_BOLT_WIDTH * spawn_mult,
                PROJECTILE_BOLT_LENGTH * spawn_mult,
            )
        # Combo-scaling aura: pulse faster and grow larger at high combos
        combo_t = max(0.0, min(1.0, (combo_count - PROJECTILE_AURA_COMBO_TIER) / 10.0))
        pulse_speed = lerp(PROJECTILE_AURA_PULSE_SPEED_BASE, PROJECTILE_AURA_PULSE_SPEED_MAX, combo_t)
        aura_scale_mult = lerp(1.0, PROJECTILE_AURA_SCALE_MAX / PROJECTILE_AURA_SCALE, combo_t)
        self._aura_phase += dt * pulse_speed
        pulse = 0.5 + 0.5 * math.sin(self._aura_phase)
        # Brighten the aura as combo rises too — higher base alpha at high combos
        alpha_floor = 0.6 + 0.3 * combo_t
        a = max(20, min(255, int(self.aura_base_alpha * (alpha_floor + (1.0 - alpha_floor) * pulse))))
        r, g, b = _c255_color(PROJECTILE_AURA_COLOR)
        self.aura.color = color.rgba(r, g, b, a)
        self.aura.scale = PROJECTILE_AURA_SCALE * aura_scale_mult
        # ── Combo Milestone Aura Surge ── When the surge timer is active
        # (set by the game when a combo milestone is hit), override the
        # aura with a brief scale boost and brighter alpha flash. The
        # surge decays over COMBO_MILESTONE_PROJ_SURGE_DURATION seconds,
        # blending smoothly back to the normal combo-scaling aura. This
        # makes every active shot in the air momentarily swell brighter
        # and larger when you hit a milestone — your kill streak
        # supercharges your in-flight lasers.
        if self._milestone_surge_timer > 0:
            self._milestone_surge_timer -= dt
            if self._milestone_surge_timer < 0:
                self._milestone_surge_timer = 0
            surge_t = self._milestone_surge_timer / COMBO_MILESTONE_PROJ_SURGE_DURATION
            surge_scale = PROJECTILE_AURA_SCALE * aura_scale_mult * lerp(1.0, COMBO_MILESTONE_PROJ_SURGE_SCALE, surge_t)
            surge_alpha = min(255, int(a + (COMBO_MILESTONE_PROJ_SURGE_ALPHA - a) * surge_t))
            self.aura.color = color.rgba(r, g, b, surge_alpha)
            self.aura.scale = surge_scale
        # ── Combo Warm Tint ── At high combos the core bolt lerps from pure
        # cyan toward a warm cyan-gold, making the laser visibly "heat up"
        # during kill streaks. This complements the aura pulse/scale scaling
        # so the bolt itself also reflects combo state. Piercing crits turn
        # full gold via the pierce system (set in the collision code), which
        # takes priority over this subtle combo tint — so we only apply the
        # warm tint to non-piercing bolts.
        if not self.is_piercing and combo_count >= PROJECTILE_COMBO_WARM_TIER:
            warm_t = max(0.0, min(1.0, (combo_count - PROJECTILE_COMBO_WARM_TIER) / 10.0))
            warm_t *= PROJECTILE_COMBO_WARM_MAX  # Cap the lerp
            # Lerp cyan (0,255,255) toward gold (255,215,80)
            br = int(0 + (255 - 0) * warm_t)
            bg = int(255 + (215 - 255) * warm_t)
            bb = int(255 + (80 - 255) * warm_t)
            self.color = color.rgb(br, bg, bb)
        elif not self.is_piercing:
            # Combo too low — ensure the bolt is at its base cyan color
            self.color = C_LASER
        return self.lifetime > 0


# ─── Enemy Projectile Trail ──────────────────────────────────────────────────
# Enemy projectiles now leave a brief fading trail (matching the player's
# projectile trail system) so incoming fire is easy to track and dodge. The
# trail uses the same ProjectileTrail class with an orange tint instead of
# cyan, maintaining visual consistency between player and enemy projectiles
# while making them instantly distinguishable by color.
ENEMY_PROJ_TRAIL_INTERVAL = 0.04  # Seconds between trail dot spawns
ENEMY_PROJ_TRAIL_COLOR = color.rgba(255, 120, 20, 140)  # Orange trail (matching projectile color)
# ── Enemy Projectile Expiry Fizz ── When an enemy projectile's lifetime
# expires without hitting the player (a missed shot), a small orange fizz
# particle burst appears at the expiry point — matching the player
# projectile fizz system so enemy shots also get visual closure instead
# of silently vanishing. This makes it clear the shot was a near-miss
# rather than a glitch, and helps the player gauge enemy effective range.
ENEMY_PROJ_FIZZ_PARTICLE_COUNT = 4   # Small particle burst on expiry
ENEMY_PROJ_FIZZ_COLOR = color.rgb(200, 100, 0)  # Orange fizz (matching projectile color)


class EnemyProjectile(Entity):
    """A projectile fired by Spore Spitter enemies toward the player.

    Features a soft pulsing orange glow aura (matching the player projectile
    aura) so incoming enemy fire is clearly visible and threatening —
    especially in dark biomes where a flat orange sphere can be hard to see.
    The aura pulses in brightness as the projectile flies, making it easy to
    track and dodge.
    """

    def __init__(self, position, direction, damage=10, speed=20):
        super().__init__(
            model='sphere',
            color=color.rgb(200, 100, 0),
            scale=0.25,
            position=position,
        )
        self.direction = direction.normalized()
        self.damage = damage
        self.speed = speed
        self.lifetime = 3.0
        self.intercepted = False  # Set True when a player bolt shoots it down

        # ── Glow Aura ── A larger translucent sphere parented to the projectile
        # that gives the enemy shot a glowing energy-ball look, making it much
        # easier to see and dodge. The aura pulses in brightness each frame.
        self.aura = Entity(
            model='sphere',
            color=ENEMY_PROJECTILE_AURA_COLOR,
            scale=ENEMY_PROJECTILE_AURA_SCALE,
            parent=self,
        )
        self.aura_base_alpha = ENEMY_PROJECTILE_AURA_COLOR[3]
        self._aura_phase = random.uniform(0, math.pi * 2)
        # Trail spawning timer — leaves a fading orange trail so the projectile
        # is easy to track and dodge, matching the player projectile trail system
        self.trail_timer = 0.0
        # Warning ring timer — drops red ground rings when close to the player
        self.warn_ring_timer = 0.0

    def move(self, dt, time_scale=1.0):
        """Move the enemy projectile forward. Returns False when lifetime expires.

        Also pulses the glow aura's alpha for a living, threatening visual
        that makes the projectile easy to track as it flies toward the player.
        Accumulates a trail timer so the caller can spawn trail dots at a
        regular interval (matching the player projectile trail system).

        The time_scale parameter allows the Chrono Field to slow enemy
        projectiles that are inside the bubble — making ranged enemies easier
        to dodge while the field is active.
        """
        effective_dt = dt * time_scale
        self.position += self.direction * self.speed * effective_dt
        self.lifetime -= effective_dt
        # Pulse the aura brightness so the projectile visibly glows
        self._aura_phase += dt * ENEMY_PROJECTILE_AURA_PULSE_SPEED
        pulse = 0.5 + 0.5 * math.sin(self._aura_phase)
        # BUG FIX: Previously alpha was multiplied by (0.5 + 0.5 * pulse),
        # but pulse is already 0..1 — so the multiplier only ranged 0.5-1.0,
        # collapsing the pulse to a barely-visible 25-50 alpha range.
        # Now use the full 0.4-1.0 range for a visible pulsing effect.
        a = max(20, min(255, int(self.aura_base_alpha * (0.4 + 0.6 * pulse))))
        r, g, b = _c255_color(ENEMY_PROJECTILE_AURA_COLOR)
        self.aura.color = color.rgba(r, g, b, a)
        # Accumulate trail timer — the caller reads this to spawn trail dots
        self.trail_timer += dt
        return self.lifetime > 0


# ─── Damage Number Pop-In Animation ──────────────────────────────────────────
# Damage numbers now pop in with a brief scale overshoot instead of appearing
# at full size instantly — a subtle but satisfying improvement that makes hit
# and kill feedback feel punchier. The pop-in runs over DMG_NUMBER_POPIN_DURATION
# seconds: the number scales from 0.3x to 1.15x (overshoot) then settles to 1.0x,
# matching the polish standard of other visual effects in the game.
DMG_NUMBER_POPIN_DURATION = 0.12   # How long the pop-in animation lasts (seconds)
DMG_NUMBER_POPIN_START_SCALE = 0.3 # Starting scale (small)
DMG_NUMBER_POPIN_PEAK_SCALE = 1.15 # Peak overshoot scale
DMG_NUMBER_POPIN_SETTLE_SCALE = 1.0  # Final settled scale

class DamageNumber:
    """A floating damage number that rises from an enemy on hit and fades out.

    Uses a 3D billboard entity with a text overlay for visibility.
    Tracks its own lifetime and handles cleanup.

    The number pops in with a brief scale overshoot on appearance —
    starting at 0.3x scale, overshooting to 1.15x, and settling to 1.0x
    over DMG_NUMBER_POPIN_DURATION seconds. This makes damage feedback
    feel punchier and more satisfying instead of numbers appearing flat.
    """

    def __init__(self, position, amount, is_kill=False, is_crit=False, is_overkill=False, is_heal=False, is_execution=False, is_flawless=False, is_pickup=False, pickup_color=None, is_score=False):
        # Color: gold for flawless, green for heals, gold for crits, yellow for kills, red-orange for overkills, white for normal hits
        if is_flawless:
            col = color.rgb(255, 215, 0)
            text_str = f"✦+{amount} XP"
            scale_factor = 1.45
        elif is_score:
            # ── Kill Score Popup ── A small "+N pts" floating number in bright
            # cyan-white appears at the kill location, showing exactly how many
            # points the kill was worth. Distinct from the yellow damage/kill
            # number so players can see both the damage dealt AND the score
            # gained. Especially satisfying at high combo multipliers where the
            # score scales up significantly.
            col = KILL_SCORE_POPUP_COLOR
            text_str = f"+{amount} pts"
            scale_factor = 0.9
        elif is_heal:
            col = color.rgb(80, 255, 120)
            text_str = f"+{amount}"
            scale_factor = 1.1
        elif is_pickup:
            # ── Pickup Score Popup ── A small floating "+N pts" number in the
            # item's color appears at the pickup location, making the score
            # gain feel tangible and immediate instead of just silently rolling
            # up in the HUD. Uses the item's own color for visual cohesion.
            if pickup_color is not None:
                cr, cg, cb = _c255_color(pickup_color)
                col = color.rgb(cr, cg, cb)
            else:
                col = color.rgb(200, 255, 200)
            text_str = f"+{amount}"
            scale_factor = 0.85
        elif is_overkill:
            col = color.rgb(255, 80, 0)
            text_str = f"OVERKILL {amount}!"
            scale_factor = 1.6
        elif is_execution:
            col = color.rgb(255, 200, 40)
            text_str = f"⚡EXECUTE! +{amount} XP"
            scale_factor = 1.5
        elif is_crit and not is_kill:
            col = CRIT_NUMBER_COLOR
            text_str = f"★{amount}"
        elif is_kill:
            col = color.yellow
            text_str = f"{amount} KILL!"
        else:
            col = color.white
            text_str = str(amount)
        # Scale: crits pop bigger than normal hits, kills pop biggest, overkills biggest
        if is_overkill:
            scale_factor = 1.6
        elif is_execution:
            scale_factor = 1.5
        elif is_flawless:
            scale_factor = 1.45
        elif is_kill:
            scale_factor = 1.4
        elif is_crit:
            scale_factor = 1.25
        else:
            scale_factor = 1.0

        # ── Damage Number Magnitude Scaling ── Scale up the number based on the
        # raw damage amount so heavy hits produce visibly larger numbers than
        # light hits. A logarithmic curve maps the damage amount to a boost
        # between 0 and DMG_NUMBER_MAGNITUDE_MAX_BOOST, applied multiplicatively
        # on top of the category-based scale_factor. This makes a 80-damage crit
        # noticeably bigger than a 20-damage hit, enhancing the visual hierarchy
        # Skipped for heals, pickups, and XP/execution/flawless numbers
        # (those use fixed scales and aren't raw damage).
        if not is_heal and not is_pickup and not is_flawless and not is_execution and not is_score and amount > 0:
            if amount > DMG_NUMBER_MAGNITUDE_BASE:
                # Log curve: 0 boost at BASE, approaching MAX_BOOST at high damage
                log_ratio = math.log(amount / DMG_NUMBER_MAGNITUDE_BASE) / DMG_NUMBER_MAGNITUDE_CURVE
                magnitude_boost = DMG_NUMBER_MAGNITUDE_MAX_BOOST * min(1.0, max(0.0, log_ratio))
                scale_factor *= (1.0 + magnitude_boost)

        # 3D billboard quad as a glowing background dot behind the number
        # BUG FIX: col may be a named color (0-1 .r/.g/.b) or color.rgb() (0-255).
        # Use _c255_color() to normalize before passing to color.rgba().
        cr, cg, cb = _c255_color(col)
        # ── Anti-Overlap Jitter ── When multiple damage numbers spawn at the
        # same position (e.g., a multi-hit AOE or rapid-fire burst), they stack
        # perfectly on top of each other, making only the topmost readable. A
        # small random horizontal offset (±0.8 world units) spreads them out so
        # each number is individually visible, making rapid hit feedback much
        # more readable in intense combat.
        jitter_x = random.uniform(-0.8, 0.8)
        jitter_z = random.uniform(-0.4, 0.4)
        self.bg_dot = Entity(
            model='quad',
            color=color.rgba(cr, cg, cb, 120),
            scale=0.6 * scale_factor,
            position=Vec3(position.x + jitter_x, position.y + 2.0, position.z + jitter_z),
            billboard=True,
        )
        # UI Text anchored to the camera for crisp rendering
        self.text_ent = Text(
            parent=camera.ui,
            text=text_str,
            scale=DMG_NUMBER_SCALE * scale_factor * 0.7,
            color=col,
            origin=(0, 0),
            background=False,
        )
        self.lifetime = DMG_NUMBER_LIFETIME
        self.max_lifetime = DMG_NUMBER_LIFETIME
        self.world_pos = Vec3(position.x + jitter_x, position.y + 2.0, position.z + jitter_z)
        self.is_kill = is_kill
        self.is_crit = is_crit
        self.is_overkill = is_overkill
        self.is_heal = is_heal
        self.is_flawless = is_flawless
        self.is_pickup = is_pickup
        self.is_score = is_score
        self.alive = True
        # ── Pop-In Animation ── The number scales in from small to an
        # overshoot peak then settles to normal, making damage feedback
        # feel punchier instead of appearing at full size instantly.
        self.popin_timer = DMG_NUMBER_POPIN_DURATION
        self._base_text_scale = DMG_NUMBER_SCALE * scale_factor * 0.7
        self._base_bg_scale = 0.6 * scale_factor
        # BUG FIX: Store the bg_dot's category color so update() can preserve it
        # instead of hardcoding white every frame (which overrode the colored
        # tint set in __init__, making all bg_dots appear white regardless of
        # the damage category — heal=green, flawless=gold, overkill=red, etc.)
        self._bg_r = cr
        self._bg_g = cg
        self._bg_b = cb
        # Start at the pop-in starting scale
        self.text_ent.scale = self._base_text_scale * DMG_NUMBER_POPIN_START_SCALE
        self.bg_dot.scale = self._base_bg_scale * DMG_NUMBER_POPIN_START_SCALE
        # ── Horizontal Drift ── Each number drifts gently to a random side,
        # producing a natural floating arc instead of a rigid vertical rise.
        # The drift direction is randomized per number so grouped hits spread
        # organically in different directions rather than all leaning the same way.
        self._drift_dir = random.uniform(-1.0, 1.0)
        self._drift_decay_timer = 0.0

    def update(self, dt):
        """Advance the damage number animation. Returns True when expired."""
        self.lifetime -= dt
        # ── Horizontal Drift ── The number moves sideways with a decaying
        # velocity, producing a gentle arc. The drift eases to a stop over
        # the first ~0.5 seconds so the number settles as it fades.
        self._drift_decay_timer += dt
        drift_decay = math.exp(-self._drift_decay_timer * DMG_NUMBER_DRIFT_DECAY)
        drift_x = self._drift_dir * DMG_NUMBER_DRIFT_SPEED * drift_decay * dt
        self.world_pos += Vec3(drift_x, DMG_NUMBER_RISE_SPEED * dt, 0)
        self.bg_dot.position = self.world_pos
        # Project world position to UI screen coordinates
        cam = camera
        cam_pos = cam.get_world_position()
        diff = self.world_pos - cam_pos
        # Simple projection to screen space using camera's view
        screen_pos = camera.screen_point(self.world_pos)
        self.text_ent.position = (screen_pos[0], screen_pos[1])
        # ── Pop-In Scale Animation ── During the first DMG_NUMBER_POPIN_DURATION
        # seconds, the number scales from DMG_NUMBER_POPIN_START_SCALE through an
        # overshoot peak (DMG_NUMBER_POPIN_PEAK_SCALE) and settles to 1.0x. This
        # uses a triangle wave (0→1→0) mapped to a scale interpolation: first half
        # ramps from start to peak, second half eases from peak to settle. After
        # the pop-in completes, the scale stays at 1.0x (base scale).
        if self.popin_timer > 0:
            self.popin_timer -= dt
            if self.popin_timer < 0:
                self.popin_timer = 0
            popin_progress = 1.0 - (self.popin_timer / DMG_NUMBER_POPIN_DURATION)  # 0→1
            if popin_progress < 0.5:
                # Ramp up from start scale to peak overshoot
                ramp_t = popin_progress / 0.5
                # Ease-out: fast start, slows as it reaches peak
                scale_mult = DMG_NUMBER_POPIN_START_SCALE + (DMG_NUMBER_POPIN_PEAK_SCALE - DMG_NUMBER_POPIN_START_SCALE) * (1.0 - (1.0 - ramp_t) ** 2)
            else:
                # Settle from peak to normal
                settle_t = (popin_progress - 0.5) / 0.5
                scale_mult = DMG_NUMBER_POPIN_PEAK_SCALE + (DMG_NUMBER_POPIN_SETTLE_SCALE - DMG_NUMBER_POPIN_PEAK_SCALE) * settle_t
            self.text_ent.scale = self._base_text_scale * scale_mult
            self.bg_dot.scale = self._base_bg_scale * scale_mult
        # Fade out — defensive: clamp alpha to prevent negative values
        alpha = max(0, min(1, self.lifetime / self.max_lifetime))
        # NOTE: r, g, b were previously read from text_ent.color but never used —
        # the color is always overridden below with hardcoded values.
        if self.is_flawless:
            self.text_ent.color = color.rgba(255, 215, 0, int(255 * alpha))
        elif self.is_score:
            self.text_ent.color = color.rgba(120, 255, 255, int(255 * alpha))
        elif self.is_pickup:
            self.text_ent.color = color.rgba(self._bg_r, self._bg_g, self._bg_b, int(255 * alpha))
        elif self.is_heal:
            self.text_ent.color = color.rgba(80, 255, 120, int(255 * alpha))
        elif self.is_overkill:
            self.text_ent.color = color.rgba(255, 80, 0, int(255 * alpha))
        elif self.is_kill:
            self.text_ent.color = color.rgba(255, 255, 0, int(255 * alpha))
        elif self.is_crit:
            self.text_ent.color = color.rgba(255, 200, 0, int(255 * alpha))
        else:
            self.text_ent.color = color.rgba(255, 255, 255, int(255 * alpha))
        # BUG FIX: Preserve the bg_dot's category color (stored in __init__)
        # instead of hardcoding white — so heal numbers get a green bg_dot,
        # flawless gets gold, overkill gets red, etc.
        self.bg_dot.color = color.rgba(self._bg_r, self._bg_g, self._bg_b, int(80 * alpha))
        if self.lifetime <= 0:
            self.alive = False
            return True
        return False

    def destroy(self):
        """Clean up all owned entities."""
        destroy(self.bg_dot)
        destroy(self.text_ent)
