class Mission:
    """A mission objective with progress tracking."""
    def __init__(self, title, description, target, reward, mission_type, target_count):
        self.title = title
        self.description = description
        self.target = target
        self.reward = reward
        self.mission_type = mission_type
        self.target_count = target_count
        self.progress = 0
        self.completed = False
        # Bug fix: track baseline kills/collects at mission creation so progress
        # measures delta (kills since mission assigned), not lifetime total.
        # Without this, kill missions are instantly completable if the player
        # already killed enough of that enemy before the mission was assigned.
        self.baseline = 0
        self.turned_in = False


# ─── Game ──────────────────────────────────────────────────────────────────────
class Game:
    """Main game controller: manages world, entities, HUD, and game state."""

    def __init__(self):
        self.seed = random.randint(0, 999999)
        self.world_grid = WorldGenerator.generate(WORLD_SIZE, self.seed)
        self.terrain_entities = []
        self.tree_entities = []
        self.crystal_entities = []
        self.enemies = []
        self.collectibles = []
        self.health_fragments = []  # Enemy death health fragment orbs
        self.projectiles = []
        self.projectile_trails = []
        self.enemy_projectiles = []
        self.particles = []
        self.damage_numbers = []
        self.shockwave_rings = []  # Starburst Sentinel shockwave rings
        self.hit_ripples = []      # Expanding impact ring effects on enemy hits
        self.portals = []          # Portal pairs for fast travel
        self.traders = []          # Wandering Trader NPCs
        self.monoliths = []        # Alien Monoliths — world structures granting buffs
        self.shrines = []           # Healing Crystal Shrines — instant heal structures
        self.water_overlays = []   # Water surface shimmer quads (for animation)
        self.lava_overlays = []     # Lava glow shimmer quads (for animation)
        self.trader_spawn_timer = TRADER_RESPAWN_TIME / 2  # Initial spawn delay
        self.time_warp_timer = 0   # Time Warp slow-mo for enemies
        self.missions = []
        self.messages = []
        self.game_over = False
        self.paused = False
        self.t = 0
        # BUG FIX: Removed unused 'game_start_time' — survival time is tracked
        # via self.t which is incremented in game_update. This was dead state.
        self.spawn_timer = 0
        self.mission_timer = 0

        # ── Death Screen Fade-In State ── Tracks the staggered fade-in
        # animation for the death screen. When _show_death_screen() is called,
        # death_fade_timer is set to the total animation duration and counts
        # down in real time. Each element's alpha is computed from how much
        # time has elapsed since its stagger offset. The death_score_displayed
        # ramps from 0 to the final score via lerp for a satisfying count-up.
        self.death_fade_timer = 0.0
        self.death_score_displayed = 0.0
        self.death_final_score = 0

        # Visual effects state
        self.screen_shake = 0.0
        self.level_up_timer = 0.0
        self.hit_stop_timer = 0.0
        # ── Boss Death Slow-Motion ── When a boss-tier enemy is killed, time
        # is briefly slowed for a cinematic effect. slowmo_timer counts down
        # in real-time; while > 0, time.dt is multiplied by BOSS_DEATH_SLOWMO_SCALE.
        # The time scale smoothly recovers to 1.0 as the timer winds down.
        self.boss_slowmo_timer = 0.0
        self.boss_slowmo_time_scale = 1.0  # Current effective time scale (lerps back to 1.0)
        self.kill_fov_timer = 0.0  # Camera FOV punch on kill — brief zoom-in effect
        self.level_up_fov_timer = 0.0  # Camera FOV punch on level-up — cinematic zoom
        self.current_biome = 'grass'
        # Smoothly-interpolated biome indicator color (r,g,b floats in 0-255 range)
        self.biome_color_current = (10.0, 180.0, 80.0)

        # Combo system
        self.combo_count = 0
        self.combo_timer = 0.0
        self.combo_display_timer = 0.0
        self.max_combo = 0  # Track highest combo reached in this run
        self.combo_bar_refresh_flash = 0.0  # Timer for combo bar green flash on each kill

        # Combo Break Shatter: When a combo of x3+ expires, a red
        # "COMBO BROKEN!" announcement appears with shatter particles.
        # Tracks the announcement timer and the combo count that was broken
        # (for display in the text).
        self.combo_break_announce_timer = 0.0
        self.combo_break_count = 0  # The combo count that was lost

        # ── Flawless Kill Streak ── Tracks consecutive kills made without
        # taking any damage. At milestones (every FLAWLESS_MILESTONE kills),
        # bonus XP is awarded with a golden "FLAWLESS!" announcement. Taking
        # ANY damage resets the streak to 0. The display timer controls how
        # long the streak text stays visible on the HUD. max_flawless tracks
        # the highest streak achieved this run for the death screen summary.
        self.flawless_streak = 0              # Current consecutive flawless kills
        self.flawless_display_timer = 0.0    # How long the streak HUD text stays visible
        self.max_flawless = 0                 # Highest flawless streak this run

        # Multi-Kill system — tracks rapid kills within a short window for
        # dramatic announcements ("DOUBLE KILL!", "TRIPLE KILL!", etc.)
        self.multi_kill_count = 0           # Kills in the current window
        self.multi_kill_timer = 0.0         # Time remaining in the current window
        self.multi_kill_announce_timer = 0.0  # How long the announcement stays visible
        self.multi_kill_announce_text = ''    # Current announcement text
        self.multi_kill_announce_scale = 1.0  # Current announcement scale (for pop animation)

        # ── Berserk Mode ── When the player kills BERSERK_KILL_THRESHOLD enemies
        # within BERSERK_WINDOW seconds, a temporary berserk state activates with
        # +50% damage and +30% speed. berserk_kill_window counts down; each kill
        # resets it and increments berserk_kill_count. When the threshold is
        # reached, berserk_timer is set and the kill counter resets.
        self.berserk_kill_count = 0           # Kills in the current rapid-kill window
        self.berserk_kill_timer = 0.0         # Time remaining in the current window
        self.berserk_announce_timer = 0.0     # How long the BERSERK! announcement stays
        self.berserk_screen_flash_timer = 0.0 # Red screen flash on berserk trigger

        # ── First Blood ── Tracks whether the first-kill bonus has been
        # awarded this run. Set False on init, set True when the first enemy
        # is killed so the bonus only fires once per run.
        self.first_blood_triggered = False

        # ── Kill Streak Milestone ── Tracks total kills toward the next
        # milestone reward. When total_kills crosses a KILL_STREAK_MILESTONE
        # boundary, bonus XP is awarded with a golden announcement. The
        # last_milestone_kills tracks the last milestone reached so we can
        # detect crossing the next boundary.
        self.last_milestone_kills = 0

        # ── Combo Sustain Heal ── Tracks kills within the current combo for
        # the periodic heal tick. Reset to 0 when the combo breaks so the
        # counter only counts kills within an active high combo.
        self.combo_sustain_heal_counter = 0

        # ── Swarm Escape ── Tracks whether the swarm-escape speed boost is
        # currently active. Updated periodically by checking how many enemies
        # are within SWARM_ESCAPE_RADIUS. The check runs on an interval to
        # avoid iterating the enemy list every frame.
        self.swarm_escape_active = False
        self.swarm_escape_check_timer = 0.0

        # ── Pickup Streak ── Tracks consecutive rapid item pickups. Each pickup
        # within PICKUP_STREAK_WINDOW seconds extends the streak. At milestones
        # (every 5), bonus XP is awarded. Makes item gathering runs feel rewarding.
        self.pickup_streak = 0               # Current consecutive pickup count
        self.pickup_streak_timer = 0.0       # Time remaining before streak resets
        self.pickup_streak_display_timer = 0.0  # How long the streak HUD text stays visible
        self.max_pickup_streak = 0           # Highest streak this run (for death screen)
        self.pickup_streak_bar_flash = 0.0   # Green flash timer on the streak bar

        # ── Critical Hit Chain ── Tracks consecutive crits within a time window.
        # After CRIT_CHAIN_THRESHOLD consecutive crits, subsequent crits deal
        # CRIT_CHAIN_MULT (3x) instead of the normal CRIT_DAMAGE_MULT (2x).
        self.crit_chain = 0                  # Current consecutive crit count
        self.crit_chain_timer = 0.0          # Time remaining before chain resets
        self.crit_chain_display_timer = 0.0  # How long the chain HUD text stays visible

        # ── Enemy Spawn Direction Indicators ── Reuses the damage arrow entities
        # but in orange. Spawn indicators are tracked separately so they fade
        # independently from damage indicators.
        self.spawn_indicators = []            # List of (arrow_ent, direction, remaining_time)

        # Kill feed: list of (timestamp, text) entries
        self.kill_feed = []

        # Pulse Wave ability (Q key)
        self.pulse_wave_cooldown = 0.0
        self.pulse_wave_rings = []

        # Collectible Vacuum Pulse (V key) — pulls all nearby collectibles
        self.vacuum_pulse_cooldown = 0.0
        self.vacuum_pulse_active_timer = 0.0  # >0 while the pulse is pulling
        self.vacuum_pulse_rings = []           # Visual ring entities
        # ── Vacuum Pulse Item Counter ── Tracks how many collectibles were
        # vacuumed during the active pulse window. Reset to 0 on activation
        # and displayed as a summary message + small screen shake when the
        # pulse ends, giving the player feedback on how effective the vacuum
        # pulse was. Without this, the vacuum pulse just silently pulls items
        # with no summary of results — you can't tell if you vacuumed 3 items
        # or 20.
        self.vacuum_pulse_collected_count = 0

        # ── Nova Blast (C key) ── A pure-damage AOE ability. Unlike Pulse Wave
        # (knockback + minor damage), Nova Blast deals significant damage to all
        # enemies in a large radius with no knockback. Longer cooldown makes it
        # a tactical nuke rather than a spammy tool. The nova_rings list holds
        # active visual ring entities; nova_cooldown tracks the cooldown timer.
        self.nova_blast_cooldown = 0.0
        self.nova_blast_rings = []  # Active Nova Blast ring entities

        # ── Chrono Field (Z key) ── A localized time-slow bubble around the
        # player. Unlike Time Warp (which slows ALL enemies globally), Chrono
        # Field only affects enemies within a radius. chrono_field_timer counts
        # down while the bubble is active; chrono_field_cooldown tracks the
        # ability cooldown. The dome and ring entities are lazily created on
        # first activation and made visible/invisible as the field toggles.
        # Affected enemy tracking is done per-frame by distance check in the
        # enemy update loop, so no separate enemy list is needed.
        self.chrono_field_timer = 0.0       # >0 while the bubble is active
        self.chrono_field_cooldown = 0.0    # Cooldown before next use
        self.chrono_field_dome = None       # Lazily created dome visual
        self.chrono_field_ring = None       # Lazily created ground ring visual
        self._chrono_was_on_cooldown = False  # Track cooldown transition for ready flash
        self.chrono_ready_flash_timer = 0.0   # Flash when Chrono Field becomes ready
        self.chrono_field_text = Text(
            text='CHRONO READY [Z]', position=(-0.75, 0.13), scale=0.85,
            color=color.rgb(160, 100, 255),
            origin=(-0.5, 0),
        )
        self.chrono_cd_bar_bg = Entity(
            parent=camera.ui, model='quad', color=color.dark_gray,
            scale=(0.22, 0.012, 1), position=(-0.65, 0.115, 0),
            origin=(-0.5, 0), visible=False,
        )
        self.chrono_cd_bar = Entity(
            parent=camera.ui, model='quad', color=color.rgb(160, 100, 255),
            scale=(0, 0.012, 1), position=(-0.65, 0.115, 0),
            origin=(-0.5, 0), visible=False,
        )
        self.chrono_ready_flash = Entity(
            parent=camera.ui, model='quad', color=color.rgba(160, 100, 255, 0),
            scale=(0.28, 0.04, 1), position=(-0.65, 0.127, 0),
            origin=(-0.5, 0), visible=False,
        )

        # ── Speed Boost Energy Trail ── Tracks accumulators for the vibrant
        # green trail and upward sparkles that appear when the Speed Boost
        # power-up is active. The trail_timer counts down between trail particle
        # spawns; the sparkle_timer counts down between upward sparkle bursts.
        self._speed_boost_trail_timer = 0.0
        self._speed_boost_sparkle_timer = 0.0

        # Auto-fire toggle (X key) — continuous shooting without holding mouse
        self.auto_fire_enabled = False

        # Dash afterimage accumulator — tracks time between afterimage spawns
        # during a dash so we spawn multiple fading ghosts along the dash path
        # instead of just one at the start position.
        self._dash_afterimage_timer = 0.0
        # ── Dash Cooldown Ground Ring ── A thin circular ring at Zorp's feet
        # that shows dash cooldown progress. Created lazily and made
        # visible/hidden as the dash cooldown state changes. The ring starts
        # full (alpha = DASH_CD_RING_ALPHA) when dash goes on cooldown, then
        # fades to near-transparent as the cooldown counts down, and flashes
        # bright cyan when the dash becomes ready again.
        self.dash_cd_ring = None       # Lazily created Entity
        self.dash_cd_ring_flash_timer = 0.0  # >0 while the "dash ready" flash is playing

        # Idle HP regeneration — rewards standing still with slow HP regen
        self.idle_timer = 0.0        # How long the player has been idle
        self.idle_regen_tick = 0.0   # Accumulator for idle regen healing
        self.spawn_warnings = []  # Enemy spawn warning rings
        self.spawn_vortices = []  # Enemy spawn portal vortex discs
        self.heal_pulse_rings = []  # Healing pulse ring effects
        self.collect_spawn_rings = []  # Collectible spawn ground rings
        self.collect_pickup_rings = []  # Collectible pickup ground rings
        self.dash_land_rings = []  # Dash landing impact rings
        self.footstep_ripples = []  # Player footstep ground ripples while running
        self.enemy_death_rings = []  # Enemy death expanding ground rings
        self.muzzle_flash_rings = []  # Muzzle flash ground rings on each shot
        self.player_damage_rings = []  # Player damage ground impact rings

        # ── Meteor Shower World Event ── Tracks the countdown to the next
        # meteor crash. When the timer reaches 0, a meteor streaks across the
        # sky and crashes near the player, spawning bonus collectibles. The
        # timer is initialized to a random value in the interval range so the
        # first event doesn't happen immediately but at an organic time.
        self.meteor_timer = random.uniform(METEOR_SHOWER_INTERVAL_MIN, METEOR_SHOWER_INTERVAL_MAX)
        # List of active meteor ground ring entities (expanding impact rings)
        self.meteor_rings = []

        # ── Enemy Slayer Tracking ── Tracks consecutive kills of the same
        # enemy type within a time window. When SLAYER_THRESHOLD same-type
        # kills happen within SLAYER_WINDOW seconds, a "SLAYER!" bonus is
        # awarded. slayer_current_type stores the last killed enemy's type,
        # slayer_count tracks the streak, and slayer_timer counts down the
        # window. slayer_announce_timer controls the HUD announcement display.
        self.slayer_current_type = None
        self.slayer_count = 0
        self.slayer_timer = 0.0
        self.slayer_announce_timer = 0.0
        self.slayer_announce_text = ''
        self.slayer_announce_scale = 1.0

        # ── Headhunter Bonus ── Tracks distinct enemy types killed within the
        # current combo. When HEADHUNTER_THRESHOLD different types are killed
        # in one combo, a bonus XP reward fires with a blue-violet
        # announcement. The set resets when the combo breaks. This is the
        # counterpart to the Slayer bonus (same type repeatedly) — Headhunter
        # rewards target diversity instead.
        self.headhunter_types = set()           # Enemy types killed in current combo
        self.headhunter_announce_timer = 0.0    # How long the announcement stays
        self.headhunter_announce_text = ''
        self.headhunter_announce_scale = 1.0
        self.headhunter_triggered = False       # Prevents re-trigger in same combo

        # ── Collection Rush Speed Boost ── When the player rapidly collects
        # COLLECTION_RUSH_THRESHOLD items (tracked via the existing pickup
        # streak), a temporary speed boost activates. rush_timer counts down
        # while the boost is active; when it reaches 0, the boost ends.
        self.collection_rush_timer = 0.0

        # ── Collection Rush HUD Text ── Displays "COLLECTION RUSH!" when the
        # speed boost is active, positioned below the pickup streak text.
        self.collection_rush_text = Text(
            text='', position=(0.35, 0.04), scale=1.4,
            color=color.rgba(100, 255, 200, 0),
            visible=False, origin=(0, 0),
        )

        # ── Slayer Announcement Text ── Displays "☠ SLAYER!" with the enemy
        # type name when the slayer bonus triggers. Large, dramatic, fiery
        # orange text that pops and fades.
        self.slayer_text = Text(
            text='', position=(0, -0.04), scale=2.5,
            color=color.rgba(255, 120, 40, 0),
            origin=(0, 0), visible=False,
        )

        # ── Headhunter Announcement Text ── Displays "🎯 HEADHUNTER!" when the
        # player kills HEADHUNTER_THRESHOLD distinct enemy types in one combo.
        # Blue-violet text that pops and fades, positioned slightly above the
        # slayer text so the two don't overlap when both trigger.
        self.headhunter_text = Text(
            text='', position=(0, -0.08), scale=2.3,
            color=color.rgba(140, 120, 255, 0),
            origin=(0, 0), visible=False,
        )

        # ── Ability Ready Flash Tracking ── When the Pulse Wave or Vacuum
        # Pulse cooldown ends, a brief colored pulse flashes behind their HUD
        # text so the player notices the ability is available again — matching
        # the existing Dash ready flash. We track whether each was on cooldown
        # last frame so we only fire the flash on the transition.
        self._pulse_was_on_cooldown = False
        self.pulse_ready_flash_timer = 0.0
        self._vacuum_was_on_cooldown = False
        self.vacuum_ready_flash_timer = 0.0
        # BUG FIX: _nova_was_on_cooldown was missing from __init__ — the readiness
        # flash used getattr(game, '_nova_was_on_cooldown', False) as a workaround,
        # but the first cooldown cycle's ready flash was silently skipped because
        # the attribute didn't exist yet. Now initialized like the other trackers.
        self._nova_was_on_cooldown = False

        # ── Biome Entry Banner ── Tracks the current biome entry banner
        # animation state. When the player crosses into a new biome, the
        # banner text is set and the timer counts down; _update_hud handles
        # the slide-in/hold/slide-out animation. The flash overlay provides
        # a biome-colored screen flash on entry.
        self.biome_banner_timer = 0.0
        self.biome_banner_text = ''
        self.biome_banner_color = (255, 255, 255)
        self.biome_banner_flash_timer = 0.0
        self.biome_banner_flash_color = (255, 255, 255)
        self._prev_biome = 'grass'  # Track previous biome for change detection

        # ── Boss Spawn Warning ── When a boss-tier enemy materializes, a
        # dramatic warning announcement and red screen flash alert the player.
        # The announcement text pulses and fades over the warning duration.
        self.boss_spawn_warning_timer = 0.0
        self.boss_spawn_flash_timer = 0.0

        # ── Enemy Enrage Proximity Warning ── Tracks when the last enrage
        # proximity warning fired so we can throttle them and prevent spam
        # when multiple enemies enrage simultaneously.
        self._last_enrage_warning_time = -999.0

        # ── Vengeful Surge ── Tracks the announcement display timer for the
        # "VENGEFUL SURGE!" HUD text that appears when the player takes damage
        # at a high combo and gets the fight-back buff.
        self.vengeful_surge_announce_timer = 0.0
        self.vengeful_surge_text = Text(
            text='', position=(0, 0.08), scale=2.0,
            color=color.rgba(255, 80, 160, 0),
            origin=(0, 0), visible=False,
        )

        # ── Rapid Pickup Chain ── Tracks very rapid consecutive item pickups
        # (within RAPID_CHAIN_WINDOW seconds). Each chain step awards bonus
        # score that grows with chain length. Distinct from the broader pickup
        # streak — this rewards tight, fast collection patterns.
        self.rapid_chain_count = 0           # Current chain length
        self.rapid_chain_timer = 0.0         # Time remaining before chain resets
        self.rapid_chain_display_timer = 0.0  # How long the HUD text stays visible
        self.max_rapid_chain = 0               # Highest rapid chain this run (for death screen)
        self.rapid_chain_text = Text(
            text='', position=(0.32, -0.02), scale=1.3,
            color=color.rgba(100, 255, 180, 0),
            origin=(0, 0), visible=False,
        )

        # ── Last Stand ── Tracks the announcement display timer for the golden
        # "LAST STAND!" HUD text that appears when the player cheats death via
        # the Last Stand perk. The visual entity is a golden aura on the player
        # model that pulses briefly after the save triggers.
        self.last_stand_announce_timer = 0.0
        self.last_stand_text = Text(
            text='', position=(0, 0.12), scale=2.2,
            color=color.rgba(255, 215, 0, 0),
            origin=(0, 0), visible=False,
        )

        # ── Cornered Beast ── Tracks the visual indicator timer for the
        # damage buff when at low HP. The visual is a subtle red-orange edge
        # glow that intensifies as HP drops, complementing the existing
        # danger vignette and adrenaline rush. The HUD text shows the current
        # damage multiplier.
        self.cornered_beast_text = Text(
            text='', position=(-0.45, -0.08), scale=1.1,
            color=color.rgba(255, 80, 30, 0),
            origin=(0, 0), visible=False,
        )

        # ── Bounty Mark ── Periodically marks a random alive enemy as a bounty
        # target. The bounty_marker_entity is a golden billboard ring that
        # floats above the marked enemy. bounty_enemy holds the reference to
        # the marked Enemy object (or None). The timer counts down to the next
        # bounty assignment.
        self.bounty_timer = BOUNTY_MARK_INTERVAL  # Initial delay before first bounty
        self.bounty_enemy = None                  # Currently marked Enemy (or None)
        self.bounty_ring_entity = None            # Golden billboard ring above the enemy
        self.bounty_announce_timer = 0.0          # How long the bounty announcement stays
        self.bounty_announce_text = Text(
            text='', position=(0, 0.06), scale=1.8,
            color=color.rgba(255, 215, 0, 0),
            origin=(0, 0), visible=False,
        )

        # ── Threat Proximity Pulse Ring ── A red ground ring at Zorp's feet
        # that intensifies based on nearby enemy count. Lazily created on
        # first need, then made visible/invisible based on threat level. The
        # ring reuses the swarm_escape proximity check (same interval) to
        # avoid a second per-frame enemy iteration — the nearby enemy count
        # is stored and the ring update reads from it.
        self.threat_ring = None             # Lazily created Entity
        self.threat_nearby_count = 0        # Updated by swarm-escape check

        # ── Combo Timer Ground Ring ── A thin gold ring on the ground around
        # the player that depletes as the combo timer counts down, giving a
        # glance-free visual countdown. Lazily created and made visible only
        # when a combo is active (x2+).
        self.combo_timer_ring = None        # Lazily created Entity

        # ── Combo Milestone Rainbow Flash ── When a combo milestone is hit,
        # a brief screen-edge flash in the milestone's tier color fires. The
        # flash overlay entity is lazily created and the timer counts down.
        self.combo_milestone_flash_timer = 0.0
        self.combo_milestone_flash_entity = None  # Lazily created overlay quad
        self._combo_milestone_flash_color = (255, 60, 60)  # Default red (tier 1)

        # Achievement system
        self.achievements = [Achievement(d) for d in Achievement.DEFINITIONS]
        self.achievement_popups = []  # list of (unlock_time, achievement) for display
        self.achievement_popup_entities = []  # Text entities for popup display
        self.achievement_panel_shown = False
        self.total_kills = 0
        self.total_items_collected = 0
        self.traded_once = False

        # Spawn healing zone visual indicator
        spawn_center = Vec3(WORLD_SIZE // 2 * TILE_SCALE, 0, WORLD_SIZE // 2 * TILE_SCALE)
        self.spawn_heal_ring = Entity(
            model='quad',
            color=color.rgba(100, 255, 100, SPAWN_HEAL_INDICATOR_ALPHA),
            scale=SPAWN_HEAL_RADIUS * 2,
            position=spawn_center + Vec3(0, 0.05, 0),
            rotation_x=90,
        )
        self._spawn_heal_tick = 0.0

        # Weather particles
        self.weather_particles = []

        # Build terrain
        self._build_terrain()

        # Player
        spawn = Vec3(WORLD_SIZE // 2 * TILE_SCALE, 2, WORLD_SIZE // 2 * TILE_SCALE)
        self.player = Player(position=spawn)

        # Camera rig: orbit camera with mouse look
        self.cam_yaw = 0.0       # Current yaw angle (degrees)
        self.cam_pitch = CAMERA_ANGLE  # Current pitch angle (degrees)
        self.cam_target_yaw = 0.0    # Target yaw for smooth lerp
        self.cam_target_pitch = CAMERA_ANGLE  # Target pitch for smooth lerp
        self.cam_pivot = Entity(position=spawn)
        camera.parent = self.cam_pivot
        # Position camera based on initial yaw
        self._update_camera_orbit()
        camera.fov = DASH_FOV_NORMAL

        # Populate world
        self._spawn_initial_entities()
        self._spawn_portals()
        self._spawn_initial_traders()
        self._spawn_monoliths()
        self._spawn_shrines()
        self._assign_missions(count=3)

        # Lighting — NOTE: Ursina entities use unlit_with_fog_shader by default,
        # so DirectionalLight/AmbientLight have no effect on terrain/entity colors.
        # Keeping a DirectionalLight for any lit entities that may be added later.
        # self.sun = DirectionalLight(color=color.rgba(255, 220, 180, 255))
        # self.sun.look_at(Vec3(1, -1, 1))
        # AmbientLight(color=color.rgba(140, 130, 120, 255))

        # Gradient sky dome — 8 large billboard quads in a ring for a smooth sky gradient
        # OPTIMIZED: 8 quads instead of 96 (12 layers x 8 angles) — same visual, far fewer entities
        self.sky_quads = []
        sky_top_color = (20, 0, 60)       # deep purple at zenith
        sky_horizon_color = (120, 40, 80)  # alien pink at horizon
        sky_height_min = 60
        sky_height_max = 250
        sky_radius = 300
        # 3 layers: top, middle, bottom — each with 8 quads in a ring = 24 total
        sky_layers = [(0.0, sky_height_max + 20, sky_radius * 0.5),
                      (0.5, (sky_height_max + sky_height_min) / 2, sky_radius * 0.75),
                      (1.0, sky_height_min, sky_radius)]
        for t, y_pos, radius in sky_layers:
            r = int(sky_top_color[0] + (sky_horizon_color[0] - sky_top_color[0]) * t)
            g = int(sky_top_color[1] + (sky_horizon_color[1] - sky_top_color[1]) * t)
            b = int(sky_top_color[2] + (sky_horizon_color[2] - sky_top_color[2]) * t)
            for angle_deg in range(0, 360, 45):
                rad = math.radians(angle_deg)
                qx = math.cos(rad) * radius
                qz = math.sin(rad) * radius
                sky_quad = Entity(
                    model='quad',
                    color=color.rgb(r, g, b),
                    scale=(sky_radius * 0.6, sky_radius * 0.5),
                    position=(qx, y_pos, qz),
                    billboard=True,
                )
                self.sky_quads.append(sky_quad)

        # Stars in the sky — varied colors for a richer alien sky
        self.stars = []
        for _ in range(STAR_COUNT):
            angle_h = random.uniform(0, math.pi * 2)
            angle_v = random.uniform(0.15, math.pi * 0.45)
            dist = random.uniform(STAR_HEIGHT_MIN, STAR_HEIGHT_MAX)
            sx = math.cos(angle_h) * math.cos(angle_v) * STAR_SPREAD
            sy = abs(math.sin(angle_v)) * dist + STAR_HEIGHT_MIN
            sz = math.sin(angle_h) * math.cos(angle_v) * STAR_SPREAD
            brightness = random.uniform(0.5, 1.0)
            star_size = random.uniform(1, 3)
            twinkle_speed = random.uniform(2.0, 6.0)
            twinkle_offset = random.uniform(0, math.pi * 2)
            # Pick a star color from the varied palette for richer sky visuals
            star_base_color = random.choice(STAR_COLORS)
            # BUG FIX: STAR_COLORS use color.rgba() which stores components as
            # 0-1 normalized floats in Ursina. int(1.0)=1 instead of 255, making
            # stars nearly invisible. Use _c255_color() to normalize to 0-255.
            sbr, sbg, sbb = _c255_color(star_base_color)
            star = Entity(
                model='quad',
                color=color.rgba(sbr, sbg, sbb, int(255 * brightness)),
                scale=star_size,
                position=(sx, sy, sz),
                billboard=True,
            )
            star.base_brightness = brightness
            star.twinkle_speed = twinkle_speed
            star.twinkle_offset = twinkle_offset
            star.base_color = star_base_color  # Store for twinkling updates
            star.base_scale = star_size  # Store for scale twinkling
            self.stars.append(star)

        # Nebula clouds — large translucent colored quads for atmospheric depth
        self.nebula_clouds = []
        nebula_palette = [
            color.rgb(100, 30, 160),   # deep purple
            color.rgb(30, 60, 160),    # deep blue
            color.rgb(160, 30, 60),    # crimson
            color.rgb(30, 140, 100),   # teal
            color.rgb(160, 90, 30),    # amber
            color.rgb(60, 30, 140),    # indigo
            color.rgb(50, 100, 160),   # sky blue
            color.rgb(140, 50, 100),   # rose
        ]
        for i in range(NEBULA_CLOUD_COUNT):
            angle_h = random.uniform(0, math.pi * 2)
            ny = random.uniform(NEBULA_HEIGHT_MIN, NEBULA_HEIGHT_MAX)
            nx = random.uniform(-NEBULA_SPREAD, NEBULA_SPREAD)
            nz = random.uniform(-NEBULA_SPREAD, NEBULA_SPREAD)
            nebula_size = random.uniform(30, 80)
            nebula_color = nebula_palette[i % len(nebula_palette)]
            # BUG FIX: nebula_palette uses color.rgb() which stores components
            # as 0-1 normalized floats in Ursina. int(0.392)=0, int(0.118)=0,
            # etc. — making nebula clouds black. Use _c255_color() to normalize.
            ncr, ncg, ncb = _c255_color(nebula_color)
            cloud = Entity(
                model='quad',
                color=color.rgba(ncr, ncg, ncb, 25),
                scale=nebula_size,
                position=(nx, ny, nz),
                billboard=True,
            )
            cloud.drift_speed = random.uniform(0.1, 0.4)
            cloud.drift_phase = random.uniform(0, math.pi * 2)
            self.nebula_clouds.append(cloud)

        # Horizon glow band — translucent gradient quads at low altitude for atmospheric depth
        self.horizon_glows = []
        horizon_palette = [
            color.rgb(100, 30, 140),    # purple
            color.rgb(30, 50, 130),     # blue
            color.rgb(140, 30, 60),     # red
            color.rgb(30, 110, 70),     # teal
            color.rgb(110, 60, 25),     # amber
            color.rgb(50, 25, 110),     # indigo
            color.rgb(40, 80, 120),     # slate blue
            color.rgb(100, 30, 70),     # rose
        ]
        for i in range(HORIZON_GLOW_COUNT):
            angle_h = random.uniform(0, math.pi * 2)
            gx = math.cos(angle_h) * HORIZON_GLOW_SPREAD
            gz = math.sin(angle_h) * HORIZON_GLOW_SPREAD
            gy = random.uniform(HORIZON_GLOW_HEIGHT_MIN, HORIZON_GLOW_HEIGHT_MAX)
            glow_size = random.uniform(60, 120)
            glow_color = horizon_palette[i % len(horizon_palette)]
            glow_alpha = HORIZON_GLOW_ALPHA_BASE + random.randint(-10, 10)
            # BUG FIX: horizon_palette uses color.rgb() which stores components
            # as 0-1 normalized floats in Ursina. int(0.392)=0, int(0.118)=0,
            # etc. — making horizon glows black. Use _c255_color() to normalize.
            gcr, gcg, gcb = _c255_color(glow_color)
            horizon_glow = Entity(
                model='quad',
                color=color.rgba(gcr, gcg, gcb, glow_alpha),
                scale=glow_size,
                position=(gx, gy, gz),
                billboard=True,
            )
            horizon_glow.base_color = glow_color
            self.horizon_glows.append(horizon_glow)

        # Fog DISABLED — Ursina's unlit_with_fog_shader expects fog_color as
        # normalized 0-1 vec4, but color.rgb() returns 0-255 values. This mismatch
        # causes fog_color.rgb to be 30x+ too bright in GLSL, washing everything
        # white. Re-enable fog only with properly normalized color values.
        scene.fog_color = color.clear  # alpha=0 means zero fog effect
        scene.fog_density = 0

        # Weather particles (rain, snow, embers)
        self._init_weather()

        # ── World Edge Energy Barrier ── Glowing translucent wall segments
        # at the world boundaries so players can see where the playable area
        # ends. The barrier is a ring of tall translucent quads that pulse
        # gently in an alien purple energy color, giving the world a clear,
        # attractive perimeter instead of just fading into the skybox.
        self.world_edge_barriers = []
        world_span = WORLD_SIZE * TILE_SCALE
        barrier_y = WORLD_EDGE_BARRIER_HEIGHT / 2
        # North and South edges (run along X axis)
        for edge_z in [0, world_span]:
            for seg in range(8):
                seg_width = world_span / 8
                seg_x = seg_width / 2 + seg * seg_width
                barrier = Entity(
                    model='quad',
                    color=color.rgba(100, 60, 200, WORLD_EDGE_BARRIER_ALPHA),
                    scale=(seg_width, WORLD_EDGE_BARRIER_HEIGHT),
                    position=(seg_x, barrier_y, edge_z),
                    billboard=False,
                )
                self.world_edge_barriers.append(barrier)
        # East and West edges (run along Z axis)
        for edge_x in [0, world_span]:
            for seg in range(8):
                seg_width = world_span / 8
                seg_z = seg_width / 2 + seg * seg_width
                # BUG FIX: East/West barriers had swapped scale dimensions —
                # (WORLD_EDGE_BARRIER_HEIGHT, seg_width) made them wide and short
                # instead of thin and tall. Now matches N/S barrier orientation:
                # seg_width on X (runs along Z), height on Y (tall wall).
                # BUG FIX 2: Missing rotation_y=90 — a quad lies in the XY plane by
                # default (facing ±Z). N/S barriers at z=0/z=world_span face the
                # player correctly, but E/W barriers at x=0/x=world_span are
                # edge-on (perpendicular) without rotation, making them invisible.
                # rotation_y=90 faces them along the X axis so players see the wall.
                barrier = Entity(
                    model='quad',
                    color=color.rgba(100, 60, 200, WORLD_EDGE_BARRIER_ALPHA),
                    scale=(seg_width, WORLD_EDGE_BARRIER_HEIGHT),
                    position=(edge_x, barrier_y, seg_z),
                    rotation_y=90,  # Face along X axis for E/W edges
                    billboard=False,
                )
                self.world_edge_barriers.append(barrier)

        # ── Ambient Alien Fireflies ── Small harmless glowing creatures that
        # drift through the world, adding life and atmosphere. Each firefly
        # is a tiny billboard quad with a random color from the palette, a
        # random drift direction, and a random bob/pulse phase. They wander
        # within the world bounds and are only visible when near the player.
        self.fireflies = []
        for _ in range(FIREFLY_COUNT):
            fx = random.uniform(10, world_span - 10)
            fz = random.uniform(10, world_span - 10)
            fy = FIREFLY_BASE_HEIGHT + random.uniform(-1, 1)
            firefly_color = random.choice(FIREFLY_COLORS)
            ff = Entity(
                model='quad',
                color=firefly_color,
                scale=0.25,
                position=(fx, fy, fz),
                billboard=True,
            )
            ff._drift_dir = Vec3(
                random.uniform(-1, 1), 0, random.uniform(-1, 1)
            ).normalized()
            ff._dir_timer = random.uniform(FIREFLY_DIR_CHANGE_MIN, FIREFLY_DIR_CHANGE_MAX)
            ff._bob_phase = random.uniform(0, math.pi * 2)
            ff._pulse_phase = random.uniform(0, math.pi * 2)
            ff._base_color = firefly_color
            self.fireflies.append(ff)

        # HUD
        self._create_hud()

        # Crosshair
        self.crosshair = Entity(parent=camera.ui, model='quad', color=color.rgba(255, 255, 255, 128),
                                scale=(0.003, 0.04), position=(0, 0))
        self.crosshair2 = Entity(parent=camera.ui, model='quad', color=color.rgba(255, 255, 255, 128),
                                 scale=(0.04, 0.003), position=(0, 0))

        # ── Ground Aim Reticle ── A 3D ring on the ground at the mouse
        # world_point position, showing exactly where shots are aimed in the
        # world. Lazily positioned each frame in _update_hud. Uses a quad
        # model scaled to a ring-like appearance (thin cross shape).
        self.ground_reticle = Entity(
            model='quad',
            color=color.rgba(GROUND_RETICLE_COLOR[0], GROUND_RETICLE_COLOR[1],
                             GROUND_RETICLE_COLOR[2], GROUND_RETICLE_ALPHA),
            scale=(GROUND_RETICLE_RADIUS * 2, GROUND_RETICLE_RADIUS * 2),
            position=(0, GROUND_RETICLE_Y, 0),
            rotation_x=90,
            visible=False,
        )
        self._ground_reticle_enemy_near = False  # Tracks proximity state for scaling

        # ── Player Facing Direction Ground Arrow ── A small translucent
        # arrow on the ground beneath Zorp pointing in the facing direction.
        # Sits flat on the ground and smoothly rotates to match facing.
        self.facing_arrow = Entity(
            model='cube',
            color=color.rgba(FACING_ARROW_COLOR[0], FACING_ARROW_COLOR[1],
                              FACING_ARROW_COLOR[2], FACING_ARROW_ALPHA),
            scale=(FACING_ARROW_WIDTH, 0.02, FACING_ARROW_LENGTH),
            position=(0, FACING_ARROW_Y, 0),
            visible=False,
        )
        self._facing_arrow_current_yaw = 0.0  # Smoothed yaw for rotation lerp

        # Low-HP danger vignette — full-screen red overlay that pulses when health is critical
        self.danger_vignette = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(200, 0, 0, 0),
            scale=2.0,
            position=(0, 0),
            z=1,  # Render behind other UI
        )

        # Kill flash overlay — brief white screen flash on enemy kills for satisfying feedback
        self.kill_flash = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(255, 255, 255, 0),
            scale=2.0,
            position=(0, 0),
            z=0.5,  # Same layer as kill flash
        )
        self.kill_flash_timer = 0.0

        # Berserk screen flash overlay — dedicated red flash entity for berserk
        # mode trigger. BUG FIX: previously reused self.kill_flash, which fought
        # with the white kill flash when kills happened during berserk (very
        # common since berserk is triggered by rapid kills). The two systems
        # overwrote each other's color/alpha every frame, causing flickering.
        self.berserk_flash = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(255, 30, 10, 0),
            scale=2.0,
            position=(0, 0),
            z=0.5,  # Same layer as kill flash
        )

        # XP bar gain flash — XP bar pulses brighter and scales up briefly when XP is gained
        self.xp_gain_flash_timer = 0.0

        # Boss proximity tension vignette — subtle red screen-edge tint when a
        # boss (Plasma Drake) is nearby, building atmospheric tension before combat
        self.boss_tension_vignette = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(180, 0, 0, 0),
            scale=2.0,
            position=(0, 0),
            z=1.5,  # Behind most UI but above the danger vignette
        )

        # HP bar damage shake — HP bar jitters briefly when player takes damage
        self.hp_bar_shake_timer = 0.0
        # ── HP Bar Heal Pulse ── When the player heals from any source, the HP
        # bar briefly pulses brighter green and scales up slightly — a positive
        # counterpart to the damage shake. Set by game_update when a heal is
        # detected (via the hp_heal_flag set by Player.heal()), decays smoothly.
        self.hp_bar_heal_pulse_timer = 0.0

        # Dash readiness flash — brief cyan pulse when dash comes off cooldown
        self.dash_ready_flash_timer = 0.0
        self._dash_was_on_cooldown = False

        # Rare collectible pickup flash — screen-edge color flash for rare+
        # pickups, making valuable finds feel special
        self.rare_pickup_flash = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(255, 255, 255, 0),
            scale=2.0,
            position=(0, 0),
            z=0.5,  # Same layer as kill flash
        )
        self.rare_pickup_flash_timer = 0.0
        self.rare_pickup_flash_color = (255, 255, 255)

        # Heal pickup green flash — screen-edge green flash when a Health Potion
        # is picked up while at low HP, giving a clear "you're saved!" feedback
        self.heal_flash = Entity(
            parent=camera.ui,
            model='quad',
            color=color.rgba(80, 255, 120, 0),
            scale=2.0,
            position=(0, 0),
            z=0.5,
        )
        self.heal_flash_timer = 0.0

        # Crosshair recoil — expands briefly on each shot for a dynamic aim feel
        self.crosshair_recoil = 0.0  # 1.0 = just fired, decays to 0
        # Camera shoot recoil kick — decays from 1.0 to 0; applied as a backward
        # camera offset in the camera follow section of game_update. Set by shoot().
        self.camera_shoot_recoil = 0.0
        self._camera_recoil_dir = Vec3(0, 0, 1)  # Default forward; overwritten on each shot
        # Crosshair hit flash — briefly tints the crosshair when a shot hits an
        # enemy, giving instant hit-confirmation feedback. Gold for crits.
        self.crosshair_hit_flash_timer = 0.0
        self.crosshair_hit_flash_color = CROSSHAIR_HIT_FLASH_COLOR
        # ── Crosshair Pickup Pulse ── When a collectible is picked up, the
        # crosshair briefly contracts inward and tints to the item's color —
        # a "got it!" squeeze that complements the shooting recoil expansion.
        self.crosshair_pickup_pulse = 0.0  # 1.0 = just picked up, decays to 0
        self.crosshair_pickup_pulse_color = (255, 255, 255)  # 0-255 tuple

        # Score roll-up — displayed score smoothly lerps toward the real score
        self.displayed_score = 0

        # Damage direction indicator — red arrow pointing toward the source of damage
        self.damage_indicators = []  # List of (Entity, direction_vec, remaining_time) tuples
        # BUG FIX: Removed unused 'damage_indicator_entities' list — it was initialized
        # but never populated or read. The actual arrow entities are tracked in
        # self.dmg_arrow_entities below.

        # Pre-create 4 directional damage arrows (up, down, left, right quadrants)
        # These are hidden and shown when the player takes damage from a direction
        self.dmg_arrow_entities = []
        for i in range(8):  # 8 directions (N, NE, E, SE, S, SW, W, NW)
            angle = math.radians(i * 45)
            ax = math.sin(angle) * DAMAGE_INDICATOR_DISTANCE
            ay = math.cos(angle) * DAMAGE_INDICATOR_DISTANCE
            arrow = Text(
                parent=camera.ui,
                text='▲',
                scale=2.0,
                color=color.rgba(255, 50, 50, 0),
                position=(ax, ay),
                origin=(0, 0),
                z=-0.5,
            )
            self.dmg_arrow_entities.append(arrow)

    @staticmethod
    def _destroy_enemy_entities(enemy):
        """Clean up all sub-entities owned by an enemy (decor, eyes, HP bar, shadow, segments).

        Consolidates the duplicated cleanup code that appeared in three places:
        _cleanup(), the death animation handler, and the not-alive handler.
        Call this before destroying the enemy entity itself.

        Args:
            enemy: The Enemy entity whose sub-entities should be destroyed.
        """
        for d in enemy.decor_entities:
            destroy(d)
        # Clean up Plasma Serpent segments if present
        if hasattr(enemy, 'segment_entities') and enemy.segment_entities:
            for seg in enemy.segment_entities:
                for child in seg.children:
                    if hasattr(child, 'enabled') and child.enabled:
                        destroy(child)
                destroy(seg)
            enemy.segment_entities.clear()
        # Clean up Graviton pull ring if present
        if hasattr(enemy, 'pull_ring') and enemy.pull_ring is not None:
            destroy(enemy.pull_ring)
            enemy.pull_ring = None
        # Clean up Void Bomber warning ring if present
        if hasattr(enemy, 'warning_ring') and enemy.warning_ring is not None:
            if enemy.warning_ring.enabled:
                destroy(enemy.warning_ring)
            enemy.warning_ring = None
        # Clean up alert "!" indicator if present
        # BUG FIX: This was previously duplicated — the same alert_indicator
        # cleanup appeared twice (lines 4117-4121 and 4128-4132). The second
        # copy was dead code since the first already sets alert_indicator=None.
        # Removed the duplicate to keep cleanup logic clean and maintainable.
        if hasattr(enemy, 'alert_indicator') and enemy.alert_indicator is not None:
            if getattr(enemy.alert_indicator, 'enabled', False):
                destroy(enemy.alert_indicator)
            enemy.alert_indicator = None
        # Clean up Echo Wraith decoy clones if present
        if hasattr(enemy, 'echo_clone_entities') and enemy.echo_clone_entities:
            for clone in enemy.echo_clone_entities:
                if clone and hasattr(clone, 'enabled') and clone.enabled:
                    destroy(clone)
            enemy.echo_clone_entities.clear()
        # Clean up Shard Golem shield entity if present
        if hasattr(enemy, 'shield_entity') and enemy.shield_entity is not None:
            if enemy.shield_entity.enabled:
                destroy(enemy.shield_entity)
            enemy.shield_entity = None
        destroy(enemy.eye_l)
        destroy(enemy.eye_r)
        destroy(enemy.hp_bar_bg)
        destroy(enemy.hp_bar)
        if hasattr(enemy, 'ground_shadow') and enemy.ground_shadow:
            destroy(enemy.ground_shadow)
        # Clean up enrage aura if present
        if hasattr(enemy, 'enrage_aura') and enemy.enrage_aura:
            if hasattr(enemy.enrage_aura, 'enabled') and enemy.enrage_aura.enabled:
                destroy(enemy.enrage_aura)
            enemy.enrage_aura = None
        # Clean up spawn grace shield if present
        if hasattr(enemy, 'grace_shield') and enemy.grace_shield:
            if enemy.grace_shield.enabled:
                destroy(enemy.grace_shield)
            enemy.grace_shield = None
        # Clean up hit slow visual ring if present
        if hasattr(enemy, 'hit_slow_ring') and enemy.hit_slow_ring is not None:
            if enemy.hit_slow_ring.enabled:
                destroy(enemy.hit_slow_ring)
            enemy.hit_slow_ring = None

    def _cleanup(self):
        """Clean up all game entities for a restart. Destroys terrain, enemies,
        collectibles, projectiles, particles, HUD, and player — but NOT camera,
        scene, or lighting which Ursina manages globally."""
        # Destroy enemies and their sub-entities
        for e in self.enemies:
            if e and e.enabled:
                self._destroy_enemy_entities(e)
                destroy(e)
        self.enemies.clear()

        # Destroy collectibles
        for c in self.collectibles:
            if c and c.enabled:
                destroy(c.glow)
                destroy(c)
        self.collectibles.clear()

        # Destroy health fragments
        for hf in self.health_fragments:
            if hf and hf.enabled:
                if getattr(hf, '_glow_ring', None) is not None:
                    destroy(hf._glow_ring)
                destroy(hf)
        self.health_fragments.clear()

        # Destroy projectiles
        for p in self.projectiles:
            if p and p.enabled:
                destroy(p)
        self.projectiles.clear()

        # Destroy projectile trails
        for t in self.projectile_trails:
            if t and t.enabled:
                destroy(t)
        self.projectile_trails.clear()

        for ep in self.enemy_projectiles:
            if ep and ep.enabled:
                destroy(ep)
        self.enemy_projectiles.clear()

        # Destroy particles
        for p_ent, vel, lifetime in self.particles:
            if p_ent and p_ent.enabled:
                destroy(p_ent)
        self.particles.clear()

        # Destroy damage numbers
        for dn in self.damage_numbers:
            dn.destroy()
        self.damage_numbers.clear()

        # Destroy shockwave rings
        for ring in self.shockwave_rings:
            if ring and hasattr(ring, 'enabled') and ring.enabled:
                destroy(ring)
        self.shockwave_rings.clear()

        # Destroy pulse wave rings
        for pwr in self.pulse_wave_rings:
            if pwr and hasattr(pwr, 'enabled') and pwr.enabled:
                destroy(pwr)
        self.pulse_wave_rings.clear()

        # BUG FIX: Destroy vacuum pulse rings — these were missing from cleanup,
        # causing entity leaks on restart. Each vacuum pulse spawns a
        # PulseWaveRing entity that must be destroyed before the new Game() is
        # created, otherwise stale rings linger in the scene.
        for vpr in self.vacuum_pulse_rings:
            if vpr and hasattr(vpr, 'enabled') and vpr.enabled:
                destroy(vpr)
        self.vacuum_pulse_rings.clear()

        # Destroy Nova Blast rings
        for nr in self.nova_blast_rings:
            if nr and hasattr(nr, 'enabled') and nr.enabled:
                destroy(nr)
        self.nova_blast_rings.clear()

        # Destroy Chrono Field visuals
        if self.chrono_field_dome is not None:
            if self.chrono_field_dome.enabled:
                destroy(self.chrono_field_dome)
            self.chrono_field_dome = None
        if self.chrono_field_ring is not None:
            if self.chrono_field_ring.enabled:
                destroy(self.chrono_field_ring)
            self.chrono_field_ring = None

        # Destroy spawn warning rings
        for sw in self.spawn_warnings:
            if sw and hasattr(sw, 'enabled') and sw.enabled:
                destroy(sw)
        self.spawn_warnings.clear()

        # Destroy spawn portal vortices
        for vortex in self.spawn_vortices:
            if vortex and hasattr(vortex, 'enabled') and vortex.enabled:
                destroy(vortex)
        self.spawn_vortices.clear()

        # Destroy heal pulse rings
        for hpr in self.heal_pulse_rings:
            if hpr and hasattr(hpr, 'enabled') and hpr.enabled:
                destroy(hpr)
        self.heal_pulse_rings.clear()

        # Destroy collectible spawn rings
        for csr in self.collect_spawn_rings:
            if csr and hasattr(csr, 'enabled') and csr.enabled:
                destroy(csr)
        self.collect_spawn_rings.clear()

        # Destroy collectible pickup rings
        for cpr in self.collect_pickup_rings:
            if cpr and hasattr(cpr, 'enabled') and cpr.enabled:
                destroy(cpr)
        self.collect_pickup_rings.clear()

        # Destroy dash landing rings
        for dlr in self.dash_land_rings:
            if dlr and hasattr(dlr, 'enabled') and dlr.enabled:
                destroy(dlr)
        self.dash_land_rings.clear()

        # Destroy footstep ripples
        for fr in self.footstep_ripples:
            if fr and hasattr(fr, 'enabled') and fr.enabled:
                destroy(fr)
        self.footstep_ripples.clear()

        # Destroy enemy death rings
        for edr in self.enemy_death_rings:
            if edr and hasattr(edr, 'enabled') and edr.enabled:
                destroy(edr)
        self.enemy_death_rings.clear()

        # Destroy muzzle flash rings
        for mfr in self.muzzle_flash_rings:
            if mfr and hasattr(mfr, 'enabled') and mfr.enabled:
                destroy(mfr)
        self.muzzle_flash_rings.clear()

        # Destroy player damage ground impact rings
        for pdr in self.player_damage_rings:
            if pdr and hasattr(pdr, 'enabled') and pdr.enabled:
                destroy(pdr)
        self.player_damage_rings.clear()

        # Destroy meteor shower impact rings
        for mr in self.meteor_rings:
            if mr and hasattr(mr, 'enabled') and mr.enabled:
                destroy(mr)
        self.meteor_rings.clear()

        # Destroy spawn healing zone ring
        if hasattr(self, 'spawn_heal_ring') and self.spawn_heal_ring:
            destroy(self.spawn_heal_ring)

        # Destroy hit ripples
        for ripple in self.hit_ripples:
            if ripple and hasattr(ripple, 'enabled') and ripple.enabled:
                destroy(ripple)
        self.hit_ripples.clear()

        # Destroy portals
        for portal in self.portals:
            portal.destroy_all()
        self.portals.clear()

        # Destroy traders and their sub-entities
        for trader in self.traders:
            if trader and hasattr(trader, 'enabled') and trader.enabled:
                destroy(trader.hat)
                destroy(trader.eye_l)
                destroy(trader.eye_r)
                destroy(trader.smile)
                destroy(trader.name_label)
                destroy(trader.trade_label)
                destroy(trader)
        self.traders.clear()

        # Destroy monoliths
        for monolith in self.monoliths:
            monolith.destroy_all()
        self.monoliths.clear()

        # Destroy healing crystal shrines
        for shrine in self.shrines:
            shrine.destroy_all()
        self.shrines.clear()

        # Destroy terrain and decoration entities
        for t in self.terrain_entities:
            if t and t.enabled:
                destroy(t)
        self.terrain_entities.clear()

        for t in self.tree_entities:
            if t and t.enabled:
                destroy(t)
        self.tree_entities.clear()

        for c in self.crystal_entities:
            if c and c.enabled:
                destroy(c)
        self.crystal_entities.clear()

        # Destroy water and lava overlay shimmer quads
        for overlay in self.water_overlays:
            if overlay and overlay.enabled:
                destroy(overlay)
        self.water_overlays.clear()
        for overlay in self.lava_overlays:
            if overlay and overlay.enabled:
                destroy(overlay)
        self.lava_overlays.clear()

        # Destroy stars
        for s in self.stars:
            if s and s.enabled:
                destroy(s)
        self.stars.clear()

        # Destroy nebula clouds
        for c in self.nebula_clouds:
            if c and c.enabled:
                destroy(c)
        self.nebula_clouds.clear()

        # Destroy horizon glows
        for hg in self.horizon_glows:
            if hg and hg.enabled:
                destroy(hg)
        self.horizon_glows.clear()

        # Destroy player and sub-entities (player's children: tentacles, eyes, pupils, shield_visual)
        if self.player and self.player.enabled:
            if hasattr(self.player, 'ground_shadow') and self.player.ground_shadow:
                destroy(self.player.ground_shadow)
            if hasattr(self.player, 'glow_ring') and self.player.glow_ring:
                destroy(self.player.glow_ring)
            if hasattr(self.player, 'glow_light') and self.player.glow_light:
                destroy(self.player.glow_light)
            # BUG FIX: powerup_ring is a standalone Entity (no parent=self), so it
            # doesn't cascade-destroy with the player. Must be explicitly destroyed
            # to prevent entity leak on restart.
            if hasattr(self.player, 'powerup_ring') and self.player.powerup_ring:
                destroy(self.player.powerup_ring)
            if hasattr(self.player, 'float_ring') and self.player.float_ring is not None:
                destroy(self.player.float_ring)
            if hasattr(self.player, 'monolith_ring') and self.player.monolith_ring is not None:
                destroy(self.player.monolith_ring)
            if hasattr(self.player, 'overheal_ring') and self.player.overheal_ring is not None:
                destroy(self.player.overheal_ring)
            if hasattr(self.player, 'adrenaline_ring') and self.player.adrenaline_ring is not None:
                destroy(self.player.adrenaline_ring)
            if hasattr(self.player, 'combo_shield_ring') and self.player.combo_shield_ring is not None:
                destroy(self.player.combo_shield_ring)
            destroy(self.player)
        # Player's children cascade-destroy: tentacles, eyes, pupils, shield_visual

        # Destroy HUD entities
        for attr in ('hp_bar_bg', 'hp_bar', 'xp_bar_bg', 'xp_bar',
                      'level_text', 'score_text', 'hp_text', 'kills_text',
                      'mission_text', 'controls_text', 'version_text',
                      'game_over_text', 'game_over_sub', 'game_over_stats',
                      'game_over_restart', 'level_up_text', 'dash_text',
                      'powerup_text', 'crosshair', 'crosshair2',
                      'combo_text', 'combo_bar_bg', 'combo_bar', 'weapon_text', 'effect_text', 'biome_text',
                      'boss_hp_bar_bg', 'boss_hp_bar', 'boss_name_text',
                      'danger_vignette', 'kill_flash', 'rare_pickup_flash',
                      'achievement_popup_text', 'achievement_popup_sub',
                      'achievement_panel_text',
                      'pulse_wave_text', 'spawn_heal_text', 'dash_ready_flash',
                      'boss_tension_vignette', 'multi_kill_text', 'combo_break_text', 'berserk_text',
                      'dash_cd_bar_bg', 'dash_cd_bar', 'pulse_cd_bar_bg', 'pulse_cd_bar',
                      'heal_flash', 'combo_edge_glow', 'threat_counter_text',
                      'level_up_flash', 'overheal_bar', 'adrenaline_vignette',
                      'compass_arrow', 'multi_kill_glow',
                      'vacuum_pulse_text', 'vacuum_cd_bar_bg', 'vacuum_cd_bar',
                      'auto_fire_text', 'pulse_ready_flash', 'vacuum_ready_flash',
                      'nova_blast_text', 'nova_cd_bar_bg', 'nova_cd_bar', 'nova_ready_flash',
                      'chrono_field_text', 'chrono_cd_bar_bg', 'chrono_cd_bar', 'chrono_ready_flash',
                      'radar_bg',
                      'biome_banner_text_ent', 'biome_banner_flash',
                      'boss_spawn_warning_text', 'boss_spawn_flash',
                      'pickup_streak_text', 'pickup_streak_bar_bg', 'pickup_streak_bar',
                      'crit_chain_text', 'flawless_text',
                      'swarm_escape_text',
                      'collection_rush_text', 'slayer_text', 'headhunter_text',
                      'vengeful_surge_text', 'rapid_chain_text',
                      'ground_reticle', 'facing_arrow',
                      'last_stand_text', 'cornered_beast_text',
                      'bounty_announce_text',
                      'berserk_flash'):  # BUG FIX: berserk_flash was missing from cleanup — it's a standalone camera.ui overlay (not parented to player), so it leaked on restart.
            ent = getattr(self, attr, None)
            if ent and hasattr(ent, 'enabled'):
                destroy(ent)
        # Destroy radar dots
        for dot in self.radar_dots:
            if dot and hasattr(dot, 'enabled'):
                destroy(dot)
        # Destroy HP bar tick marks
        for tick in getattr(self, 'hp_bar_ticks', []):
            if tick and hasattr(tick, 'enabled'):
                destroy(tick)
        self.hp_bar_ticks = []
        # Destroy damage direction arrows
        for arrow_ent in self.dmg_arrow_entities:
            if arrow_ent and hasattr(arrow_ent, 'enabled'):
                destroy(arrow_ent)
        self.dmg_arrow_entities.clear()
        self.damage_indicators.clear()
        self.spawn_indicators.clear()
        # Destroy bounty ring entity if it exists
        # BUG FIX: Also clear bounty_enemy — it was leaving a dangling reference
        # to a destroyed enemy entity after restart. While the old Game object is
        # replaced by a new one (so the dangling reference doesn't persist), it's
        # good practice to clean up all references to avoid confusion during
        # debugging and prevent issues if _cleanup is ever called without
        # creating a new Game.
        if self.bounty_ring_entity is not None:
            destroy(self.bounty_ring_entity)
            self.bounty_ring_entity = None
        self.bounty_enemy = None
        for t in self.msg_texts:
            if t:
                destroy(t)
        self.msg_texts.clear()

        # Destroy kill feed texts
        for t in self.kill_feed_texts:
            if t and hasattr(t, 'enabled'):
                destroy(t)
        self.kill_feed_texts.clear()

        # Destroy minimap entities
        if self.minimap_entity and hasattr(self.minimap_entity, 'enabled'):
            destroy(self.minimap_entity)
        if self.minimap_player_dot and hasattr(self.minimap_player_dot, 'enabled'):
            destroy(self.minimap_player_dot)
        for dot in self.minimap_enemy_dots:
            if dot and hasattr(dot, 'enabled'):
                destroy(dot)
        self.minimap_enemy_dots.clear()

        # Destroy camera pivot (player follow rig)
        if self.cam_pivot and hasattr(self.cam_pivot, 'enabled'):
            destroy(self.cam_pivot)

        # Destroy lights
        if hasattr(self, 'sun') and self.sun:
            destroy(self.sun)

        # Destroy weather particles
        for wp in self.weather_particles:
            if wp and hasattr(wp, 'enabled'):
                destroy(wp)
        self.weather_particles.clear()

        # BUG FIX: clear missions and messages on restart so stale data
        # doesn't carry over to the new game session.
        self.missions.clear()
        self.messages.clear()

        # BUG FIX: Removed fragile scene.entities iteration that destroyed any
        # entity whose model name contained 'sky'. This could accidentally destroy
        # unrelated entities and is unnecessary — gradient sky quads are destroyed
        # explicitly below, and no Ursina Sky() entity is created in this game.
        # (The sky is built from gradient quads in __init__.)

        # Destroy gradient sky quads
        if hasattr(self, 'sky_quads'):
            for sq in self.sky_quads:
                if sq and hasattr(sq, 'enabled') and sq.enabled:
                    destroy(sq)
            self.sky_quads.clear()

        # Destroy world edge energy barriers
        if hasattr(self, 'world_edge_barriers'):
            for barrier in self.world_edge_barriers:
                if barrier and hasattr(barrier, 'enabled') and barrier.enabled:
                    destroy(barrier)
            self.world_edge_barriers.clear()

        # Destroy ambient fireflies
        if hasattr(self, 'fireflies'):
            for ff in self.fireflies:
                if ff and hasattr(ff, 'enabled') and ff.enabled:
                    destroy(ff)
            self.fireflies.clear()

        # Destroy dash cooldown ground ring
        if hasattr(self, 'dash_cd_ring') and self.dash_cd_ring is not None:
            if self.dash_cd_ring.enabled:
                destroy(self.dash_cd_ring)
            self.dash_cd_ring = None

        # Destroy threat proximity pulse ring
        if hasattr(self, 'threat_ring') and self.threat_ring is not None:
            if self.threat_ring.enabled:
                destroy(self.threat_ring)
            self.threat_ring = None

        # Destroy combo timer ground ring
        if hasattr(self, 'combo_timer_ring') and self.combo_timer_ring is not None:
            if self.combo_timer_ring.enabled:
                destroy(self.combo_timer_ring)
            self.combo_timer_ring = None

        # Destroy combo milestone flash overlay
        if hasattr(self, 'combo_milestone_flash_entity') and self.combo_milestone_flash_entity is not None:
            if self.combo_milestone_flash_entity.enabled:
                destroy(self.combo_milestone_flash_entity)
            self.combo_milestone_flash_entity = None

    def _build_terrain(self):
        """Build the 3D terrain from the world grid with height variation per biome.
        
        OPTIMIZED: Removed 6400 individual box colliders — walkability is checked
        via world_grid array, not physics. A single invisible ground plane provides
        the collider for mouse.world_point ray hits. This saves massive startup time
        and per-frame overhead.
        """
        # Height and scale_y settings per biome for terrain variation
        biome_height = {
            'water': -0.3,
            'lava': -0.2,
            'snow': 0.2,
            'crystal': 0.1,
            'mushroom': 0.15,
            'floating_islands': 0.3,
        }
        biome_scale_y = {
            'water': 0.4,
            'lava': 0.5,
            'snow': 1.1,
            'crystal': 1.05,
            'mushroom': 1.1,
            'floating_islands': 1.2,
        }
        for wy in range(WORLD_SIZE):
            for wx in range(WORLD_SIZE):
                biome = self.world_grid[wy][wx]
                c = BIOME_COLORS.get(biome, C_GRASS)
                tile_y = biome_height.get(biome, 0)
                tile_sy = biome_scale_y.get(biome, 1)
                tile = Entity(
                    model='cube',
                    color=c,
                    position=(wx * TILE_SCALE, tile_y, wy * TILE_SCALE),
                    scale=(TILE_SCALE, tile_sy, TILE_SCALE),
                )
                self.terrain_entities.append(tile)

                # Water surface overlay — semi-transparent blue tint for depth feel
                if biome == 'water':
                    water_overlay = Entity(
                        model='quad',
                        color=color.rgba(30, 80, 220, 80),
                        position=(wx * TILE_SCALE, -0.05, wy * TILE_SCALE),
                        scale=TILE_SCALE,
                        rotation_x=90,
                    )
                    water_overlay._shimmer_offset = random.uniform(0, math.pi * 2)
                    self.water_overlays.append(water_overlay)

                # Lava glow overlay — orange glow disc above lava tiles
                if biome == 'lava':
                    lava_glow = Entity(
                        model='quad',
                        color=color.rgba(255, 120, 30, 60),
                        position=(wx * TILE_SCALE, 0.06, wy * TILE_SCALE),
                        scale=TILE_SCALE * 0.9,
                        rotation_x=90,
                    )
                    lava_glow._shimmer_offset = random.uniform(0, math.pi * 2)
                    self.lava_overlays.append(lava_glow)

        # Single invisible ground plane collider for mouse.world_point ray hits
        # This replaces 6400 individual box colliders with ONE collider
        world_extent = WORLD_SIZE * TILE_SCALE
        ground_collider = Entity(
            model='cube',
            color=color.rgba(0, 0, 0, 0),  # fully invisible
            position=(world_extent / 2 - TILE_SCALE / 2, -0.5, world_extent / 2 - TILE_SCALE / 2),
            scale=(world_extent + TILE_SCALE, 0.1, world_extent + TILE_SCALE),
            collider='box',
            visible=False,
        )
        self.terrain_entities.append(ground_collider)

        # Decorations — separate pass for clarity; not combined since they vary per-tile
        for wy in range(WORLD_SIZE):
            for wx in range(WORLD_SIZE):
                biome = self.world_grid[wy][wx]

                if biome == 'forest' and random.random() < 0.3:
                    tree = Entity(
                        model='cube',
                        color=color.rgb(60, 35, 15),
                        position=(wx * TILE_SCALE, 3, wy * TILE_SCALE),
                        scale=(0.6, 6, 0.6),
                    )
                    canopy = Entity(
                        model='sphere',
                        color=color.rgb(0, 80, 30),
                        position=(wx * TILE_SCALE, 7, wy * TILE_SCALE),
                        scale=3,
                    )
                    self.tree_entities.extend([tree, canopy])

                elif biome == 'crystal' and random.random() < 0.2:
                    height = random.uniform(3, 8)
                    crystal = Entity(
                        model='cube',
                        color=color.rgb(0, 240, 255),
                        position=(wx * TILE_SCALE, height / 2 + 0.6, wy * TILE_SCALE),
                        scale=(0.5, height, 0.5),
                    )
                    self.crystal_entities.append(crystal)

                elif biome == 'mushroom' and random.random() < 0.25:
                    # Alien mushroom: stem + cap with glow
                    stem_h = random.uniform(1.5, 4.5)
                    stem = Entity(
                        model='cube',
                        color=color.rgb(180, 170, 160),
                        position=(wx * TILE_SCALE, stem_h / 2 + 0.5, wy * TILE_SCALE),
                        scale=(0.4, stem_h, 0.4),
                    )
                    cap_r = random.uniform(1.0, 2.5)
                    cap_color_choices = [
                        color.rgb(255, 50, 120),   # neon pink
                        color.rgb(80, 255, 80),    # bright green
                        color.rgb(200, 50, 255),   # purple
                        color.rgb(255, 200, 0),    # golden
                    ]
                    cap = Entity(
                        model='sphere',
                        color=random.choice(cap_color_choices),
                        position=(wx * TILE_SCALE, stem_h + 1.0, wy * TILE_SCALE),
                        scale=cap_r,
                    )
                    # Spore glow ring under cap
                    glow = Entity(
                        model='quad',
                        color=color.rgba(255, 100, 255, 50),
                        position=(wx * TILE_SCALE, stem_h + 0.5, wy * TILE_SCALE),
                        scale=cap_r * 1.5,
                        rotation_x=90,
                    )
                    self.crystal_entities.extend([stem, cap, glow])

                elif biome == 'floating_islands' and random.random() < FLOATING_ISLAND_SPAWN_CHANCE:
                    # Floating island: raised platform with crystals
                    island_h = random.uniform(FLOATING_ISLAND_HEIGHT_MIN, FLOATING_ISLAND_HEIGHT_MAX)
                    island_size = random.uniform(1.5, 3.0)
                    # The floating platform itself
                    island = Entity(
                        model='cube',
                        color=color.rgb(160, 120, 200),
                        position=(wx * TILE_SCALE, island_h, wy * TILE_SCALE),
                        scale=(island_size, 0.5, island_size),
                    )
                    # Shadow beneath
                    shadow = Entity(
                        model='quad',
                        color=color.rgba(0, 0, 0, 40),
                        position=(wx * TILE_SCALE, 0.05, wy * TILE_SCALE),
                        scale=island_size * 1.5,
                        rotation_x=90,
                    )
                    self.crystal_entities.extend([island, shadow])
                    # Crystal on top of island
                    if random.random() < FLOATING_ISLAND_CRYSTAL_CHANCE:
                        crystal_h = random.uniform(1.5, 4.0)
                        crystal_top = Entity(
                            model='cube',
                            color=color.rgb(180, 140, 255),
                            position=(wx * TILE_SCALE, island_h + crystal_h / 2 + 0.25, wy * TILE_SCALE),
                            scale=(0.3, crystal_h, 0.3),
                        )
                        self.crystal_entities.append(crystal_top)

                elif biome == 'toxic_bog' and random.random() < 0.2:
                    # Toxic bog: bubbling toxic pools and twisted fungal stalks
                    if random.random() < 0.5:
                        # Toxic bubble pool — flat glowing disc on ground
                        pool_size = random.uniform(1.0, 2.5)
                        pool = Entity(
                            model='quad',
                            color=color.rgba(100, 200, 50, 90),
                            position=(wx * TILE_SCALE, 0.06, wy * TILE_SCALE),
                            scale=pool_size,
                            rotation_x=90,
                        )
                        self.crystal_entities.append(pool)
                        # Occasional tall toxic spire
                        if random.random() < 0.3:
                            spire_h = random.uniform(2, 5)
                            spire = Entity(
                                model='cube',
                                color=color.rgb(80, 160, 40),
                                position=(wx * TILE_SCALE, spire_h / 2 + 0.5, wy * TILE_SCALE),
                                scale=(0.3, spire_h, 0.3),
                            )
                            self.crystal_entities.append(spire)
                    else:
                        # Twisted fungal stalk with glowing cap
                        stalk_h = random.uniform(1.5, 3.5)
                        stalk = Entity(
                            model='cube',
                            color=color.rgb(50, 100, 20),
                            position=(wx * TILE_SCALE, stalk_h / 2 + 0.5, wy * TILE_SCALE),
                            scale=(0.3, stalk_h, 0.3),
                        )
                        cap = Entity(
                            model='sphere',
                            color=color.rgb(120, 220, 30),
                            position=(wx * TILE_SCALE, stalk_h + 0.8, wy * TILE_SCALE),
                            scale=random.uniform(0.8, 1.5),
                        )
                        # Sickly glow beneath cap
                        bog_glow = Entity(
                            model='quad',
                            color=color.rgba(80, 200, 20, 50),
                            position=(wx * TILE_SCALE, stalk_h + 0.3, wy * TILE_SCALE),
                            scale=random.uniform(1.0, 2.0),
                            rotation_x=90,
                        )
                        self.crystal_entities.extend([stalk, cap, bog_glow])

                elif biome == 'desert' and random.random() < RUINS_PILLAR_CHANCE:
                    # Alien ruins: ancient stone pillars
                    pillar_count = random.randint(1, 4)
                    for pi in range(pillar_count):
                        offset_x = random.uniform(-2, 2)
                        offset_z = random.uniform(-2, 2)
                        pillar_h = random.uniform(2, 6)
                        pillar = Entity(
                            model='cube',
                            color=color.rgb(160, 140, 100),
                            position=(wx * TILE_SCALE + offset_x, pillar_h / 2 + 0.5, wy * TILE_SCALE + offset_z),
                            scale=(0.4, pillar_h, 0.4),
                        )
                        self.crystal_entities.append(pillar)
                    # Broken wall segment
                    if random.random() < 0.5:
                        wall_w = random.uniform(1, 3)
                        wall_h = random.uniform(1.5, 3)
                        wall = Entity(
                            model='cube',
                            color=color.rgb(140, 120, 80),
                            position=(wx * TILE_SCALE, wall_h / 2 + 0.5, wy * TILE_SCALE),
                            scale=(wall_w, wall_h, 0.3),
                        )
                        self.crystal_entities.append(wall)

    @staticmethod
    def _biome_dust_color(biome):
        """Return a biome-tinted dust color for particle effects.

        Lightens the biome's ground color to produce a natural dust tint
        (e.g. green dust on grass, tan on desert, blue on snow). Used by
        movement dust puffs and dash landing bursts for cohesive visuals.

        Args:
            biome: Biome name string (e.g. 'grass', 'desert').

        Returns:
            A Ursina Color suitable for dust particles.
        """
        biome_col = BIOME_COLORS.get(biome, C_GRASS)
        # BUG FIX: biome_col components are 0-1 normalized floats (Ursina stores
        # color.rgb() values as 0-1 internally). int(0.039*0.7+80)=80 instead of
        # int(10*0.7+80)=87. Without this fix, dust color was always ~rgb(80,60,70)
        # regardless of biome — no biome tinting at all. Use _c255_color() first.
        dr, dg, db = _c255_color(biome_col)
        dust_r = min(255, int(dr * 0.7 + 80))
        dust_g = min(255, int(dg * 0.7 + 60))
        dust_b = min(255, int(db * 0.6 + 70))
        return color.rgb(dust_r, dust_g, dust_b)

    @staticmethod
    def _smooth_rotate_toward(entity, target_pos, turn_speed, dt):
        """Smoothly rotate an entity to face a target position on the XZ plane.

        Uses angle lerp with proper wraparound handling so enemies turn
        naturally instead of snapping instantly.

        Args:
            entity: The entity to rotate.
            target_pos: World position to face toward.
            turn_speed: Degrees per second for the rotation lerp.
            dt: Frame delta time.
        """
        dx = target_pos.x - entity.x
        dz = target_pos.z - entity.z
        if abs(dx) < 0.01 and abs(dz) < 0.01:
            return  # Already facing target, skip
        target_angle = math.degrees(math.atan2(dx, dz))
        current = entity.rotation_y
        # Shortest-path angle difference (handles wraparound at 360/0)
        diff = (target_angle - current + 180) % 360 - 180
        max_turn = turn_speed * dt
        if abs(diff) < max_turn:
            entity.rotation_y = target_angle
        else:
            entity.rotation_y = current + max_turn * (1 if diff > 0 else -1)

    def _is_walkable(self, world_x: float, world_z: float) -> bool:
        """Check if a world position is on walkable terrain.

        Args:
            world_x: X coordinate in world space.
            world_z: Z coordinate in world space.

        Returns:
            True if the tile at that position is walkable, False if out of bounds
            or on an unwalkable biome (water/lava).
        """
        tx = int(world_x / TILE_SCALE)
        tz = int(world_z / TILE_SCALE)
        if 0 <= tx < WORLD_SIZE and 0 <= tz < WORLD_SIZE:
            return self.world_grid[tz][tx] in WALKABLE
        return False  # Out of bounds is not walkable

    def _update_camera_orbit(self):
        """Position the camera around the pivot based on current yaw and pitch.
        
        Uses spherical coordinates to place the camera behind and above the
        player, with yaw controlling horizontal orbit and pitch controlling
        the vertical angle. The camera always looks at the pivot point.
        """
        yaw_rad = math.radians(self.cam_yaw)
        pitch_rad = math.radians(self.cam_pitch)
        # Spherical coords: camera offset from pivot
        cam_x = math.sin(yaw_rad) * math.cos(pitch_rad) * CAMERA_DISTANCE
        cam_y = math.sin(pitch_rad) * CAMERA_DISTANCE
        cam_z = math.cos(yaw_rad) * math.cos(pitch_rad) * CAMERA_DISTANCE
        camera.position = (cam_x, cam_y + 2, cam_z)
        camera.rotation = (self.cam_pitch, -self.cam_yaw + 180, 0)

    def _get_camera_forward(self):
        """Return the camera's forward direction on the XZ plane (flattened).
        
        Used to make WASD movement relative to where the camera is looking,
        so W always moves 'forward' from the player's perspective.
        """
        yaw_rad = math.radians(self.cam_yaw)
        return Vec3(math.sin(yaw_rad), 0, math.cos(yaw_rad)).normalized()

    def _get_camera_right(self):
        """Return the camera's right direction on the XZ plane."""
        yaw_rad = math.radians(self.cam_yaw + 90)
        return Vec3(math.sin(yaw_rad), 0, math.cos(yaw_rad)).normalized()

    def _get_biome_at(self, world_x: float, world_z: float) -> str:
        """Return the biome name at a world position.

        Args:
            world_x: X coordinate in world space.
            world_z: Z coordinate in world space.

        Returns:
            Biome name string (e.g. 'grass', 'lava', 'crystal').
        """
        tx = int(world_x / TILE_SCALE)
        tz = int(world_z / TILE_SCALE)
        tx = max(0, min(tx, WORLD_SIZE - 1))
        tz = max(0, min(tz, WORLD_SIZE - 1))
        return self.world_grid[tz][tx]

    @staticmethod
    def _dist2d(a: 'Entity', b: 'Entity') -> float:
        """Compute 2D (XZ-plane) distance between two entities.

        Uses flat distance (ignores Y) since all ground-level gameplay
        happens on the XZ plane. More readable than inline math.

        Args:
            a: First entity (must have .x and .z attributes).
            b: Second entity (must have .x and .z attributes).

        Returns:
            Euclidean distance on the XZ plane.
        """
        dx = a.x - b.x
        dz = a.z - b.z
        return math.sqrt(dx * dx + dz * dz)

    @staticmethod
    def _dist2d_coords(x1: float, z1: float, x2: float, z2: float) -> float:
        """Compute 2D (XZ-plane) distance between two coordinate pairs.

        Useful when you have raw x,z coordinates instead of Entity objects,
        avoiding the need to reference .x and .z on intermediate variables.

        Args:
            x1, z1: Coordinates of the first point.
            x2, z2: Coordinates of the second point.

        Returns:
            Euclidean distance on the XZ plane.
        """
        dx = x1 - x2
        dz = z1 - z2
        return math.sqrt(dx * dx + dz * dz)

    def _show_death_screen(self, p):
        """Display the game over screen with detailed survival stats.

        The death screen uses a staggered fade-in: elements appear in sequence
        (title → subtitle → stats → restart prompt) rather than all snapping
        visible at once, making death feel cinematic and weighty. The subtitle
        score also rolls up from 0 to the final value for a satisfying count-up
        reveal, mirroring the in-game HUD score rollup.
        """
        self.game_over = True
        # Total fade-in duration = all stagger offsets + one fade duration
        # Elements: title (stagger 0), subtitle (stagger 1), stats (stagger 2), restart (stagger 3)
        self.death_fade_timer = (3 * DEATH_SCREEN_FADE_STAGGER) + DEATH_SCREEN_FADE_DURATION
        self.death_final_score = p.score
        self.death_score_displayed = 0.0

        # Set text content immediately but start at 0 alpha — the fade-in
        # is driven by the game_over update block in game_update().
        self.game_over_text.text = 'GAME OVER'
        self.game_over_sub.text = f'Score: 0  Level: {p.level}'
        total_kills = sum(p.kills.values())
        total_items = sum(p.inventory.values())
        time_alive = int(self.t)
        minutes = time_alive // 60
        seconds = time_alive % 60
        kill_details = '  '.join(f'{k}:{v}' for k, v in p.kills.items()) if p.kills else 'None'
        item_details = '  '.join(f'{k}:{v}' for k, v in p.inventory.items()) if p.inventory else 'None'
        # BUG FIX: max(1, time_alive / 60) caps the denominator at 1.0, so for any
        # survival time < 60s the KPM shows the raw kill count instead of kills/min.
        # e.g. 5 kills in 30s → max(1, 0.5) = 1.0 → 5.0 KPM (should be 10.0). Using
        # max(0.001, ...) prevents division by zero while allowing sub-minute rates.
        kpm = f'{total_kills / max(0.001, time_alive / 60):.1f}' if time_alive > 0 else '0'
        # Include total items collected (tracked across all pickups, not just
        # inventory — power-ups consumed in play aren't in inventory but still
        # count toward total collection for a more complete survival summary).
        stats_lines = [
            f'Time Survived: {minutes}m {seconds}s',
            f'Total Kills: {total_kills}   Items Collected: {total_items}',
            f'Total Pickups: {self.total_items_collected}   Kills Per Minute: {kpm}',
            f'Best Combo: x{self.max_combo}   Best Pickup Streak: x{self.max_pickup_streak}',
            f'Best Flawless Streak: x{self.max_flawless}   Best Rapid Chain: x{self.max_rapid_chain}',
            f'Last Stand Used: {"Yes" if p.last_stand_used else "No"}',
            f'Missions Completed: {p.completed_missions}   Enemies Defeated: {kill_details}',
            f'Inventory: {item_details}',
        ]
        self.game_over_stats.text = '\n'.join(stats_lines)
        self.game_over_restart.text = 'Press R to Restart'
        # Make all elements visible — the fade-in controls alpha, not visibility.
        # They start at 0 alpha (set by the update loop) so they're invisible
        # until their stagger offset passes.
        self.game_over_text.visible = True
        self.game_over_sub.visible = True
        self.game_over_stats.visible = True
        self.game_over_restart.visible = True
        # Store the original colors so we can lerp alpha from 0 to full
        self._death_title_color_255 = _c255_color(DEATH_SCREEN_TITLE_COLOR)
        self._death_sub_color_255 = _c255_color(color.white)
        self._death_stats_color_255 = _c255_color(DEATH_SCREEN_STATS_COLOR)
        self._death_restart_color_255 = _c255_color(color.yellow)

    def _spawn_initial_entities(self):
        """Populate the world with initial collectibles and enemies.

        Spawns collectibles on walkable tiles away from the center safe zone,
        and enemies scaled by distance from spawn for gradual difficulty.
        """
        spawn_x = WORLD_SIZE // 2 * TILE_SCALE
        spawn_z = WORLD_SIZE // 2 * TILE_SCALE

        # Spawn collectibles
        for _ in range(INITIAL_COLLECTIBLES):
            x = random.uniform(2, (WORLD_SIZE - 2) * TILE_SCALE)
            z = random.uniform(2, (WORLD_SIZE - 2) * TILE_SCALE)
            if self._is_walkable(x, z):
                dist = math.sqrt((x - spawn_x) ** 2 + (z - spawn_z) ** 2)
                if dist > SPAWN_SAFE_RADIUS:
                    c = Collectible(position=Vec3(x, 1, z))
                    self.collectibles.append(c)

        # Spawn enemies
        for _ in range(INITIAL_ENEMIES):
            x = random.uniform(2, (WORLD_SIZE - 2) * TILE_SCALE)
            z = random.uniform(2, (WORLD_SIZE - 2) * TILE_SCALE)
            if self._is_walkable(x, z):
                dist = math.sqrt((x - spawn_x) ** 2 + (z - spawn_z) ** 2)
                if dist > ENEMY_SPAWN_SAFE_RADIUS:
                    # Distance-based difficulty scaling for initial spawn
                    enemy_type = self._pick_enemy_type(dist)
                    e = Enemy(position=Vec3(x, 1, z), enemy_type=enemy_type)
                    self.enemies.append(e)

    def _pick_enemy_type(self, distance_from_spawn: float) -> str:
        """Pick an enemy type based on distance from spawn (farther = harder).

        Args:
            distance_from_spawn: Distance in world units from the spawn point.

        Returns:
            Enemy type name string suitable for the difficulty tier.
        """
        tier = min(int(distance_from_spawn / DIFFICULTY_SCALE_DISTANCE), 2)
        if tier == 0:
            return random.choice(EASY_ENEMY_TYPES)
        elif tier == 1:
            return random.choice(MEDIUM_ENEMY_TYPES)
        else:
            return random.choice(HARD_ENEMY_TYPES)

    def _scale_enemy_to_player_level(self, enemy: Enemy) -> None:
        """Scale enemy HP and damage based on player level for balanced difficulty.

        Higher-level players face tougher variants of the same enemy type,
        keeping early enemies relevant while making the game progressively harder.

        The scaling now interpolates smoothly between tiers instead of stepping
        in hard jumps. The fractional portion of the tier calculation blends
        toward the next tier's multiplier, producing a continuous difficulty
        curve. At level 6 you get 20% of the tier-1 bonus; at level 8 you get
        60%; at level 10 you get the full tier-1 bonus. This makes progression
        feel natural — enemies gradually get tougher rather than abruptly
        stepping up at milestone levels.

        Args:
            enemy: The Enemy entity to scale (modified in-place).
        """
        p = self.player
        # Continuous tier calculation: tier_floor is the completed tier count,
        # tier_frac is the progress toward the next tier (0.0 to 1.0).
        raw_tier = max(0.0, (p.level - 1) / PLAYER_LEVEL_DIFFICULTY_INTERVAL)
        tier_floor = int(raw_tier)
        tier_frac = raw_tier - tier_floor
        if tier_floor > 0 or tier_frac > 0:
            # Blend between the current tier's multiplier and the next tier's
            # multiplier using the fractional portion, producing a smooth
            # interpolation instead of a hard step at each tier boundary.
            hp_mult_current = 1.0 + tier_floor * ENEMY_HP_SCALE_PER_TIER
            hp_mult_next = 1.0 + (tier_floor + 1) * ENEMY_HP_SCALE_PER_TIER
            hp_mult = lerp(hp_mult_current, hp_mult_next, tier_frac)
            dmg_mult_current = 1.0 + tier_floor * ENEMY_DAMAGE_SCALE_PER_TIER
            dmg_mult_next = 1.0 + (tier_floor + 1) * ENEMY_DAMAGE_SCALE_PER_TIER
            dmg_mult = lerp(dmg_mult_current, dmg_mult_next, tier_frac)
            enemy.hp = int(enemy.hp * hp_mult)
            enemy.max_hp = enemy.hp
            enemy.damage = int(enemy.damage * dmg_mult)

    def _assign_missions(self, count: int = 1) -> None:
        """Assign new random missions from templates.

        Args:
            count: Number of missions to assign.
        """
        templates = list(MISSION_TEMPLATES)
        random.shuffle(templates)
        # BUG FIX: Filter out templates for missions that are already active
        # (not turned in). Without this, the player could have two identical
        # missions (e.g., two "Beetle B Gone") active simultaneously, which is
        # confusing and doubles the progress tracking for the same objective.
        active_targets = {m.target for m in self.missions if not m.turned_in}
        available = [t for t in templates if t[2] not in active_targets]
        for template in available[:count]:
            m = Mission(template[0], template[1], template[2], template[5], template[4], template[3])
            # Bug fix: capture baseline kills/collects at assignment time so progress
            # is computed as delta from this point, not lifetime total.
            if m.mission_type == 'kill':
                m.baseline = self.player.kills.get(m.target, 0)
            elif m.mission_type == 'collect':
                m.baseline = self.player.inventory.get(m.target, 0)
            self.missions.append(m)
            self.add_message(f"New Mission: {m.title}")

    def _spawn_portals(self):
        """Create linked portal pairs at walkable locations around the world."""
        spawn_center = WORLD_SIZE // 2 * TILE_SCALE
        for i in range(PORTAL_COUNT):
            for _ in range(50):  # Max attempts to find walkable positions
                angle1 = random.uniform(0, math.pi * 2)
                dist1 = random.uniform(30, (WORLD_SIZE * TILE_SCALE) * 0.4)
                x1 = spawn_center + math.cos(angle1) * dist1
                z1 = spawn_center + math.sin(angle1) * dist1
                x1 = max(10, min(x1, (WORLD_SIZE - 2) * TILE_SCALE))
                z1 = max(10, min(z1, (WORLD_SIZE - 2) * TILE_SCALE))

                # Partner portal on the opposite side of the map
                angle2 = angle1 + math.pi + random.uniform(-0.5, 0.5)
                dist2 = random.uniform(30, (WORLD_SIZE * TILE_SCALE) * 0.4)
                x2 = spawn_center + math.cos(angle2) * dist2
                z2 = spawn_center + math.sin(angle2) * dist2
                x2 = max(10, min(x2, (WORLD_SIZE - 2) * TILE_SCALE))
                z2 = max(10, min(z2, (WORLD_SIZE - 2) * TILE_SCALE))

                if self._is_walkable(x1, z1) and self._is_walkable(x2, z2):
                    # Ensure not too close to spawn
                    d1 = math.sqrt((x1 - spawn_center) ** 2 + (z1 - spawn_center) ** 2)
                    d2 = math.sqrt((x2 - spawn_center) ** 2 + (z2 - spawn_center) ** 2)
                    if d1 > 30 and d2 > 30:
                        portal_a = Portal(position=Vec3(x1, 0, z1), partner_position=Vec3(x2, 0, z2), portal_id=i)
                        portal_b = Portal(position=Vec3(x2, 0, z2), partner_position=Vec3(x1, 0, z1), portal_id=i)
                        self.portals.append(portal_a)
                        self.portals.append(portal_b)
                        break

    def _spawn_initial_traders(self):
        """Spawn initial wandering traders at walkable locations."""
        spawn_x = WORLD_SIZE // 2 * TILE_SCALE
        spawn_z = WORLD_SIZE // 2 * TILE_SCALE
        for _ in range(TRADER_INITIAL_COUNT):
            for _ in range(50):
                angle = random.uniform(0, math.pi * 2)
                dist = random.uniform(40, 120)
                tx = spawn_x + math.cos(angle) * dist
                tz = spawn_z + math.sin(angle) * dist
                tx = max(10, min(tx, (WORLD_SIZE - 2) * TILE_SCALE))
                tz = max(10, min(tz, (WORLD_SIZE - 2) * TILE_SCALE))
                if self._is_walkable(tx, tz):
                    trader = Trader(position=Vec3(tx, 1, tz))
                    self.traders.append(trader)
                    break

    def _spawn_monoliths(self):
        """Spawn Alien Monoliths in crystal and snow biomes.

        Monoliths are tall ancient structures that grant random buffs when the
        player approaches within range. They appear more frequently in crystal
        biomes and less in snow biomes for risk/reward balance.
        """
        spawn_center = WORLD_SIZE // 2 * TILE_SCALE
        for gx in range(WORLD_SIZE):
            for gz in range(WORLD_SIZE):
                biome = self.world_grid[gz][gx]  # Bug fix: was self.biome_map[gx][gz] — attribute doesn't exist, and indices were swapped (grid is [row][col] = [gz][gx])
                # Crystal biomes have higher monolith spawn rate
                if biome == 'crystal' and random.random() < MONOLITH_SPAWN_CHANCE_CRYSTAL:
                    wx = gx * TILE_SCALE
                    wz = gz * TILE_SCALE
                    # Don't place too close to spawn
                    dist_from_spawn = math.sqrt((wx - spawn_center) ** 2 + (wz - spawn_center) ** 2)
                    if dist_from_spawn > 60 and self._is_walkable(wx, wz):
                        monolith = AlienMonolith(position=Vec3(wx, 0, wz))
                        self.monoliths.append(monolith)
                elif biome == 'snow' and random.random() < MONOLITH_SPAWN_CHANCE_SNOW:
                    wx = gx * TILE_SCALE
                    wz = gz * TILE_SCALE
                    dist_from_spawn = math.sqrt((wx - spawn_center) ** 2 + (wz - spawn_center) ** 2)
                    if dist_from_spawn > 60 and self._is_walkable(wx, wz):
                        monolith = AlienMonolith(position=Vec3(wx, 0, wz))
                        self.monoliths.append(monolith)

    def add_message(self, msg):
        """Add a timed message to the HUD message queue."""
        self.messages.append((self.t, msg))
        if len(self.messages) > 50:
            self.messages = self.messages[-50:]

    def _trigger_meteor_shower(self):
        """Trigger a meteor crash world event near the player.

        A meteor streaks across the sky and crashes at a walkable location
        within METEOR_CRASH_RADIUS of the player (but not too close). It
        spawns 3-6 bonus collectibles biased toward rarer items, plus a
        dramatic visual: a sky trail, impact flash, expanding ground ring,
        fiery particle burst, and screen shake. A HUD message announces
        the event so the player knows to investigate.

        BUG FIX: The meteor_timer was initialized in __init__ but never
        decremented or checked, so this world event never fired. All the
        meteor constants (METEOR_SHOWER_INTERVAL_MIN/MAX, METEOR_CRASH_RADIUS,
        METEOR_DROP_WEIGHTS, etc.) were dead code. Now the timer is
        decremented in game_update() and this method is called when it
        reaches zero.
        """
        p = self.player
        # Pick a crash site within the radius range from the player
        for _ in range(10):  # Try up to 10 times to find a walkable spot
            angle = random.uniform(0, math.pi * 2)
            dist = random.uniform(METEOR_CRASH_RADIUS_MIN, METEOR_CRASH_RADIUS)
            cx = p.x + math.cos(angle) * dist
            cz = p.z + math.sin(angle) * dist
            cx = max(5, min(cx, (WORLD_SIZE - 5) * TILE_SCALE))
            cz = max(5, min(cz, (WORLD_SIZE - 5) * TILE_SCALE))
            if self._is_walkable(cx, cz):
                break
        else:
            return  # Couldn't find a walkable crash site — skip this event

        crash_pos = Vec3(cx, 1, cz)

        # ── Sky Trail ── A brief streaking line from high above to the crash point
        sky_trail = Entity(
            model='cube',
            color=color.rgb(255, 180, 60),
            scale=(0.3, METEOR_TRAIL_HEIGHT, 0.3),
            position=Vec3(cx, METEOR_TRAIL_HEIGHT / 2, cz),
        )
        tr_r, tr_g, tr_b = _c255_color(color.rgb(255, 180, 60))
        sky_trail.animate_color(
            color.rgba(tr_r, tr_g, tr_b, 0),
            duration=METEOR_TRAIL_DURATION,
            curve=curve.linear,
        )
        destroy(sky_trail, delay=METEOR_TRAIL_DURATION + 0.01)

        # ── Impact Flash ── Bright expanding sphere at the crash point
        flash = Entity(
            model='sphere',
            color=color.rgb(255, 200, 80),
            scale=0.01,
            position=crash_pos,
        )
        flash.animate_scale(
            METEOR_IMPACT_FLASH_SCALE,
            duration=METEOR_IMPACT_FLASH_DURATION,
            curve=curve.out_expo,
        )
        fl_r, fl_g, fl_b = _c255_color(color.rgb(255, 200, 80))
        flash.animate_color(
            color.rgba(fl_r, fl_g, fl_b, 0),
            duration=METEOR_IMPACT_FLASH_DURATION,
            curve=curve.linear,
        )
        destroy(flash, delay=METEOR_IMPACT_FLASH_DURATION + 0.01)

        # ── Sky Beam ── Vertical beam of light at the crash site
        sky_beam = Entity(
            model='cube',
            color=color.rgb(255, 150, 40),
            scale=(0.8, METEOR_SKY_BEAM_HEIGHT, 0.8),
            position=Vec3(cx, METEOR_SKY_BEAM_HEIGHT / 2, cz),
        )
        sb_r, sb_g, sb_b = _c255_color(color.rgb(255, 150, 40))
        sky_beam.animate_color(
            color.rgba(sb_r, sb_g, sb_b, 0),
            duration=METEOR_SKY_BEAM_DURATION,
            curve=curve.linear,
        )
        destroy(sky_beam, delay=METEOR_SKY_BEAM_DURATION + 0.01)

        # ── Ground Ring ── Expanding impact ring on the ground
        ring = Entity(
            model='quad',
            color=color.rgb(255, 120, 30),
            scale=0.01,
            position=Vec3(cx, 0.1, cz),
            rotation_x=90,
        )
        ring.animate_scale(
            METEOR_GROUND_RING_MAX_SCALE,
            duration=METEOR_GROUND_RING_DURATION,
            curve=curve.out_expo,
        )
        gr_r, gr_g, gr_b = _c255_color(color.rgb(255, 120, 30))
        ring.animate_color(
            color.rgba(gr_r, gr_g, gr_b, 0),
            duration=METEOR_GROUND_RING_DURATION,
            curve=curve.linear,
        )
        destroy(ring, delay=METEOR_GROUND_RING_DURATION + 0.01)
        self.meteor_rings.append(ring)

        # ── Fiery Impact Particles ──
        self._spawn_particles(crash_pos, color.rgb(255, 150, 40), count=METEOR_PARTICLE_COUNT)

        # ── Screen Shake ──
        self.screen_shake = max(self.screen_shake, METEOR_SCREEN_SHAKE)

        # ── Spawn Bonus Collectibles ── Weighted toward rarer items
        drop_count = random.randint(METEOR_DROP_COUNT_MIN, METEOR_DROP_COUNT_MAX)
        meteor_names = list(METEOR_DROP_WEIGHTS.keys())
        meteor_weights = list(METEOR_DROP_WEIGHTS.values())
        for _ in range(drop_count):
            item_type = random.choices(meteor_names, weights=meteor_weights, k=1)[0]
            # Scatter items around the crash site
            offset_angle = random.uniform(0, math.pi * 2)
            offset_dist = random.uniform(1, 4)
            ix = cx + math.cos(offset_angle) * offset_dist
            iz = cz + math.sin(offset_angle) * offset_dist
            ix = max(2, min(ix, (WORLD_SIZE - 2) * TILE_SCALE))
            iz = max(2, min(iz, (WORLD_SIZE - 2) * TILE_SCALE))
            if self._is_walkable(ix, iz):
                c = Collectible(position=Vec3(ix, 1, iz), item_type=item_type)
                self.collectibles.append(c)

        # ── HUD Announcement ──
        self.add_message("☄ METEOR CRASH! Bonus loot nearby!")

    def _spawn_shrines(self):
        """Spawn Healing Crystal Shrines in mushroom and swamp biomes.

        Shrines provide an instant heal when approached (on a long cooldown),
        serving as safe havens in dangerous biomes far from the spawn healing
        zone. They appear less frequently than monoliths for balance.
        """
        spawn_center = WORLD_SIZE // 2 * TILE_SCALE
        for gx in range(WORLD_SIZE):
            for gz in range(WORLD_SIZE):
                biome = self.world_grid[gz][gx]
                if biome == 'mushroom' and random.random() < HEALING_SHRINE_SPAWN_CHANCE_MUSHROOM:
                    wx = gx * TILE_SCALE
                    wz = gz * TILE_SCALE
                    dist_from_spawn = math.sqrt((wx - spawn_center) ** 2 + (wz - spawn_center) ** 2)
                    if dist_from_spawn > HEALING_SHRINE_MIN_DIST_FROM_SPAWN and self._is_walkable(wx, wz):
                        shrine = HealingCrystalShrine(position=Vec3(wx, 0, wz))
                        self.shrines.append(shrine)
                elif biome == 'swamp' and random.random() < HEALING_SHRINE_SPAWN_CHANCE_SWAMP:
                    wx = gx * TILE_SCALE
                    wz = gz * TILE_SCALE
                    dist_from_spawn = math.sqrt((wx - spawn_center) ** 2 + (wz - spawn_center) ** 2)
                    if dist_from_spawn > HEALING_SHRINE_MIN_DIST_FROM_SPAWN and self._is_walkable(wx, wz):
                        shrine = HealingCrystalShrine(position=Vec3(wx, 0, wz))
                        self.shrines.append(shrine)

