                    # number for satisfying excess-damage feedback.
                    overkill_amount = abs(enemy.hp) if enemy.hp < 0 else 0
                    is_overkill = overkill_amount >= OVERKILL_DAMAGE_THRESHOLD
                    p.add_kill(enemy.name)
                    game.total_kills += 1
